# Status update function
update_status() {
    local status="$1"
    local ts
    ts="$(date '+%Y-%m-%d %H:%M:%S')"

    # Status file is a single-line indicator consumed by the dashboard.
    # Keep it plain and stable so it can be parsed by humans and tools.
    # IMPORTANT: write atomically to avoid transient empty reads while the file
    # is being truncated/written (can cause UI badge "flashing").
    write_atomic "${STATUS_FILE}" <<EOF 2>/dev/null || true
[${ts}] ${status}
EOF
    chmod 644 "${STATUS_FILE}" 2>/dev/null || true

    # Also emit a structured line so the dashboard Recent Activity timeline
    # shows verification/auto-repair progress with the same log format.
    # (This replaces the previous tee-to-LOG_FILE behaviour to avoid duplicates.)
    log_info "[status] ${status}"
}

# Helper: determine whether a system reboot is required.
# Used to surface a "Reboot Required" status in the dashboard, since rolling
# releases frequently update the kernel and core libraries.
check_reboot_required() {
    # Returns 0 if a reboot is required, 1 otherwise.

    local had_errexit rc_nr
    had_errexit=0
    [[ "$-" == *e* ]] && had_errexit=1

    # 1) Prefer zypper's own hint when available.
    if command -v zypper >/dev/null 2>&1; then
        set +e
        zypper needs-reboot >/dev/null 2>&1
        rc_nr=$?
        [ "$had_errexit" -eq 1 ] 2>/dev/null && set -e

        # On openSUSE, rc=1 means reboot needed.
        if [ "$rc_nr" -eq 1 ] 2>/dev/null; then
            return 0
        fi
    fi

    # 2) Marker files used by various tools.
    if [ -f /run/reboot-needed ] || [ -f /var/run/reboot-needed ] || [ -f /run/reboot-required ] || [ -f /var/run/reboot-required ]; then
        return 0
    fi

    # 3) Kernel package version heuristic (best-effort).
    local running_kernel installed_pkg installed_ver
    running_kernel=$(uname -r 2>/dev/null || echo "")

    if command -v rpm >/dev/null 2>&1; then
        installed_pkg=$(rpm -q --last kernel-default kernel-preempt kernel-rt 2>/dev/null | head -n 1 | awk '{print $1}' || true)
        if [ -n "${installed_pkg:-}" ] && [[ "${installed_pkg}" == kernel-*-* ]]; then
            installed_ver=${installed_pkg#kernel-default-}
            installed_ver=${installed_ver#kernel-preempt-}
            installed_ver=${installed_ver#kernel-rt-}

            if [ -n "${installed_ver:-}" ] && [ -n "${running_kernel:-}" ] && [[ "${running_kernel}" != *"${installed_ver}"* ]]; then
                return 0
            fi
        fi
    fi

    return 1
}

# --- Remote monitoring: Webhooks (best-effort) ---
_json_escape() {
    # Minimal JSON escaping for safe webhook payloads and dashboard JSON blobs.
    # Escapes: backslash, double quote, newlines, CR, tabs.
    # Also strips other ASCII control chars which can break JSON parsers.
    local s="$*"
    if command -v tr >/dev/null 2>&1; then
        # delete: NUL..BS, VT, FF, SO..US
        s=$(printf '%s' "$s" | tr -d '\000-\010\013\014\016-\037')
    fi
    s=${s//\\/\\\\}
    s=${s//"/\\"}
    s=${s//$'\n'/\\n}
    s=${s//$'\r'/\\r}
    s=${s//$'\t'/\\t}
    printf '%s' "$s"
}

_redact_url() {
    # Redact secret paths/tokens while keeping enough info for diagnostics.
    # Example: https://example.com/secret -> https://example.com/...
    local url="$1"
    printf '%s' "$url" | sed -E 's#^(https?://[^/]+).*$#\1/...#'
}

send_webhook() {
    # Usage: send_webhook "Title" "Message" "ColorInt(optional)"
    # Color is a Discord-style integer (e.g., 65280 green, 16711680 red).
    local title="$1"
    local message="$2"
    local color="${3:-}"

    # Only run if URL is configured
    [ -z "${WEBHOOK_URL:-}" ] && return 0

    # Never fail the main script because remote monitoring is unavailable.
    if ! command -v curl >/dev/null 2>&1; then
        log_debug "Webhook configured but curl not found; skipping webhook send"
        return 0
    fi

    local url
    url="${WEBHOOK_URL}"

    # Append correlation IDs for traceability
    local trace_tag=""
    [ -n "${ZYPPER_TRACE_ID:-}" ] && trace_tag=" TID=${ZYPPER_TRACE_ID}"
    message="${message}\n\nRUN=${RUN_ID}${trace_tag}"

    local title_esc msg_esc
    title_esc="$(_json_escape "$title")"
    msg_esc="$(_json_escape "$message")"

    # Keep URL out of logs; only show a redacted host.
    log_debug "Sending webhook: title='${title}' url=$(_redact_url "$url")"

    # Provider auto-detection based on URL patterns.
    if [[ "$url" == *"discord.com/api/webhooks"* ]] || [[ "$url" == *"discordapp.com/api/webhooks"* ]]; then
        # Discord embed
        local c
        c="${color:-65280}"
        curl -fsS --connect-timeout 5 --max-time 10 \
            -H "Content-Type: application/json" \
            -d "{\"embeds\":[{\"title\":\"${title_esc}\",\"description\":\"${msg_esc}\",\"color\":${c}}]}" \
            "$url" >/dev/null 2>&1 || true
        return 0
    fi

    if [[ "$url" == *"hooks.slack.com/services"* ]]; then
        # Slack incoming webhook (simple text)
        curl -fsS --connect-timeout 5 --max-time 10 \
            -H "Content-Type: application/json" \
            -d "{\"text\":\"${title_esc}: ${msg_esc}\"}" \
            "$url" >/dev/null 2>&1 || true
        return 0
    fi

    if [[ "$url" == *"ntfy.sh/"* ]]; then
        # ntfy.sh: post text with headers
        curl -fsS --connect-timeout 5 --max-time 10 \
            -H "Title: ${title}" \
            -H "Tags: zypper-auto" \
            -d "${message}" \
            "$url" >/dev/null 2>&1 || true
        return 0
    fi

    # Generic fallback: POST as plain text
    curl -fsS --connect-timeout 5 --max-time 10 \
        -H "Content-Type: text/plain" \
        -d "${title}: ${message}" \
        "$url" >/dev/null 2>&1 || true
    return 0
}

# --- Extensibility: Hook system ---
ensure_hook_dirs() {
    local base
    base="${HOOKS_BASE_DIR:-/etc/zypper-auto/hooks}"
    execute_guarded "Ensure hook base directory exists (${base})" mkdir -p "${base}" || true
    execute_guarded "Ensure pre-hook directory exists" mkdir -p "${base}/pre.d" || true
    execute_guarded "Ensure post-hook directory exists" mkdir -p "${base}/post.d" || true
    execute_guarded "Set hook directory permissions" chmod 755 "${base}" "${base}/pre.d" "${base}/post.d" || true
}

install_hook_templates() {
    # Best-effort: install example templates so users can quickly enable hooks
    # by copying them to a new filename and making them executable.
    local base
    base="${HOOKS_BASE_DIR:-/etc/zypper-auto/hooks}"

    local pre_tpl post_tpl
    pre_tpl="${base}/pre.d/00-example-pre.sh.example"
    post_tpl="${base}/post.d/00-example-post.sh.example"

    if [ ! -f "${pre_tpl}" ]; then
        if write_atomic "${pre_tpl}" <<'EOF'
#!/usr/bin/env bash
# Example pre-update hook for zypper-auto-helper
#
# To enable:
#   sudo cp /etc/zypper-auto/hooks/pre.d/00-example-pre.sh.example /etc/zypper-auto/hooks/pre.d/10-my-pre-hook.sh
#   sudo chmod +x /etc/zypper-auto/hooks/pre.d/10-my-pre-hook.sh
set -euo pipefail

stage="${HOOK_STAGE:-pre}"
run_id="${ZNH_RUN_ID:-}"
tid="${ZYPPER_TRACE_ID:-}"

msg="[HOOK] stage=${stage} RUN=${run_id}${tid:+ TID=${tid}} (example hook)"

if command -v logger >/dev/null 2>&1; then
  logger -t zypper-auto-hook -- "$msg" || true
fi

# Optional file log (best-effort)
echo "$(date '+%Y-%m-%d %H:%M:%S') $msg" >>/var/log/zypper-auto/hooks.log 2>/dev/null || true
EOF
        then
            chmod 644 "${pre_tpl}" 2>/dev/null || true
            log_success "Hook template installed: ${pre_tpl}"
        else
            log_warn "Failed to write hook template: ${pre_tpl} (non-fatal)"
        fi
    fi

    if [ ! -f "${post_tpl}" ]; then
        if write_atomic "${post_tpl}" <<'EOF'
#!/usr/bin/env bash
# Example post-update hook for zypper-auto-helper
#
# To enable:
#   sudo cp /etc/zypper-auto/hooks/post.d/00-example-post.sh.example /etc/zypper-auto/hooks/post.d/90-my-post-hook.sh
#   sudo chmod +x /etc/zypper-auto/hooks/post.d/90-my-post-hook.sh
set -euo pipefail

stage="${HOOK_STAGE:-post}"
run_id="${ZNH_RUN_ID:-}"
tid="${ZYPPER_TRACE_ID:-}"

msg="[HOOK] stage=${stage} RUN=${run_id}${tid:+ TID=${tid}} (example hook)"

if command -v logger >/dev/null 2>&1; then
  logger -t zypper-auto-hook -- "$msg" || true
fi

# Optional file log (best-effort)
echo "$(date '+%Y-%m-%d %H:%M:%S') $msg" >>/var/log/zypper-auto/hooks.log 2>/dev/null || true
EOF
        then
            chmod 644 "${post_tpl}" 2>/dev/null || true
            log_success "Hook template installed: ${post_tpl}"
        else
            log_warn "Failed to write hook template: ${post_tpl} (non-fatal)"
        fi
    fi

    # Developer/forensics helper: high-signal state dump before updates.
    # This is shipped as a template (not executable) so it is opt-in.
    local dbg_tpl
    dbg_tpl="${base}/pre.d/99-debug-dump.sh.example"
    if [ ! -f "${dbg_tpl}" ]; then
        if write_atomic "${dbg_tpl}" <<'EOF'
#!/usr/bin/env bash
# Developer / forensics pre-update hook (template)
#
# Purpose:
#   Dump high-signal system state into the dashboard Settings API log so WebUI
#   traces and backend state appear in one timeline.
#
# To enable:
#   sudo cp /etc/zypper-auto/hooks/pre.d/99-debug-dump.sh.example /etc/zypper-auto/hooks/pre.d/99-debug-dump.sh
#   sudo chmod +x /etc/zypper-auto/hooks/pre.d/99-debug-dump.sh
#
# Notes:
# - This hook runs as root (via the helper/wrapper).
# - Keep it fast; avoid slow commands.
# - Treat logs as potentially sensitive.

set +e

LOG="/var/log/zypper-auto/service-logs/dashboard-api.log"
TS="$(date '+%Y-%m-%d %H:%M:%S')"
RUN="${ZNH_RUN_ID:-}"
TID="${ZYPPER_TRACE_ID:-}"

{
  echo "[DEBUG HOOK] ts=${TS} stage=${HOOK_STAGE:-pre} RUN=${RUN}${TID:+ TID=${TID}}"
  echo "[DEBUG HOOK] ---- free -h ----"
  free -h 2>&1
  echo "[DEBUG HOOK] ---- zypp lock ----"
  if [ -f /run/zypp.pid ]; then
    pid=$(cat /run/zypp.pid 2>/dev/null | tr -cd '0-9')
    echo "zypp.pid=${pid:-?}"
    if [ -n "${pid:-}" ]; then
      ps -p "${pid}" -o pid,ppid,comm,args 2>&1 || true
    fi
  else
    echo "zypp.pid not present"
  fi
  echo "[DEBUG HOOK] ---- zypper/yast/packagekit processes ----"
  if command -v pgrep >/dev/null 2>&1; then
    pgrep -a -i -f 'zypper|yast|y2base|packagekit' 2>&1 || echo "(none)"
  else
    ps aux 2>/dev/null | grep -Ei 'zypper|yast|y2base|packagekit' 2>&1 | grep -v grep || echo "(none)"
  fi
  echo "[DEBUG HOOK] ---- end ----"
} >>"${LOG}" 2>/dev/null || true

exit 0
EOF
        then
            chmod 644 "${dbg_tpl}" 2>/dev/null || true
            log_success "Hook template installed: ${dbg_tpl}"
        else
            log_warn "Failed to write hook template: ${dbg_tpl} (non-fatal)"
        fi
    fi
}

run_hooks() {
    local stage="$1"

    if [[ "${HOOKS_ENABLED,,}" != "true" ]]; then
        log_debug "Hooks disabled (HOOKS_ENABLED=${HOOKS_ENABLED}); skipping ${stage} hooks"
        return 0
    fi

    local base hook_dir
    base="${HOOKS_BASE_DIR:-/etc/zypper-auto/hooks}"
    hook_dir="${base}/${stage}.d"

    if [ ! -d "${hook_dir}" ]; then
        log_debug "Hook directory not present: ${hook_dir} (skipping)"
        return 0
    fi

    log_info "Running ${stage}-update hooks from ${hook_dir}..."

    local hook ran_any=0
    for hook in "${hook_dir}"/*; do
        [ -e "${hook}" ] || continue
        if [ -f "${hook}" ] && [ -x "${hook}" ]; then
            ran_any=1
            log_info "  -> Executing hook: $(basename "${hook}")"
            if ! execute_guarded "Hook (${stage}): $(basename "${hook}")" "${hook}"; then
                log_warn "Hook $(basename "${hook}") failed (non-fatal)"
            fi
        fi
    done

    if [ "${ran_any}" -eq 0 ] 2>/dev/null; then
        log_debug "No executable hooks found in ${hook_dir}"
    fi

    return 0
}

# --- Visual reporting: Static HTML dashboard ---
_html_escape() {
    local s="$*"
    s=${s//&/\&amp;}
    s=${s//</\&lt;}
    s=${s//>/\&gt;}
    printf '%s' "$s"
}

generate_dashboard() {
    if [[ "${DASHBOARD_ENABLED,,}" != "true" ]]; then
        log_debug "Dashboard disabled (DASHBOARD_ENABLED=${DASHBOARD_ENABLED}); skipping dashboard generation"
        return 0
    fi

    local out_root out_user
    out_root="${LOG_DIR}/status.html"

    out_user=""
    if [ -n "${SUDO_USER_HOME:-}" ]; then
        out_user="${SUDO_USER_HOME}/.local/share/zypper-notify/status.html"
    fi

    local last_status last_install_log last_install_tail now now_iso
    now="$(date '+%Y-%m-%d %H:%M:%S')"
    now_iso="$(date -Iseconds 2>/dev/null || date '+%Y-%m-%dT%H:%M:%S%z')"
    last_status=$(cat "${STATUS_FILE}" 2>/dev/null || echo "Unknown")

    # Backward-compat normalization:
    # Older builds used to write "FAILED: Reboot Required" into last-status.txt.
    # A reboot requirement is a WARNING, not a failure, so normalize the display.
    if [[ "${last_status,,}" == *"failed: reboot required"* ]]; then
        last_status=$(printf '%s' "${last_status}" | sed -E 's/(\][[:space:]]*)[Ff][Aa][Ii][Ll][Ee][Dd]:[[:space:]]*Reboot Required/\1Reboot Required/' 2>/dev/null || printf '%s' "${last_status}")
    fi

    # Helper VERSION header embedded into the dashboard so the WebUI can detect
    # when it is outdated compared to the installed helper binary.
    local helper_version_at_gen helper_version_line
    helper_version_at_gen="0"
    helper_version_line=$(grep -m1 -E '^#\s*VERSION\s+[0-9]+' "$0" 2>/dev/null || true)
    helper_version_at_gen=$(printf '%s' "${helper_version_line}" | sed -E 's/^#\s*VERSION\s+([0-9]+).*/\1/' 2>/dev/null || echo "0")
    if ! [[ "${helper_version_at_gen:-}" =~ ^[0-9]+$ ]]; then helper_version_at_gen="0"; fi

    # Dashboard generation ID: used by an already-open tab to detect that a NEW
    # dashboard file was generated (even if the helper version didn't change).
    local dash_gen_id
    dash_gen_id=""
    if date +%s%N >/dev/null 2>&1; then
        dash_gen_id="g$(date +%s%N)"
    else
        dash_gen_id="g$(date +%s)"
    fi

    # Pending updates count (from cached dry-run output)
    local pending_count dry_file
    pending_count="0"
    dry_file="${LOG_DIR}/dry-run-last.txt"
    if [ -f "${dry_file}" ]; then
        pending_count=$(grep -oP "\d+(?= packages to upgrade)" "${dry_file}" 2>/dev/null | head -1 || true)
        if [ -z "${pending_count:-}" ]; then
            pending_count=$(grep -Eo "[0-9]+ packages to upgrade" "${dry_file}" 2>/dev/null | head -1 | awk '{print $1}' || true)
        fi
        if ! [[ "${pending_count:-}" =~ ^[0-9]+$ ]]; then
            pending_count="0"
        fi
    fi

    # Reboot-required warning badge (separate from FAILED status)
    local reboot_required_json reboot_badge_class reboot_badge_title
    reboot_required_json=false
    reboot_badge_class="znh-hidden"
    reboot_badge_title="Reboot required to fully apply kernel/core library updates."
    if check_reboot_required; then
        reboot_required_json=true
        reboot_badge_class=""
    fi

    # Feature toggles (visual state)
    local feat_flatpak feat_snap feat_soar feat_brew feat_pipx
    local feat_flatpak_class feat_snap_class feat_soar_class feat_brew_class feat_pipx_class

    feat_flatpak=$([[ "${ENABLE_FLATPAK_UPDATES,,}" == "true" ]] && echo "ON" || echo "OFF")
    feat_snap=$([[ "${ENABLE_SNAP_UPDATES,,}" == "true" ]] && echo "ON" || echo "OFF")
    feat_soar=$([[ "${ENABLE_SOAR_UPDATES,,}" == "true" ]] && echo "ON" || echo "OFF")
    feat_brew=$([[ "${ENABLE_BREW_UPDATES,,}" == "true" ]] && echo "ON" || echo "OFF")
    feat_pipx=$([[ "${ENABLE_PIPX_UPDATES,,}" == "true" ]] && echo "ON" || echo "OFF")

    feat_flatpak_class=$([[ "${feat_flatpak}" == "ON" ]] && echo "feat-on" || echo "feat-off")
    feat_snap_class=$([[ "${feat_snap}" == "ON" ]] && echo "feat-on" || echo "feat-off")
    feat_soar_class=$([[ "${feat_soar}" == "ON" ]] && echo "feat-on" || echo "feat-off")
    feat_brew_class=$([[ "${feat_brew}" == "ON" ]] && echo "feat-on" || echo "feat-off")
    feat_pipx_class=$([[ "${feat_pipx}" == "ON" ]] && echo "feat-on" || echo "feat-off")

    # Determine status color for a quick-glance badge.
    local status_color last_status_lc
    status_color="#7f8c8d" # Default gray
    last_status_lc="${last_status,,}"
    if [[ "${last_status_lc}" == *"reboot required"* ]]; then
        status_color="#f59e0b" # Amber (warning)
    elif [[ "${last_status_lc}" == *"error"* ]] || [[ "${last_status_lc}" == *"failed"* ]] || [[ "${last_status_lc}" == *"crash"* ]]; then
        status_color="#e74c3c" # Red
    elif [[ "${last_status_lc}" == *"complete"* ]] || [[ "${last_status_lc}" == *"success"* ]]; then
        status_color="#2ecc71" # Green
    elif [[ "${last_status_lc}" == *"downloading"* ]] || [[ "${last_status_lc}" == *"refreshing"* ]]; then
        status_color="#3498db" # Blue
    fi

    # Zypper lock badge (helps explain "stuck" installs / why Rocket wizard may wait).
    local zypp_lock_state zypp_lock_pid zypp_lock_file
    local zypp_lock_badge_text zypp_lock_badge_class zypp_lock_badge_title
    zypp_lock_state="none"
    zypp_lock_pid=""
    zypp_lock_file=""
    for zlock in /run/zypp.pid /var/run/zypp.pid; do
        if [ -f "${zlock}" ]; then
            zypp_lock_file="${zlock}"
            zypp_lock_pid=$(cat "${zlock}" 2>/dev/null || echo "")
            if [[ "${zypp_lock_pid:-}" =~ ^[0-9]+$ ]] && kill -0 "${zypp_lock_pid}" 2>/dev/null; then
                zypp_lock_state="active"
                break
            fi
            # If lock file exists but PID isn't alive, mark it stale.
            zypp_lock_state="stale"
        fi
    done
    # If the lock file is missing but zypper is running, still show "active".
    if [ "${zypp_lock_state}" = "none" ] && pgrep -x zypper >/dev/null 2>&1; then
        zypp_lock_state="active"
        if [ -z "${zypp_lock_pid:-}" ]; then
            zypp_lock_pid="unknown"
        fi
    fi

    zypp_lock_badge_text=""
    zypp_lock_badge_class="znh-hidden"
    zypp_lock_badge_title=""

    if [ "${zypp_lock_state}" = "active" ]; then
        zypp_lock_badge_text="Zypper lock: ACTIVE${zypp_lock_pid:+ (PID ${zypp_lock_pid})}"
        zypp_lock_badge_class="lock-active"
        zypp_lock_badge_title="A zypper/YaST process is running; updates may be waiting on the lock."
    elif [ "${zypp_lock_state}" = "stale" ]; then
        zypp_lock_badge_text="Zypper lock: STALE${zypp_lock_pid:+ (PID ${zypp_lock_pid})}"
        zypp_lock_badge_class="lock-stale"
        zypp_lock_badge_title="Lock file exists but PID does not appear to be running (stale lock?)."
    fi
    if [ -n "${zypp_lock_file:-}" ]; then
        zypp_lock_badge_title="${zypp_lock_badge_title} Lock file: ${zypp_lock_file}"
    fi

    last_install_log=""
    last_install_log=$(find "${LOG_DIR}" -maxdepth 1 -type f -name 'install-*.log' -printf '%T@\t%p\n' 2>/dev/null \
        | sort -nr | head -1 | cut -f2- || true)

    last_install_tail=""
    if [ -n "${last_install_log}" ] && [ -f "${last_install_log}" ]; then
        # Use a slightly larger tail for the dashboard so it feels like a UI,
        # without embedding the entire log.
        last_install_tail=$(tail -n 100 "${last_install_log}" 2>/dev/null || true)
    fi

    # Extract the last appended Flight Report (executive summary) from the most recent
    # log that actually contains it. The newest log may be a "--dashboard" run, which
    # won't include a Flight Report.
    local flight_report_log flight_report_raw
    flight_report_log=""
    flight_report_raw=""

    while IFS= read -r f; do
        [ -n "${f:-}" ] || continue
        if grep -q "ZYPPER-AUTO FLIGHT REPORT:" "$f" 2>/dev/null; then
            flight_report_log="$f"
            break
        fi
    done < <(
        find "${LOG_DIR}" -maxdepth 1 -type f -name 'install-*.log' -printf '%T@\t%p\n' 2>/dev/null \
            | sort -nr | cut -f2- || true
    )

    if [ -n "${flight_report_log}" ] && [ -f "${flight_report_log}" ]; then
        flight_report_raw=$(awk '
            BEGIN {cap=0; buf=""; last=""; pending_sep=""; }
            /^===================================================$/ {
                if (cap==1) {
                    buf = buf $0 "\n";
                    last = buf;
                    buf="";
                    cap=0;
                } else {
                    pending_sep=$0;
                }
                next;
            }
            /^ZYPPER-AUTO FLIGHT REPORT:/ {
                cap=1;
                buf="";
                if (pending_sep!="") { buf = pending_sep "\n"; pending_sep=""; }
                buf = buf $0 "\n";
                next;
            }
            cap==1 { buf = buf $0 "\n"; }
            END {
                if (last!="") printf "%s", last;
                else if (buf!="") printf "%s", buf;
            }
        ' "${flight_report_log}" 2>/dev/null || true)
    fi

    local dl_timer nt_timer verify_timer
    dl_timer=$(systemctl is-active "${DL_SERVICE_NAME}.timer" 2>/dev/null || echo "unknown")
    verify_timer=$(systemctl is-active "${VERIFY_SERVICE_NAME}.timer" 2>/dev/null || echo "unknown")
    nt_timer="unknown"
    if [ -n "${SUDO_USER:-}" ]; then
        local bus
        bus="unix:path=/run/user/$(id -u "${SUDO_USER}" 2>/dev/null || echo "")/bus"
        nt_timer=$(sudo -u "${SUDO_USER}" DBUS_SESSION_BUS_ADDRESS="$bus" systemctl --user is-active "${NT_SERVICE_NAME}.timer" 2>/dev/null || echo "unknown")
    fi

    # Timer status classes for badges.
    local dl_timer_class verify_timer_class nt_timer_class
    dl_timer_class="timer-inactive"
    verify_timer_class="timer-inactive"
    nt_timer_class="timer-inactive"
    if [ "${dl_timer}" = "active" ]; then dl_timer_class="timer-active"; fi
    if [ "${verify_timer}" = "active" ]; then verify_timer_class="timer-active"; fi
    if [ "${nt_timer}" = "active" ]; then nt_timer_class="timer-active"; fi

    # Last verification summary (auto-fix counters)
    local verify_last_fixed verify_last_detected verify_last_remaining verify_last_ts verify_last_ts_esc
    verify_last_fixed="0"
    verify_last_detected="0"
    verify_last_remaining="0"
    verify_last_ts="unknown"
    local verify_summary_file
    verify_summary_file="${LOG_DIR}/last-verify-summary.txt"
    if [ -f "${verify_summary_file}" ]; then
        verify_last_fixed=$(grep -E '^fixed=' "${verify_summary_file}" 2>/dev/null | head -n 1 | cut -d= -f2- || echo 0)
        verify_last_detected=$(grep -E '^detected=' "${verify_summary_file}" 2>/dev/null | head -n 1 | cut -d= -f2- || echo 0)
        verify_last_remaining=$(grep -E '^remaining=' "${verify_summary_file}" 2>/dev/null | head -n 1 | cut -d= -f2- || echo 0)
        verify_last_ts=$(grep -E '^ts_human=' "${verify_summary_file}" 2>/dev/null | head -n 1 | cut -d= -f2- || echo "unknown")
    fi
    if ! [[ "${verify_last_fixed:-}" =~ ^[0-9]+$ ]]; then verify_last_fixed="0"; fi
    if ! [[ "${verify_last_detected:-}" =~ ^[0-9]+$ ]]; then verify_last_detected="0"; fi
    if ! [[ "${verify_last_remaining:-}" =~ ^[0-9]+$ ]]; then verify_last_remaining="0"; fi
    verify_last_ts_esc="$(_html_escape "${verify_last_ts}")"

    # Snapper timers (for dashboard snapper panel): enabled/partial/disabled/missing.
    local snapper_timeline_timer snapper_cleanup_timer snapper_boot_timer
    local snapper_timeline_class snapper_cleanup_class snapper_boot_class

    __znh_dash_timer_state() {
        local unit="$1"
        if ! __znh_unit_file_exists_system "${unit}"; then
            printf '%s' "missing"
            return 0
        fi

        local en=0 act=0
        if systemctl is-enabled --quiet "${unit}" 2>/dev/null; then
            en=1
        fi
        if systemctl is-active --quiet "${unit}" 2>/dev/null; then
            act=1
        fi

        if [ "${en}" -eq 1 ] 2>/dev/null && [ "${act}" -eq 1 ] 2>/dev/null; then
            printf '%s' "enabled"
        elif [ "${en}" -eq 1 ] 2>/dev/null || [ "${act}" -eq 1 ] 2>/dev/null; then
            printf '%s' "partial"
        else
            printf '%s' "disabled"
        fi
        return 0
    }

    __znh_dash_timer_class() {
        local state="$1"
        case "${state}" in
            enabled) printf '%s' "timer-active" ;;
            partial) printf '%s' "timer-partial" ;;
            *) printf '%s' "timer-inactive" ;;
        esac
        return 0
    }

    snapper_timeline_timer="$(__znh_dash_timer_state snapper-timeline.timer 2>/dev/null || echo disabled)"
    snapper_cleanup_timer="$(__znh_dash_timer_state snapper-cleanup.timer 2>/dev/null || echo disabled)"
    snapper_boot_timer="$(__znh_dash_timer_state snapper-boot.timer 2>/dev/null || echo disabled)"

    snapper_timeline_class="$(__znh_dash_timer_class "${snapper_timeline_timer}" 2>/dev/null || echo timer-inactive)"
    snapper_cleanup_class="$(__znh_dash_timer_class "${snapper_cleanup_timer}" 2>/dev/null || echo timer-inactive)"
    snapper_boot_class="$(__znh_dash_timer_class "${snapper_boot_timer}" 2>/dev/null || echo timer-inactive)"

    # System metrics for quick scanning.
    local kernel_ver uptime_info disk_used disk_total disk_percent disk_usage_display mem_usage
    kernel_ver=$(uname -r 2>/dev/null || echo "Unknown")
    # Uptime: prefer `uptime -p` but don't depend on PATH (systemd units can have a minimal PATH).
    # Fallback to /proc/uptime parsing so the dashboard never shows Unknown on normal systems.
    uptime_info=""
    if [ -x /usr/bin/uptime ]; then
        uptime_info=$(/usr/bin/uptime -p 2>/dev/null | sed 's/^up //' || true)
    elif command -v uptime >/dev/null 2>&1; then
        uptime_info=$(uptime -p 2>/dev/null | sed 's/^up //' || true)
    fi
    if [ -z "${uptime_info}" ] && [ -r /proc/uptime ]; then
        # /proc/uptime: "<seconds> <idle_seconds>"
        up_s=$(awk '{print int($1)}' /proc/uptime 2>/dev/null || echo "")
        if [[ "${up_s:-}" =~ ^[0-9]+$ ]]; then
            d=$((up_s/86400))
            h=$(((up_s%86400)/3600))
            m=$(((up_s%3600)/60))
            if [ "$d" -gt 0 ]; then
                uptime_info="${d} days, ${h} hours, ${m} minutes"
            elif [ "$h" -gt 0 ]; then
                uptime_info="${h} hours, ${m} minutes"
            else
                uptime_info="${m} minutes"
            fi
        fi
    fi
    if [ -z "${uptime_info}" ]; then
        uptime_info="Unknown"
    fi

    # Disk: used/total + percent integer.
    disk_used=$(df -h / 2>/dev/null | awk 'NR==2 {print $3}' || echo "?")
    disk_total=$(df -h / 2>/dev/null | awk 'NR==2 {print $2}' || echo "?")
    disk_percent=$(df -P / 2>/dev/null | awk 'NR==2 {print $5}' | tr -d '%' || echo "0")
    if ! [[ "${disk_percent:-}" =~ ^[0-9]+$ ]]; then
        disk_percent=0
    fi
    disk_usage_display="${disk_used}/${disk_total} (${disk_percent}%)"

    # Memory: used/total (best-effort)
    mem_usage="Unknown"
    if command -v free >/dev/null 2>&1; then
        mem_usage=$(free -h 2>/dev/null | awk '/^Mem:/ {print $3 "/" $2}' || echo "Unknown")
    fi

    local last_status_esc last_tail_esc last_install_log_esc flight_report_esc flight_report_log_esc
    local reboot_badge_title_esc
    local zypp_lock_badge_text_esc zypp_lock_badge_title_esc

    last_status_esc="$(_html_escape "$last_status")"
    last_tail_esc="$(_html_escape "$last_install_tail")"
    last_install_log_esc="$(_html_escape "$last_install_log")"
    flight_report_esc="$(_html_escape "$flight_report_raw")"
    flight_report_log_esc="$(_html_escape "$flight_report_log")"

    reboot_badge_title_esc="$(_html_escape "${reboot_badge_title}")"

    zypp_lock_badge_text_esc="$(_html_escape "${zypp_lock_badge_text}")"
    zypp_lock_badge_title_esc="$(_html_escape "${zypp_lock_badge_title}")"

    mkdir -p "$(dirname "${out_root}")" 2>/dev/null || true

    write_atomic "${out_root}" <<EOF
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Zypper Auto Command Center</title>
  <script>
    // Apply stored theme ASAP to avoid "flash of wrong theme" (FOUC) when the
    // user has forced Light/Dark while the system prefers the opposite.
    (function() {
      try {
        var mode = localStorage.getItem('znh_theme') || 'auto';
        if (mode === 'dark' || mode === 'light') {
          document.documentElement.setAttribute('data-theme', mode);
        }
      } catch (e) {}
    })();
  </script>
  <style>
    html { color-scheme: light dark; }
    /* Ensure native form controls (especially <select>/<option>) follow our theme */
    html[data-theme="dark"] { color-scheme: dark; }
    html[data-theme="light"] { color-scheme: light; }

    select, input[type="number"], input[type="text"], textarea {
        color: var(--text);
        background: rgba(255,255,255,0.04);
        border: 1px solid var(--border);
    }
    select option {
        background: var(--bg);
        color: var(--text);
    }

    :root {
        --bg: #f6f7fb;
        --card-bg: rgba(255,255,255,0.78);
        --text: #0f172a;
        --muted: rgba(15,23,42,0.68);
        --accent: #2563eb;
        --accent-2: #7c3aed;
        --border: rgba(15,23,42,0.10);
        --shadow: 0 10px 30px rgba(15,23,42,0.10);
        --subtle: rgba(15,23,42,0.04);
        --code-bg: #0b1220;
        --code-text: #e5e7eb;
        --focus: rgba(37, 99, 235, 0.35);
        --success: #16a34a;
        --danger: #ef4444;
        --warning: #f59e0b;

        --radius: 16px;
        --radius-sm: 12px;
    }

    /* Explicit theme overrides (JS toggles html[data-theme]) */
    html[data-theme="dark"] {
        --bg: #0b1220;
        --card-bg: rgba(17, 24, 39, 0.72);
        --text: #e5e7eb;
        --muted: rgba(229,231,235,0.70);
        --accent: #60a5fa;
        --accent-2: #a78bfa;
        --border: rgba(255,255,255,0.10);
        --shadow: 0 16px 40px rgba(0,0,0,0.55);
        --subtle: rgba(255,255,255,0.06);
        --code-bg: #060b14;
        --code-text: #d1d5db;
        --focus: rgba(96, 165, 250, 0.40);
    }

    /* Default to dark when system prefers dark, unless user forced a theme */
    @media (prefers-color-scheme: dark) {
        html:not([data-theme]) {
            --bg: #0b1220;
            --card-bg: rgba(17, 24, 39, 0.72);
            --text: #e5e7eb;
            --muted: rgba(229,231,235,0.70);
            --accent: #60a5fa;
            --accent-2: #a78bfa;
            --border: rgba(255,255,255,0.10);
            --shadow: 0 16px 40px rgba(0,0,0,0.55);
            --subtle: rgba(255,255,255,0.06);
            --code-bg: #060b14;
            --code-text: #d1d5db;
            --focus: rgba(96, 165, 250, 0.40);
        }
    }

    * { box-sizing: border-box; }

    body {
        font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji";
        padding: 24px;
        margin: 0;
        color: var(--text);
        line-height: 1.55;

        /* Layered gradients for a modern "pro" look */
        background:
            radial-gradient(1200px 700px at 15% 5%, rgba(37,99,235,0.16), transparent 60%),
            radial-gradient(900px 600px at 85% 10%, rgba(124,58,237,0.14), transparent 55%),
            radial-gradient(900px 600px at 50% 95%, rgba(16,185,129,0.10), transparent 55%),
            var(--bg);
    }

    .container { max-width: 1040px; margin: 0 auto; }

    .card {
        background: var(--card-bg);
        padding: 24px;
        border-radius: var(--radius);
        box-shadow: var(--shadow);
        margin-bottom: 18px;
        border: 1px solid var(--border);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
    }
    .card:hover { transform: translateY(-2px); border-color: rgba(37,99,235,0.18); }

    h1 {
        margin: 0;
        font-size: 1.35rem;
        letter-spacing: 0.2px;
        color: var(--text);
        display: flex;
        align-items: center;
        gap: 10px;
    }

    /* Rocket button (header) */
    .rocket-btn {
        font: inherit;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 36px;
        height: 36px;
        padding: 0;
        border-radius: 12px;
        border: 1px solid transparent;
        background: transparent;
        color: inherit;
        cursor: pointer;
        position: relative;
        user-select: none;
        transition: transform 150ms ease, background 150ms ease, border-color 150ms ease;
    }
    .rocket-btn:hover {
        background: rgba(37,99,235,0.10);
        border-color: rgba(37,99,235,0.28);
        transform: translateY(-1px);
    }
    .rocket-btn:active { transform: translateY(0) scale(0.98); }
    .rocket-btn:focus { outline: none; box-shadow: 0 0 0 4px var(--focus); }

    @keyframes rocketThrust {
        0% { transform: translateY(0) rotate(-1deg); filter: saturate(1); }
        50% { transform: translateY(-2px) rotate(2deg); filter: saturate(1.25); }
        100% { transform: translateY(0) rotate(-1deg); filter: saturate(1); }
    }
    @keyframes rocketReady {
        0% { transform: translateY(0); filter: drop-shadow(0 0 0 rgba(34,197,94,0.0)); }
        50% { transform: translateY(-1px); filter: drop-shadow(0 0 10px rgba(34,197,94,0.35)); }
        100% { transform: translateY(0); filter: drop-shadow(0 0 0 rgba(34,197,94,0.0)); }
    }
    @keyframes rocketShake {
        0% { transform: translateX(0) rotate(0deg); }
        25% { transform: translateX(-1px) rotate(-4deg); }
        50% { transform: translateX(1px) rotate(4deg); }
        75% { transform: translateX(-1px) rotate(-3deg); }
        100% { transform: translateX(0) rotate(0deg); }
    }

    .rocket-btn.rocket-downloading { animation: rocketThrust 850ms ease-in-out infinite; }
    .rocket-btn.rocket-complete { animation: rocketReady 1600ms ease-in-out infinite; }
    .rocket-btn.rocket-error { animation: rocketShake 420ms ease-in-out infinite; }

    /* Rocket emoji wrapper: lets us anchor the flame to the actual emoji glyph
       instead of guessing offsets inside the 36x36 button box. */
    .rocket-emoji {
        position: relative;
        display: inline-block;
        line-height: 1;
        z-index: 1; /* keep emoji above flame */
    }

    /* Simple flame effect (only when downloading)
       NOTE: flame is anchored to the emoji span, and rendered behind it. */
    .rocket-btn.rocket-downloading .rocket-emoji::before {
        content: '';
        position: absolute;
        width: 11px;
        height: 14px;
        /* Flame anchor: tweak if emoji/font differs */
        left: -2px;
        top: 14px;
        transform: rotate(-40deg);
        transform-origin: 50% 0%;
        border-radius: 999px;
        background: radial-gradient(circle at 50% 10%, rgba(255,255,255,0.85), rgba(250,204,21,0.65) 35%, rgba(249,115,22,0.15) 70%, rgba(249,115,22,0.0) 100%);
        filter: blur(0.3px);
        opacity: 0.95;
        animation: flame 650ms ease-in-out infinite;
        pointer-events: none;
        z-index: -1;
    }
    @keyframes flame {
        0% { height: 12px; opacity: 0.85; }
        50% { height: 18px; opacity: 1; }
        100% { height: 12px; opacity: 0.85; }
    }

    h2 {
        font-size: 1.02rem;
        margin: 0 0 14px 0;
        padding-bottom: 10px;
        color: var(--muted);
        border-bottom: 1px solid var(--border);
        letter-spacing: 0.2px;
    }

    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 14px; }

    .stat-box {
        background: linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.00)), var(--subtle);
        padding: 14px;
        border-radius: var(--radius-sm);
        border: 1px solid var(--border);
        box-shadow: 0 1px 0 rgba(255,255,255,0.06) inset;
    }

    .stat-label {
        font-size: 0.78rem;
        color: var(--muted);
        display: block;
        margin-bottom: 6px;
        text-transform: uppercase;
        letter-spacing: 0.8px;
        font-weight: 800;
    }

    .stat-value { font-weight: 800; font-size: 1.02rem; }

    code { font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace; }

    /* Small pill controls */
    .pill {
        display: inline-flex;
        align-items: center;
        gap: 8px;
        padding: 8px 12px;
        border-radius: 999px;
        border: 1px solid var(--border);
        background: rgba(255,255,255,0.04);
        color: var(--muted);
        font-weight: 800;
        font-size: 0.85rem;
        cursor: pointer;
        transition: transform 150ms ease, border-color 150ms ease, background 150ms ease;
        user-select: none;
    }
    .pill:hover { transform: translateY(-1px); border-color: rgba(37,99,235,0.30); background: rgba(37,99,235,0.07); }
    .pill:focus { outline: none; box-shadow: 0 0 0 4px var(--focus); }
    .pill.active {
        background: linear-gradient(135deg, rgba(37,99,235,0.20), rgba(124,58,237,0.16));
        border-color: rgba(37,99,235,0.38);
        color: var(--text);
    }
    html[data-theme="dark"] .pill.active,
    html:not([data-theme]) .pill.active {
        color: var(--text);
    }

    input[type="checkbox"] { accent-color: var(--accent); }

    /* JS-only motion effects (kept subtle) */
    @media (prefers-reduced-motion: reduce) {
        * { scroll-behavior: auto !important; transition: none !important; animation: none !important; }
    }

    html.js .card {
        opacity: 0;
        transform: translateY(10px);
    }
    html.js .card.enter {
        opacity: 1;
        transform: translateY(0);
        transition: opacity 380ms ease, transform 380ms ease, border-color 180ms ease, box-shadow 180ms ease;
    }

    @keyframes flash {
        0%   { box-shadow: 0 0 0 0 rgba(37,99,235,0.0); }
        30%  { box-shadow: 0 0 0 6px rgba(37,99,235,0.18); }
        100% { box-shadow: 0 0 0 0 rgba(37,99,235,0.0); }
    }
    .flash {
        animation: flash 700ms ease;
        border-radius: 10px;
    }

    /* Debug: visual DOM update flashing (opt-in)
       Enable via URL: ?domflash=1 (or ?znh_domflash=1)
       This is intentionally loud so you can spot accidental full re-renders. */
    @keyframes znhDebugFlash {
        0% { background-color: rgba(250, 204, 21, 0.75); }
        100% { background-color: transparent; }
    }
    .debug-updated {
        animation: znhDebugFlash 800ms ease-out;
    }

    @keyframes pulseGlow {
        0%   { transform: translateY(0); filter: saturate(1); }
        50%  { transform: translateY(-1px); filter: saturate(1.2); }
        100% { transform: translateY(0); filter: saturate(1); }
    }
    .pulse {
        animation: pulseGlow 600ms ease;
    }

    /* Ripple effect */
    .ripple {
        position: absolute;
        border-radius: 999px;
        transform: scale(0);
        opacity: 0.7;
        pointer-events: none;
        background: radial-gradient(circle, rgba(255,255,255,0.8) 0%, rgba(255,255,255,0.25) 35%, rgba(255,255,255,0.0) 70%);
        animation: ripple 650ms ease-out;
        mix-blend-mode: overlay;
    }
    @keyframes ripple {
        to { transform: scale(12); opacity: 0; }
    }

    /* Toast */
    #toast-wrap {
        position: fixed;
        right: 18px;
        bottom: 18px;
        display: grid;
        gap: 10px;
        z-index: 9999;
        max-width: min(420px, calc(100vw - 36px));
    }

    /* Background task bubble (self-update / system update wizard)
       Shows when an update job is running so users can reopen it if they
       accidentally close/minimize the overlay or reload the page. */
    body.task-active #toast-wrap { bottom: 86px; }
    .znh-task-bubble {
        position: fixed;
        right: 18px;
        bottom: 18px;
        z-index: 15000; /* above toasts, below overlay */
        display: flex;
        align-items: center;
        gap: 10px;
        padding: 10px 12px;
        border-radius: 999px;
        background: rgba(17, 24, 39, 0.88);
        color: #fff;
        border: 1px solid rgba(255,255,255,0.12);
        box-shadow: 0 18px 40px rgba(0,0,0,0.35);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        cursor: pointer;
        user-select: none;
        max-width: min(520px, calc(100vw - 36px));
    }
    .znh-task-bubble.hidden { display: none; }

    /* Notification center (small bell icon + glow when new notifications exist) */
    .znh-notify-btn {
        position: fixed;
        right: 18px;
        top: 16px;
        z-index: 14000; /* above content, below overlay */
        width: 38px;
        height: 38px;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        border: 1px solid rgba(255,255,255,0.14);
        background: rgba(17, 24, 39, 0.72);
        color: #fff;
        box-shadow: 0 14px 34px rgba(0,0,0,0.30);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        cursor: pointer;
        user-select: none;
    }
    .znh-notify-btn:hover { transform: translateY(-1px); border-color: rgba(37,99,235,0.30); background: rgba(37,99,235,0.10); }
    .znh-notify-btn:focus { outline: none; box-shadow: 0 0 0 4px var(--focus), 0 14px 34px rgba(0,0,0,0.30); }

    .znh-notify-badge {
        position: absolute;
        right: -3px;
        top: -3px;
        min-width: 18px;
        height: 18px;
        padding: 0 6px;
        border-radius: 999px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        font-size: 0.72rem;
        font-weight: 950;
        background: rgba(250, 204, 21, 0.95);
        color: rgba(17, 24, 39, 1);
        border: 1px solid rgba(0,0,0,0.12);
        box-shadow: 0 10px 24px rgba(0,0,0,0.25);
    }
    .znh-notify-badge.hidden { display: none; }

    @keyframes znhNotifyGlow {
        0% { box-shadow: 0 14px 34px rgba(0,0,0,0.30), 0 0 0 0 rgba(250, 204, 21, 0.0); }
        100% { box-shadow: 0 14px 34px rgba(0,0,0,0.30), 0 0 0 6px rgba(250, 204, 21, 0.22); }
    }
    .znh-notify-btn.glow {
        border-color: rgba(250, 204, 21, 0.55);
        animation: znhNotifyGlow 900ms ease-in-out infinite alternate;
    }

    .znh-notify-panel {
        position: fixed;
        right: 18px;
        top: 60px;
        z-index: 14001;
        width: min(420px, calc(100vw - 36px));
        max-height: min(560px, calc(100vh - 90px));
        overflow: auto;
        border-radius: 16px;
        background: rgba(17, 24, 39, 0.92);
        color: #fff;
        border: 1px solid rgba(255,255,255,0.12);
        box-shadow: 0 18px 40px rgba(0,0,0,0.35);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        display: none;
    }
    .znh-notify-panel.open { display: block; }
    .znh-notify-head {
        display: flex;
        align-items: center;
        justify-content: space-between;
        gap: 10px;
        padding: 10px 12px;
        border-bottom: 1px solid rgba(255,255,255,0.10);
        background: rgba(255,255,255,0.04);
    }
    .znh-notify-title { font-weight: 950; font-size: 0.92rem; }
    .znh-notify-list { display: grid; gap: 10px; padding: 10px 12px; }
    .znh-notify-item {
        border: 1px solid rgba(255,255,255,0.10);
        border-radius: 12px;
        padding: 10px 12px;
        background: rgba(255,255,255,0.03);
    }
    .znh-notify-item.unread { border-color: rgba(250, 204, 21, 0.40); background: rgba(250, 204, 21, 0.06); }
    .znh-notify-item .t { font-weight: 950; margin-bottom: 4px; }
    .znh-notify-item .b { font-weight: 800; opacity: 0.9; white-space: pre-wrap; }
    .znh-notify-item .meta { margin-top: 8px; font-size: 0.78rem; font-weight: 800; opacity: 0.72; }

    /* Managers bubble (minimized "Update manager / Rocket manager" overlay) */
    #znh-mgr-bubble {
        position: fixed;
        right: 18px;
        bottom: 86px; /* above toast area */
        z-index: 14900;
        display: flex;
        align-items: center;
        gap: 10px;
        padding: 10px 12px;
        border-radius: 999px;
        background: rgba(17, 24, 39, 0.88);
        color: #fff;
        border: 1px solid rgba(255,255,255,0.12);
        box-shadow: 0 18px 40px rgba(0,0,0,0.35);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        cursor: pointer;
        user-select: none;
        max-width: min(520px, calc(100vw - 36px));
    }
    body.task-active #znh-mgr-bubble { bottom: 154px; }
    #znh-mgr-bubble.hidden { display: none; }
    .znh-mgr-ico { width: 18px; height: 18px; display: inline-flex; align-items:center; justify-content:center; flex: 0 0 auto; }
    .znh-mgr-text { display: grid; gap: 2px; min-width: 0; }
    .znh-mgr-title { font-weight: 950; font-size: 0.92rem; line-height: 1.1; }
    .znh-mgr-sub { font-weight: 800; font-size: 0.78rem; opacity: 0.85; line-height: 1.1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

    /* Managers overlay list */
    .mgr-tabs { display: flex; gap: 10px; flex-wrap: wrap; }
    .mgr-row {
        border: 1px solid rgba(255,255,255,0.10);
        border-radius: 12px;
        padding: 10px 12px;
        background: rgba(255,255,255,0.03);
        display: grid;
        gap: 8px;
    }
    .mgr-row .hdr { display:flex; align-items: baseline; justify-content: space-between; gap: 10px; flex-wrap: wrap; }
    .mgr-row .t { font-weight: 950; }
    .mgr-row .m { font-weight: 850; opacity: 0.75; font-size: 0.82rem; }
    .mgr-row .b { font-weight: 800; opacity: 0.92; white-space: pre-wrap; }
    .mgr-row.ok { border-color: rgba(34,197,94,0.30); }
    .mgr-row.err { border-color: rgba(239,68,68,0.30); }
    .mgr-row.warn { border-color: rgba(250,204,21,0.30); }
    .mgr-actions { display:flex; gap: 8px; flex-wrap: wrap; }
    .znh-task-spinner {
        width: 18px;
        height: 18px;
        border-radius: 999px;
        border: 3px solid rgba(255,255,255,0.25);
        border-top-color: rgba(34,197,94,0.95);
        animation: znhSpin 900ms linear infinite;
        flex: 0 0 auto;
    }
    @keyframes znhSpin { to { transform: rotate(360deg); } }
    .znh-task-text { display: grid; gap: 2px; min-width: 0; }
    .znh-task-title { font-weight: 950; font-size: 0.92rem; line-height: 1.1; }
    .znh-task-sub { font-weight: 800; font-size: 0.78rem; opacity: 0.85; line-height: 1.1; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .toast {
        background: rgba(17, 24, 39, 0.82);
        color: #fff;
        border: 1px solid rgba(255,255,255,0.12);
        border-radius: 14px;
        padding: 12px 14px;
        box-shadow: 0 18px 40px rgba(0,0,0,0.35);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        font-weight: 800;
        font-size: 0.92rem;
        transform: translateY(10px);
        opacity: 0;
        animation: toastIn 260ms ease forwards;
    }
    .toast small { display:block; font-weight: 700; opacity: 0.8; margin-top: 4px; }
    .toast.ok { border-color: rgba(34,197,94,0.35); }
    .toast.err { border-color: rgba(239,68,68,0.35); }
    @keyframes toastIn { to { transform: translateY(0); opacity: 1; } }
    @keyframes toastOut { to { transform: translateY(6px); opacity: 0; } }

    /* Debug HUD (advanced JS debugging toolkit)
       Toggle via keyboard (Ctrl+Alt+H or Ctrl+Backquote), or append ?hud=1 to the URL. */
    .znh-hud {
        position: fixed;
        left: 18px;
        bottom: 18px;
        z-index: 16000; /* above normal content, below blocking overlay */
        width: min(780px, calc(100vw - 36px));
        max-height: min(520px, calc(100vh - 36px));
        display: flex;
        flex-direction: column;
        background: rgba(17, 24, 39, 0.90);
        color: #fff;
        border: 1px solid rgba(255,255,255,0.12);
        border-radius: 16px;
        box-shadow: 0 18px 40px rgba(0,0,0,0.35);
        backdrop-filter: blur(10px);
        -webkit-backdrop-filter: blur(10px);
        overflow: hidden;
    }
    .znh-hud.hidden { display: none; }
    .znh-hud-head {
        display: flex;
        align-items: center;
        justify-content: space-between;
        gap: 10px;
        padding: 10px 12px;
        border-bottom: 1px solid rgba(255,255,255,0.10);
        background: rgba(255,255,255,0.04);
    }
    .znh-hud-title {
        font-weight: 950;
        font-size: 0.92rem;
        letter-spacing: 0.2px;
    }
    .znh-hud-sub {
        font-size: 0.78rem;
        font-weight: 800;
        opacity: 0.85;
        margin-left: 10px;
    }
    .znh-hud-actions { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; justify-content: flex-end; }
    .znh-hud pre {
        margin: 0;
        border: 0;
        border-radius: 0;
        max-height: none;
        flex: 1;
        background: rgba(0,0,0,0.15);
        color: #e5e7eb;
    }

    /* Feature toggles */
    .feat-grid { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 8px; }
    .feat-badge { font-size: 0.8rem; padding: 6px 10px; border-radius: 10px; background: var(--subtle); border: 1px solid var(--border); display: inline-flex; align-items: center; gap: 8px; }
    .feat-dot { font-size: 0.9rem; }
    .feat-on { color: #2ecc71; font-weight: 900; }
    .feat-off { color: var(--muted); font-weight: 900; }

    /* Command Center action buttons */
    .action-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 12px; margin-top: 12px; }
    .cmd-btn {
        font-family: inherit;
        background: linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.00)), var(--subtle);
        border: 1px solid var(--border);
        color: var(--text);
        padding: 14px;
        border-radius: var(--radius-sm);
        cursor: pointer;
        text-align: left;
        transition: transform 150ms ease, border-color 150ms ease, box-shadow 150ms ease;
        position: relative;
        overflow: hidden;
        box-shadow: 0 1px 0 rgba(255,255,255,0.06) inset;
    }
    .cmd-btn:hover {
        transform: translateY(-2px);
        border-color: rgba(37,99,235,0.30);
        box-shadow: 0 18px 40px rgba(15,23,42,0.12);
    }

    /* Stateful button styles (used for Diag Logs ON/OFF) */
    .cmd-btn.state-on {
        border-color: rgba(34,197,94,0.42);
        background: linear-gradient(180deg, rgba(34,197,94,0.10), rgba(255,255,255,0.00)), var(--subtle);
        box-shadow: 0 22px 52px rgba(34,197,94,0.08);
    }
    .cmd-btn.state-off {
        border-color: rgba(245,158,11,0.42);
        background: linear-gradient(180deg, rgba(245,158,11,0.10), rgba(255,255,255,0.00)), var(--subtle);
        box-shadow: 0 22px 52px rgba(245,158,11,0.08);
    }

    .cmd-btn:active { transform: translateY(-1px) scale(0.99); }
    .cmd-btn:focus { outline: none; box-shadow: 0 0 0 4px var(--focus); }
    .cmd-label { display: block; font-weight: 950; font-size: 0.95rem; margin-bottom: 5px; letter-spacing: 0.15px; }
    .cmd-desc { display: block; font-size: 0.80rem; color: var(--muted); line-height: 1.25; }
    .cmd-copy-feedback {
        position: absolute; top: 0; left: 0; right: 0; bottom: 0;
        background: linear-gradient(90deg, var(--success), #22c55e);
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: 900;
        opacity: 0;
        pointer-events: none;
        transition: opacity 0.18s;
    }
    .cmd-btn.copied .cmd-copy-feedback { opacity: 1; }

    /* Status badges */
    .status-badge {
        display: inline-flex;
        align-items: center;
        gap: 8px;
        padding: 7px 14px;
        border-radius: 999px;
        color: white;
        font-weight: 900;
        font-size: 0.86rem;
        background:
            linear-gradient(90deg, rgba(255,255,255,0.18), rgba(255,255,255,0.05)),
            var(--status-color, ${status_color});
        box-shadow: 0 10px 22px rgba(0,0,0,0.18);
        border: 1px solid rgba(255,255,255,0.18);
        max-width: 100%;
        overflow-wrap: anywhere;
        min-width: 0; /* allow flex items to shrink (enables ellipsis where used) */
    }

    /* Main "last status" badge in the header:
       - Do NOT let long text create a huge empty gap in the header
       - Show a short one-line summary with ellipsis
       - Full text is available on hover (title attribute set by JS) */
    .status-badge.main-status {
        max-width: min(520px, calc(100vw - 520px));
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        overflow-wrap: normal;
        cursor: help;
    }

    /* Reboot-required warning badge (separate from FAILED status) */
    .reboot-badge { --status-color: rgba(245,158,11,0.92); }

    /* JS health badge (used to quickly tell if the page JS is alive) */
    .js-health-badge { --status-color: rgba(100,116,139,0.92); }
    .js-health-badge.js-ok { --status-color: rgba(34,197,94,0.92); }
    .js-health-badge.js-err { --status-color: rgba(239,68,68,0.92); }

    .znh-hidden { display: none !important; }

    /* Zypp/zypper lock badge (helps explain why updates are waiting) */
    .lock-badge {
        background:
            linear-gradient(90deg, rgba(255,255,255,0.16), rgba(255,255,255,0.05)),
            var(--lock-color, rgba(245,158,11,0.90));
    }
    .lock-badge.lock-active { --lock-color: rgba(245,158,11,0.95); }
    .lock-badge.lock-stale { --lock-color: rgba(168,85,247,0.85); }

    .timer-active { color: #2ecc71; font-weight: 800; }
    .timer-partial { color: #f59e0b; font-weight: 800; }
    .timer-inactive { color: #e74c3c; font-weight: 800; }

    /* Disk usage bar */
    .progress-track { height: 10px; background: rgba(0,0,0,0.06); border-radius: 999px; margin-top: 10px; overflow: hidden; border: 1px solid var(--border); }
    .progress-fill { height: 100%; background: linear-gradient(90deg, var(--accent), var(--accent-2)); border-radius: 999px; width: 0%; transition: width 0.45s ease; }

    /* Mini indeterminate progress (used for Update Manager preview + verification loading) */
    .znh-mini-progress {
        height: 8px;
        background: rgba(0,0,0,0.10);
        border-radius: 999px;
        overflow: hidden;
        border: 1px solid var(--border);
    }
    .znh-mini-progress.hidden { display: none; }
    .znh-mini-progress-bar {
        height: 100%;
        width: 35%;
        background: linear-gradient(90deg, rgba(96,165,250,0.95), rgba(167,139,250,0.95), rgba(34,197,94,0.95));
        border-radius: 999px;
        animation: znhIndeterminate 1050ms ease-in-out infinite;
    }
    @keyframes znhIndeterminate {
        0% { transform: translateX(-120%); opacity: 0.55; }
        50% { opacity: 1; }
        100% { transform: translateX(300%); opacity: 0.55; }
    }

    /* Logs */
    .log-container { position: relative; }

    .copy-btn,
    .jump-btn {
        position: absolute;
        top: 10px;
        font-family: inherit;
        background: rgba(255,255,255,0.06);
        border: 1px solid var(--border);
        color: var(--muted);
        padding: 8px 10px;
        font-size: 0.85rem;
        border-radius: 10px;
        cursor: pointer;
        transition: transform 150ms ease, border-color 150ms ease, background 150ms ease, opacity 150ms ease;
        backdrop-filter: blur(6px);
        -webkit-backdrop-filter: blur(6px);
        user-select: none;
    }

    .copy-btn { right: 10px; }
    .jump-btn { right: 104px; opacity: 0; pointer-events: none; }
    .log-container.show-jump .jump-btn { opacity: 1; pointer-events: auto; }

    .copy-btn:hover,
    .jump-btn:hover {
        transform: translateY(-1px);
        border-color: rgba(37,99,235,0.28);
        background: rgba(37,99,235,0.08);
        color: var(--text);
    }
    .copy-btn:focus,
    .jump-btn:focus { outline: none; box-shadow: 0 0 0 4px var(--focus); }

    /* Copy feedback (log copy buttons) */
    .copy-btn.copied-ok {
        border-color: rgba(34,197,94,0.55) !important;
        background: rgba(34,197,94,0.08) !important;
        color: var(--text) !important;
    }
    .copy-btn.copied-err {
        border-color: rgba(239,68,68,0.55) !important;
        background: rgba(239,68,68,0.08) !important;
        color: var(--text) !important;
    }

    pre {
        background: linear-gradient(180deg, rgba(255,255,255,0.03), rgba(255,255,255,0.00)), var(--code-bg);
        color: var(--code-text);
        padding: 16px;
        border-radius: var(--radius-sm);
        overflow-x: auto;
        font-size: 0.86rem;
        white-space: pre-wrap;
        border: 1px solid rgba(255,255,255,0.12);
        max-height: 460px;
        overflow-y: auto;
        box-shadow: 0 1px 0 rgba(255,255,255,0.06) inset;
    }

    /* Keyword highlighting */
    .log-time { color: #888; }
    .log-info { color: #61afef; }
    .log-success { color: #98c379; font-weight: 800; }
    .log-warn { color: #e5c07b; font-weight: 800; }
    .log-error { color: #e06c75; font-weight: 900; }

    /* Self-update overlay (blocking modal) */
    body.overlay-open {
        overflow: hidden;
        overscroll-behavior: contain;
    }
    .overlay {
        position: fixed;
        inset: 0;
        background: rgba(0,0,0,0.72);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 20000; /* must be above toasts */
        padding: 12px;
        backdrop-filter: blur(2px) saturate(0.9);
        -webkit-backdrop-filter: blur(2px) saturate(0.9);
    }
    .overlay.hidden { display: none; }
    .overlay-card {
        width: min(920px, calc(100vw - 24px));
        max-height: calc(100vh - 24px);
        background: var(--card-bg); /* IMPORTANT: previously used undefined --card -> transparent */
        color: var(--text);
        border: 1px solid var(--border);
        border-radius: var(--radius);
        box-shadow: 0 30px 80px rgba(0,0,0,0.45);
        overflow: hidden;
        display: flex;
        flex-direction: column;
    }
    .overlay-head {
        padding: 14px 16px;
        border-bottom: 1px solid var(--border);
        display: flex;
        align-items: center;
        justify-content: space-between;
        gap: 12px;
        background: linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.02));
    }
    .overlay-title {
        font-weight: 950;
        letter-spacing: 0.2px;
        font-size: 1.02rem;
    }
    .overlay-step { color: var(--muted); font-size: 0.85rem; font-weight: 800; }
    .overlay-body {
        padding: 16px;
        display: grid;
        gap: 14px;
        flex: 1;
        min-height: 0;
        overflow-y: auto;
    }
    .overlay-scroll {
        max-height: min(560px, calc(100vh - 320px));
        overflow-y: auto;
        padding: 14px;
        border-radius: 14px;
        background: var(--subtle);
        border: 1px solid var(--border);
        color: var(--text);
        line-height: 1.55;
        font-size: 0.95rem;
    }
    .overlay-scroll p { margin: 10px 0; }
    .overlay-scroll ul { margin: 10px 0 10px 18px; }
    .overlay-scroll li { margin: 6px 0; }
    .overlay-kv { display:flex; gap:10px; flex-wrap:wrap; }
    .overlay-kv .feat-badge { font-size: 0.84rem; }

    .overlay-alert {
        padding: 10px 12px;
        border-radius: 12px;
        border: 1px solid var(--border);
        background: var(--subtle);
        font-weight: 950;
        color: var(--text);
        line-height: 1.35;
    }
    .overlay-alert-warn {
        border-color: rgba(250,204,21,0.45);
        background: rgba(250,204,21,0.12);
    }

    .overlay-footer {
        padding: 14px 16px;
        border-top: 1px solid var(--border);
        display: flex;
        justify-content: space-between;
        gap: 10px;
        flex-wrap: wrap;
        background: var(--subtle);
    }
    .overlay-footer.center { justify-content: center; }
    .overlay-pre {
        max-height: min(360px, calc(100vh - 420px));
        overflow-y: auto;
    }
    .overlay-progress {
        display: grid;
        gap: 8px;
    }
    .overlay-progress-row { display:flex; justify-content: space-between; gap: 10px; color: var(--muted); font-size: 0.85rem; font-weight: 800; }

    .footer { font-size: 0.85rem; color: var(--muted); text-align: center; margin-top: 28px; }
    .footer a { color: var(--accent); text-decoration: none; font-weight: 950; }
    .footer a:hover { text-decoration: underline; }
  </style>
</head>
<body>
  <!-- Multi-instance hard-block page (shown when dashboard is open in multiple tabs/windows) -->
  <div id="znh-multi-instance-page" style="display:none;">
    <div class="container">
      <div class="card" style="border-color: rgba(239,68,68,0.35); background: rgba(239,68,68,0.06);">
        <h1 style="margin:0 0 10px 0;">⚠ Multiple WebUI tabs detected</h1>
        <div id="znh-multi-instance-text" style="margin-top:4px; font-size:0.98rem; color: var(--muted); font-weight: 850; line-height: 1.5;">
          Close other tabs (same WebUI). Then reload this tab.
        </div>
        <div style="margin-top:14px; display:flex; gap:10px; flex-wrap:wrap; align-items:center;">
          <button class="pill" type="button" id="znh-multi-instance-reload-btn">Reload tab</button>
          <button class="pill" type="button" id="znh-multi-instance-recheck-btn" style="border-color: rgba(255,255,255,0.14);">Re-check (auto reload)</button>
        </div>
      </div>
    </div>
  </div>

  <div class="container" id="main-content">
    <div class="card">
      <div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap: 10px;">
          <h1>
            <button class="rocket-btn" id="rocket-btn" type="button" title="Install system updates (wizard)"><span class="rocket-emoji" aria-hidden="true">🚀</span></button>
            <span>Zypper Auto Command Center</span>
          </h1>
          <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap; justify-content:flex-end;">
            <span class="status-badge main-status" id="status-badge">${last_status_esc}</span>
            <span class="status-badge reboot-badge ${reboot_badge_class}" id="reboot-required-badge" title="${reboot_badge_title_esc}">↻ Reboot Required</span>
            <span class="status-badge js-health-badge" id="js-health-badge" title="JavaScript status (if this shows FAIL, open DevTools → Console)">JS: loading…</span>
            <span class="status-badge lock-badge ${zypp_lock_badge_class}" id="zypp-lock-badge" title="${zypp_lock_badge_title_esc}">${zypp_lock_badge_text_esc}</span>
          </div>
      </div>
      <p style="color:var(--muted); margin-top:8px; margin-bottom:0; font-size:0.9rem;">
        Generated <span id="time-ago">just now</span> (<span style="font-family:monospace" id="generated-at">${now}</span>) • Pending Updates: <strong id="pending-count">${pending_count}</strong>
      </p>
      <div style="margin-top:12px; display:flex; gap:10px; align-items:center; flex-wrap:wrap;">
        <label class="pill" style="gap:10px;">
          <input type="checkbox" id="live-toggle" /> Live mode
        </label>
        <button class="pill" id="theme-toggle" type="button" title="Toggle theme (auto/light/dark)">Theme: Auto</button>
        <span style="font-size:0.85rem; color: var(--muted);">Live polls <code>status-data.json</code>, <code>download-status.txt</code>, and <code>perf-data.json</code> (best via <code>http://</code>).</span>
      </div>

      <!-- Token repair banner (shown when Settings/Snapper token is missing) -->
      <div id="znh-token-repair-banner" style="display:none; margin-top: 12px; padding: 10px 12px; border-radius: 12px; border: 1px solid rgba(250,204,21,0.45); background: rgba(250,204,21,0.12); color: var(--text);">
        <div style="display:flex; gap:12px; justify-content: space-between; flex-wrap: wrap; align-items: center;">
          <div>
            <div style="font-weight: 950;">⚠ Settings/Snapper token missing</div>
            <div style="margin-top:4px; font-size:0.9rem; color: var(--muted); font-weight: 800;">Fix: re-open dashboard using <code>zypper-auto-helper --dash-open</code></div>
          </div>
          <div style="display:flex; gap:10px; flex-wrap: wrap; align-items: center;">
            <button class="pill" type="button" id="znh-token-copy-btn">Copy fix command</button>
            <button class="pill" type="button" id="znh-token-dismiss-btn" style="border-color: rgba(255,255,255,0.14);">Dismiss</button>
          </div>
        </div>
      </div>

      <!-- Dashboard update banner (shown when a newer helper/dashboard build is available) -->
      <div id="znh-dashboard-update-banner" style="display:none; margin-top: 12px; padding: 10px 12px; border-radius: 12px; border: 1px solid rgba(34,197,94,0.35); background: rgba(34,197,94,0.08); color: var(--text);">
        <div style="display:flex; gap:12px; justify-content: space-between; flex-wrap: wrap; align-items: center;">
          <div>
            <div style="font-weight: 950;">✨ Dashboard update available</div>
            <div id="znh-dashboard-update-text" style="margin-top:4px; font-size:0.9rem; color: var(--muted); font-weight: 800;">(checking…)</div>
          </div>
          <div style="display:flex; gap:10px; flex-wrap: wrap; align-items: center;">
            <button class="pill" type="button" id="znh-dashboard-update-refresh-btn" title="Regenerate dashboard via localhost API (same as Quick Actions → Run: Refresh Dashboard)">Run: Refresh Dashboard</button>
            <button class="pill" type="button" id="znh-dashboard-update-reload-btn" style="border-color: rgba(255,255,255,0.14);">Reload tab</button>
            <button class="pill" type="button" id="znh-dashboard-update-dismiss-btn" style="border-color: rgba(255,255,255,0.14);">Dismiss</button>
          </div>
        </div>
      </div>

      <div class="grid" style="margin-top: 18px;">
        <div class="stat-box">
            <span class="stat-label">Kernel</span>
            <span class="stat-value" id="kernel-ver">${kernel_ver}</span>
        </div>
        <div class="stat-box">
            <span class="stat-label">Uptime</span>
            <span class="stat-value" id="uptime-info">${uptime_info}</span>
        </div>
        <div class="stat-box">
            <span class="stat-label">Memory (Used/Total)</span>
            <span class="stat-value" id="mem-usage">${mem_usage}</span>
        </div>
        <div class="stat-box">
            <span class="stat-label">Disk Usage (/)</span>
            <span class="stat-value" id="disk-usage">${disk_usage_display}</span>
            <div class="progress-track">
                <div class="progress-fill" id="disk-bar" data-percent="${disk_percent}"></div>
            </div>
        </div>
      </div>
    </div>

    <div class="card">
      <h2>⚙️ Features & Config</h2>
      <div class="stat-label" style="text-transform:none;">Active Modules</div>
      <div class="feat-grid">
        <div class="feat-badge"><span class="feat-dot ${feat_flatpak_class}" id="feat-flatpak-dot">●</span> Flatpak: <strong id="feat-flatpak-val">${feat_flatpak}</strong></div>
        <div class="feat-badge"><span class="feat-dot ${feat_snap_class}" id="feat-snap-dot">●</span> Snap: <strong id="feat-snap-val">${feat_snap}</strong></div>
        <div class="feat-badge"><span class="feat-dot ${feat_soar_class}" id="feat-soar-dot">●</span> Soar: <strong id="feat-soar-val">${feat_soar}</strong></div>
        <div class="feat-badge"><span class="feat-dot ${feat_brew_class}" id="feat-brew-dot">●</span> Brew: <strong id="feat-brew-val">${feat_brew}</strong></div>
        <div class="feat-badge"><span class="feat-dot ${feat_pipx_class}" id="feat-pipx-dot">●</span> Pipx: <strong id="feat-pipx-val">${feat_pipx}</strong></div>
      </div>

      <div style="margin-top: 14px;">
        <span class="stat-label" style="text-transform:none;">Self-Update Channel</span>
        <div style="display:flex; gap:10px; flex-wrap:wrap; align-items:center;">
          <div class="feat-badge"><span class="feat-dot" style="color: var(--warning);">●</span> Channel: <strong id="self-update-channel">(loading)</strong></div>
          <div class="feat-badge"><span class="feat-dot" style="color: var(--accent);">●</span> Update: <strong id="self-update-status">(checking…)</strong></div>
          <div class="feat-badge znh-hidden" id="self-update-lock-badge" role="button" tabindex="0" title="Self-update safety lock is active (click to view running job)"><span class="feat-dot" style="color: rgba(239,68,68,0.9);">●</span> <strong id="self-update-lock-text">LOCKED</strong></div>
          <button class="pill" type="button" id="self-update-toggle-btn" title="Toggle update channel (rolling/stable)">Toggle channel</button>
          <button class="pill" type="button" id="self-update-run-btn" title="Install the latest build from this channel (requires confirmation phrase)" disabled>Update</button>
          <button class="pill" type="button" id="self-update-changelog-btn" title="Fetch latest changelog from GitHub">Fetch changelog</button>
        </div>
        <div id="self-update-detail" style="margin-top:6px; font-size:0.86rem; color: var(--muted); font-weight: 800;"></div>
        <div id="self-update-tech" class="znh-hidden" style="margin-top:4px; font-size:0.78rem; color: rgba(148,163,184,0.88); font-weight: 800;"></div>
        <div style="margin-top:10px;">
          <pre id="self-update-changelog" style="max-height: 280px;">(tip: click “Fetch changelog”, then “Update” if a newer build is available)</pre>
        </div>
      </div>

      <details id="settings-drawer" style="margin-top: 16px;">
        <summary style="cursor:pointer; font-weight: 900; color: var(--text);">▸ Settings (edit / apply /etc/zypper-auto.conf)</summary>
        <div style="margin-top: 12px; color: var(--muted); font-size: 0.9rem;">
          This panel writes settings via a localhost API (<code>127.0.0.1:8766</code>). If a value is invalid, it will auto-heal back to safe defaults.
        </div>
        <div id="settings-banner" style="margin-top: 10px; display:none; padding: 10px 12px; border-radius: 12px; border: 1px solid rgba(239,68,68,0.35); background: rgba(239,68,68,0.08); color: var(--text); font-weight: 900;"></div>
        <div id="settings-form" style="margin-top: 12px; display:grid; gap: 10px;"></div>
        <div style="margin-top: 12px; display:flex; gap:10px; flex-wrap:wrap;">
          <button class="pill" type="button" id="settings-save">Save / Apply</button>
          <button class="pill" type="button" id="settings-reload">Reload</button>
          <button class="pill" type="button" id="settings-reset" title="Backup and regenerate defaults" style="border-color: rgba(239,68,68,0.30);">Factory reset</button>
        </div>
      </details>

      <div style="margin-top: 14px;">
        <span class="stat-label" style="text-transform:none;">Run ID</span>
        <code style="font-size:0.85rem; background:var(--subtle); padding:2px 6px; border-radius:6px; border:1px solid var(--border);" id="run-id">${RUN_ID}</code>
      </div>
    </div>

    <div class="card">
      <h2>⚡ Quick Actions</h2>
      <div style="color:var(--muted); font-size:0.9rem; margin-bottom: 10px;">
        These buttons can run safe helper actions via the localhost API and show output in a small terminal-like window (minimize/close supported).
        Interactive actions that require a real terminal will stay copy-only for safety.
      </div>
      <div class="action-grid">
        <button class="cmd-btn" id="dash-refresh-run-btn" type="button" title="Regenerate the dashboard via the localhost API (requires Settings API running)">
            <span class="cmd-label">Run: Refresh Dashboard</span>
            <span class="cmd-desc">Via localhost API (127.0.0.1:8766) • reloads after refresh</span>
            <div class="cmd-copy-feedback">Refreshing…</div>
        </button>
        <button class="cmd-btn" id="rocket-wizard-open-btn" type="button" title="Open the Rocket Update Wizard (preview → confirm → run)">
            <span class="cmd-label">Open: Rocket Update Wizard</span>
            <span class="cmd-desc">Default update flow (recommended) • preview first</span>
            <div class="cmd-copy-feedback">Opening…</div>
        </button>
        <button class="cmd-btn" data-qa="verify" data-qa-copy="zypper-auto-helper --verify">
            <span class="cmd-label">Run: Verify & Fix</span>
            <span class="cmd-desc">Health checks + auto-repair (includes RPM DB repair)</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
        <button class="cmd-btn" data-qa="health" data-qa-copy="zypper-auto-helper --health">
            <span class="cmd-label">Run: Health Report</span>
            <span class="cmd-desc">Analyze recent runs (errors, locks, crashes)</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
        <button class="cmd-btn" data-qa="logs" data-qa-copy="zypper-auto-helper --logs">
            <span class="cmd-label">Run: View Logs</span>
            <span class="cmd-desc">Tail recent installer/service/notifier logs</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
        <button class="cmd-btn" data-qa="reset-downloads" data-qa-copy="zypper-auto-helper --reset-downloads" data-qa-danger="1">
            <span class="cmd-label">Run: Reset Downloads</span>
            <span class="cmd-desc">Clear cached state + restart timers (confirmation required)</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
        <button class="cmd-btn" data-qa="reset-config" data-qa-copy="zypper-auto-helper --reset-config" data-qa-danger="1">
            <span class="cmd-label">Run: Reset Config</span>
            <span class="cmd-desc">Recreate defaults (with backup) (confirmation required)</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
        <button class="cmd-btn" id="dash-refresh-run-btn2" type="button" title="Regenerate the dashboard artifacts (root) via localhost API">
            <span class="cmd-label">Run: Refresh Dashboard (Root)</span>
            <span class="cmd-desc">Regenerate this page (via localhost API) • reloads after refresh</span>
            <div class="cmd-copy-feedback">Refreshing…</div>
        </button>
        <button class="cmd-btn" data-qa="dash-open" data-qa-copy="zypper-auto-helper --dash-open">
            <span class="cmd-label">Open Dashboard</span>
            <span class="cmd-desc">Generate + open in your browser (runs via localhost API)</span>
            <div class="cmd-copy-feedback">Running…</div>
        </button>
      </div>

      <details style="margin-top: 14px;">
        <summary style="cursor:pointer; color: var(--muted); font-weight: 800;">More actions…</summary>
        <div class="action-grid" style="margin-top: 12px;">
          <button class="cmd-btn" data-qa="dash-open" data-qa-copy="zypper-auto-helper --dash-open">
              <span class="cmd-label">Serve Live Dashboard</span>
              <span class="cmd-desc">Recommended: runs --dash-open (starts server + sync worker + opens browser)</span>
              <div class="cmd-copy-feedback">Running…</div>
          </button>
          <button class="cmd-btn" data-qa="dash-open" data-qa-copy="zypper-auto-helper --dash-open">
              <span class="cmd-label">Serve Live Dashboard (Threaded)</span>
              <span class="cmd-desc">Recommended: runs --dash-open (ThreadingHTTPServer is preferred automatically)</span>
              <div class="cmd-copy-feedback">Running…</div>
          </button>
          <button class="cmd-btn" type="button" onclick="znhOpenUrl('http://127.0.0.1:8765/status.html?live=1', this)">
              <span class="cmd-label">Open Live URL</span>
              <span class="cmd-desc">Open served dashboard in browser</span>
              <div class="cmd-copy-feedback">Opening…</div>
          </button>
          <button class="cmd-btn" data-qa="live-logs" data-qa-copy="zypper-auto-helper --live-logs" data-qa-interactive="1">
              <span class="cmd-label">Live Logs</span>
              <span class="cmd-desc">Interactive (requires terminal) • copy-only in WebUI</span>
              <div class="cmd-copy-feedback">Open</div>
          </button>
          <button class="cmd-btn" data-qa="rm-conflict" data-qa-copy="zypper-auto-helper --rm-conflict" data-qa-danger="1">
              <span class="cmd-label">Fix RPM Conflicts</span>
              <span class="cmd-desc">Clean safe duplicate RPM versions (confirmation required)</span>
              <div class="cmd-copy-feedback">Running…</div>
          </button>
          <button class="cmd-btn" data-qa="self-check" data-qa-copy="zypper-auto-helper --check">
              <span class="cmd-label">Run: Self Check</span>
              <span class="cmd-desc">Syntax checks only</span>
              <div class="cmd-copy-feedback">Running…</div>
          </button>
          <button class="cmd-btn" data-qa="test-notify" data-qa-copy="zypper-auto-helper --test-notify">
              <span class="cmd-label">Test Notification</span>
              <span class="cmd-desc">Verify GUI/DBus wiring (sends a test desktop notification)</span>
