          <div style="margin-top:8px; font-size:0.85rem; color: var(--muted);" id="boot-grub-detail"></div>
          <div style="margin-top:6px; font-size:0.82rem; color: rgba(148,163,184,0.92);" id="boot-grub-delta"></div>
