      <div style="margin-top: 18px; padding-top: 14px; border-top: 1px solid rgba(255,255,255,0.10);">
        <h3 style="margin: 0 0 8px 0;">🧹 Boot Entry Scrub (scrub-ghost)</h3>
        <div style="color:var(--muted); font-size:0.9rem; margin-bottom: 10px;">
          Runs <code>scrub-ghost</code> through the local Dashboard API. Start with <strong>scan (dry-run)</strong>. Any change requires confirmation. For full flags + crash-safe background jobs, use <strong>Launch Wizard (overlay)</strong>.
        </div>

        <div class="grid">
          <div class="stat-box">
            <span class="stat-label">Action</span>
            <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap;">
              <select id="scrub-action" style="padding:8px 10px; border-radius: 12px;">
                <option value="auto" selected>AUTO (recommended)</option>
                <option value="scan">scan (dry-run)</option>
                <option value="apply">apply (custom)</option>
                <option value="list-backups">list backups</option>
                <option value="validate-latest">validate latest backup</option>
                <option value="restore-latest">restore latest backup (danger)</option>
              </select>

              <select id="scrub-apply-mode" style="padding:8px 10px; border-radius: 12px;" title="Apply mode">
                <option value="backup">backup (safe move)</option>
                <option value="delete">delete (permanent)</option>
              </select>

              <button class="pill" type="button" id="scrub-run-btn" style="border-color: rgba(239,68,68,0.30);">Run</button>
              <button class="pill" type="button" id="scrub-wizard-btn" title="Minimizable overlay (Rocket-style) with background job + resume if browser crashes">Launch Wizard (overlay)</button>
            </div>

            <div style="margin-top:10px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-prune-duplicates" checked /> prune duplicates</label>
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-prune-stale" checked /> prune stale snapshots</label>
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-prune-uninstalled" /> prune uninstalled kernels (extra danger)</label>
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-confirm-uninstalled" /> confirm uninstalled-kernel prune</label>
            </div>

            <div style="margin-top:10px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-update-sdboot" /> update sd-boot</label>
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-rebuild-grub" /> rebuild grub.cfg</label>
              <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">keep backups: <input id="scrub-keep-backups" type="number" min="1" max="50" step="1" value="5" style="width:90px; padding:6px 8px; border-radius: 12px;" /></label>
            </div>

            <div style="margin-top:8px; font-size:0.85rem; color: var(--muted);">
              Recommended: <strong>AUTO</strong> (safe backup mode + common prune options). Use <code>scan</code> first if unsure.
              Apply/restore require a typed confirmation phrase.
            </div>

            <details style="margin-top:12px; padding: 10px 12px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.10); background: rgba(255,255,255,0.03);">
              <summary style="cursor:pointer; font-weight: 950; color: var(--text);">Advanced scrub-ghost toggles (custom flags)</summary>
              <div style="margin-top:10px; color: var(--muted); font-size:0.88rem;">
                These map to scrub-ghost CLI flags. WebUI always runs non-interactive (<code>--no-menu</code> + no TTY prompts).
              </div>

              <div style="margin-top:12px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-no-remount-rw" /> no remount rw</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-no-backup" /> no backup (danger)</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-no-snapper-backup" /> no snapper backup</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-no-verify-snapshots" /> no verify snapshots</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-no-verify-modules" /> no verify modules</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-prune-zombies" /> prune zombies</label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);"><input type="checkbox" id="scrub-json" /> json output (scan only)</label>
              </div>

              <div style="margin-top:12px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">entries dir: <input id="scrub-entries-dir" type="text" placeholder="(auto)" style="width:340px; padding:6px 8px; border-radius: 12px;" /></label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">boot dir: <input id="scrub-boot-dir" type="text" placeholder="(auto)" style="width:260px; padding:6px 8px; border-radius: 12px;" /></label>
              </div>

              <div style="margin-top:12px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">backup root: <input id="scrub-backup-root" type="text" placeholder="/var/backups/scrub-ghost" style="width:320px; padding:6px 8px; border-radius: 12px;" /></label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">backup dir: <input id="scrub-backup-dir" type="text" placeholder="(auto timestamp)" style="width:320px; padding:6px 8px; border-radius: 12px;" /></label>
              </div>

              <div style="margin-top:12px; display:flex; gap:14px; flex-wrap:wrap; align-items:center;">
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">grub cfg: <input id="scrub-grub-cfg" type="text" placeholder="/boot/grub2/grub.cfg" style="width:320px; padding:6px 8px; border-radius: 12px;" /></label>
                <label style="display:flex; gap:8px; align-items:center; font-size:0.9rem; color: var(--muted);">log file: <input id="scrub-log-file" type="text" placeholder="/var/log/scrub-ghost.log" style="width:320px; padding:6px 8px; border-radius: 12px;" /></label>
              </div>
            </details>
          </div>
        </div>

        <div style="margin-top: 14px;">
          <div class="stat-label" style="text-transform:none;">Output</div>
          <pre id="scrub-output" style="max-height: 420px;">(no scrub action run yet)</pre>
        </div>
      </div>
    </div>

