                action: action,
                actions: actions
            };
            _znhNotify.items.unshift(it);
            if (_znhNotify.items.length > _znhNotify.max) _znhNotify.items = _znhNotify.items.slice(0, _znhNotify.max);
        }

        _znhNotifySave();
        _znhNotifyRenderBadge();
        _znhNotifyRenderList();
    }

    function _znhNotifyMarkAllRead() {
