                var hay = '';
                hay += String(it.type || '') + ' ';
                hay += String(it.job_id || '') + ' ';
                hay += String(it.title || '') + ' ';
                hay += String(it.summary || '') + ' ';
                hay += String(it.channel || '') + ' ';
                return hay.toLowerCase().indexOf(needle) !== -1;
            } catch (e) {
                return true;
            }
