            keyParts.push('helper:' + String(_znh_dash_update_state.helper_inst) + ':' + String(_znh_dash_update_state.helper_gen));
        }

        // IMPORTANT UX FIX:
        // status.html is regenerated frequently by timers (downloader/verify/etc.) to keep the dashboard fresh.
        // That should NOT trigger an "update available" banner on every run.
        // Only show this banner when the dashboard was generated by a *newer helper build*.
