    function _settingsClientLog(level, msg, ctx) {
        // Best-effort: send UI events to the API log so debug level matches the rest of the project.
        // Never throw + never leave unhandled rejections.
        try {
            return _api('/api/client-log', {
                method: 'POST',
                body: JSON.stringify({
                    level: level || 'info',
                    msg: String(msg || ''),
                    ctx: ctx || {}
                })
            }).catch(function() { return null; });
        } catch (e) {
            return null;
        }
    }

    // Verbose UI interaction telemetry:
    // When verbose debug is enabled, log most user interactions into the backend API log.
    // This is intentionally gated behind ZNH_DEBUG to avoid spamming logs during normal usage.
    (function() {
        var lastTs = 0;
        function shouldLog() {
            try { return !!ZNH_DEBUG; } catch (e) { return false; }
        }
        function trunc(s, n) {
            s = String(s || '');
            s = s.replace(/\s+/g, ' ').trim();
            if (s.length <= n) return s;
            return s.slice(0, n) + '…';
        }

        document.addEventListener('click', function(ev) {
            if (!shouldLog()) return;
            var now = 0;
            try { now = Date.now(); } catch (e0) { now = 0; }
            // Simple rate limit (avoid log spam when holding mouse down).
            if (now && lastTs && (now - lastTs) < 140) return;
            lastTs = now;

            var t = null;
            try {
                t = (ev && ev.target && ev.target.closest) ? ev.target.closest('button, a, .pill, summary, details, input, select, textarea') : null;
            } catch (e1) {
                t = null;
            }
            if (!t) return;

            // Do not capture typed secrets/phrases; only log metadata.
            var ctx = {
                event: 'click',
                tag: t.tagName,
                id: t.id || '',
                cls: trunc(t.className || '', 160),
                text: trunc((t.tagName === 'INPUT' || t.tagName === 'TEXTAREA') ? '' : (t.innerText || t.textContent || ''), 60)
            };

            _settingsClientLog('debug', 'UI interaction', ctx);
        }, { passive: true });

        document.addEventListener('change', function(ev) {
            if (!shouldLog()) return;
            var t = null;
            try {
                t = (ev && ev.target && ev.target.closest) ? ev.target.closest('input, select, textarea') : null;
            } catch (e1) {
                t = null;
            }
            if (!t) return;

            var ctx = {
                event: 'change',
                tag: t.tagName,
                id: t.id || '',
                name: t.name || '',
                type: t.type || '',
                key: (t.dataset && t.dataset.key) ? String(t.dataset.key) : ''
            };

            _settingsClientLog('debug', 'UI change', ctx);
        }, { passive: true });
    })();

    // --- Dashboard refresh (dashboard -> root API) ---
    var _znh_dash_refresh_reload_timer = null;

    function _znhDashRefreshBannerTextSet(msg) {
        try {
            var t = document.getElementById('znh-dashboard-update-text');
            if (t) t.textContent = String(msg || '');
        } catch (e) {}
    }

    function _znhDashRefreshSetBtnText(btn, fb, text) {
        try {
            if (fb) {
                fb.textContent = String(text || '');
                return;
            }
        } catch (e0) {}
        try {
            if (btn) btn.textContent = String(text || '');
        } catch (e1) {}
    }

    function _znhDashRefreshReloadNow() {
        // Cache-busting reload (more reliable than plain reload when the browser keeps
        // an old in-memory copy of status.html around).
        try {
            if (window.location && window.location.href && typeof URL === 'function') {
                var u = new URL(String(window.location.href));
                u.searchParams.set('znh_reload_ts', String(Date.now()));
                window.location.replace(u.toString());
                return;
            }
        } catch (e0) {}
        try { window.location.reload(); } catch (e1) {}
    }

    function _znhDashRefreshStartReloadCountdown(seconds, btn, fb) {
        var n = parseInt(seconds || 0, 10) || 0;
        if (n < 1) n = 1;
        if (n > 60) n = 60;

        if (_znh_dash_refresh_reload_timer) {
            try { clearInterval(_znh_dash_refresh_reload_timer); } catch (e0) {}
            _znh_dash_refresh_reload_timer = null;
        }

        function render() {
            var msg = 'Dashboard refreshed. Auto-reload in ' + String(n) + 's…';
            _znhDashRefreshBannerTextSet(msg);
            _znhDashRefreshSetBtnText(btn, fb, 'Reloading in ' + String(n) + '…');
        }

        render();
        _znh_dash_refresh_reload_timer = setInterval(function() {
            n = n - 1;
            if (n <= 0) {
                try { clearInterval(_znh_dash_refresh_reload_timer); } catch (e2) {}
                _znh_dash_refresh_reload_timer = null;
                _znhDashRefreshBannerTextSet('Reloading now…');
                _znhDashRefreshSetBtnText(btn, fb, 'Reloading…');
                _znhDashRefreshReloadNow();
                return;
            }
            render();
        }, 1000);
    }

    function dashboardRefreshRun(btnEl) {
        var btn = btnEl || document.getElementById('dash-refresh-run-btn') || document.getElementById('znh-dashboard-update-refresh-btn');
        var fb = null;
        try { fb = btn ? btn.querySelector('.cmd-copy-feedback') : null; } catch (e) { fb = null; }

        // Preserve original label (so we can restore it after auto-reload is cancelled/fails).
        try {
            if (btn && !btn.dataset.znhOrigText) {
                btn.dataset.znhOrigText = fb ? String(fb.textContent || '') : String(btn.textContent || '');
            }
        } catch (eO) {}

        if (btn) {
            try { btn.disabled = true; } catch (e0) {}
            try { btn.classList.add('copied'); } catch (e1) {}
        }
        _znhDashRefreshSetBtnText(btn, fb, 'Refreshing…');

        // Make the banner show a deterministic message (even if it was previously hidden).
        _znhDashRefreshBannerTextSet('Refreshing dashboard via localhost API…');

        toast('Refreshing dashboard…', 'Regenerating status.html via localhost API', 'ok');
        _settingsClientLog('info', 'dashboard refresh requested', {});

        return _api('/api/dashboard/refresh', { method: 'POST', body: JSON.stringify({}) }).then(function(r) {
            var ok = !!(r && r.rc === 0);
            toast('Dashboard refreshed', ok ? 'OK (auto-reload scheduled)' : ('rc=' + String(r && r.rc != null ? r.rc : '?')), ok ? 'ok' : 'err');
            _settingsClientLog(ok ? 'info' : 'warn', 'dashboard refresh result', { rc: r ? r.rc : null });

            if (!ok) {
                _znhDashRefreshSetBtnText(btn, fb, 'Refresh failed');
                _znhDashRefreshBannerTextSet('Dashboard refresh returned non-zero rc. Please check the API log and try again.');
                return r;
            }

            // The dashboard sync worker keeps /var/log/zypper-auto/status.html -> ~/.local/share/zypper-notify/status.html in sync.
            // It prefers inotify (instant) with a short interval fallback.
            // UX: show a countdown so users KNOW the reload is pending.
            _znhDashRefreshStartReloadCountdown(10, btn, fb);
            return r;

        }).catch(function(e) {
            var msg = (e && e.message) ? e.message : 'API not reachable';
            toast('Refresh failed', msg, 'err');
            _settingsClientLog('warn', 'dashboard refresh failed', { error: msg });
            _znhDashRefreshSetBtnText(btn, fb, 'Failed');
            _znhDashRefreshBannerTextSet('Refresh failed: ' + String(msg) + ' (API may be restarting)');
            return null;

        }).finally(function() {
            if (btn) {
                setTimeout(function() {
                    try { btn.disabled = false; } catch (e0) {}
                    try { btn.classList.remove('copied'); } catch (e1) {}

                    // Restore original text unless a reload countdown is active.
                    if (!_znh_dash_refresh_reload_timer) {
                        try {
                            var orig = btn.dataset ? String(btn.dataset.znhOrigText || '') : '';
                            if (orig) _znhDashRefreshSetBtnText(btn, fb, orig);
                        } catch (e2) {}
                    }
                }, 900);
            }
        });
    }

    function _wireDashboardRefreshUI() {
        var btns = [];
        try {
            btns = Array.prototype.slice.call(document.querySelectorAll('#dash-refresh-run-btn, #dash-refresh-run-btn2, #znh-dashboard-update-refresh-btn') || []);
        } catch (e) {
            btns = [];
        }
        if (!btns || btns.length === 0) return;

        btns.forEach(function(btn) {
            if (!btn) return;
            btn.addEventListener('click', function() {
                dashboardRefreshRun(btn);
            });
        });
    }

    function _wireQuickActionsUI() {
        // Wire any <button class="cmd-btn" data-qa="..."> elements.
        // These run allowlisted commands via the localhost API and show output in the overlay.
        var btns = [];
        try { btns = Array.prototype.slice.call(document.querySelectorAll('button.cmd-btn[data-qa]') || []); } catch (e) { btns = []; }
        if (!btns || btns.length === 0) return;

        btns.forEach(function(btn) {
            if (!btn) return;
            btn.addEventListener('click', function(ev) {
                try { if (ev) addRipple(btn, ev.clientX, ev.clientY); } catch (e0) {}
                try {
                    if (typeof quickActionOpenFromButton === 'function') {
                        quickActionOpenFromButton(btn);
                        return;
                    }
                } catch (e1) {}

                // Fallback: copy the command if quick actions are not available.
                try {
                    var cmd = String(btn.getAttribute('data-qa-copy') || '').trim();
                    if (cmd) {
                        copyCmd(cmd, btn);
                        toast('Copy only', 'Quick Action runner not available in this dashboard build', 'err');
                        return;
                    }
                } catch (e2) {}

                toast('Not available', 'Quick Action runner not available', 'err');
            });
        });

        // Reflect diag-logs ON/OFF state in the button UI (glow + disable)
        try { if (typeof znhDiagLogsRefreshUI === 'function') znhDiagLogsRefreshUI(); } catch (e3) {}
    }

    function znhDiagLogsRefreshUI() {
        // Best-effort: query current diag-logs service state and highlight ON/OFF.
        var btnOn = null;
        var btnOff = null;
        try { btnOn = document.querySelector('button.cmd-btn[data-qa="diag-logs-on"]'); } catch (e0) { btnOn = null; }
        try { btnOff = document.querySelector('button.cmd-btn[data-qa="diag-logs-off"]'); } catch (e1) { btnOff = null; }
        if (!btnOn && !btnOff) return Promise.resolve(null);

        function _setDesc(btn, extra) {
            if (!btn) return;
            var d = null;
            try { d = btn.querySelector('.cmd-desc'); } catch (e2) { d = null; }
            if (!d) return;
            try {
                if (!btn.dataset.znhOrigDesc) btn.dataset.znhOrigDesc = String(d.textContent || '');
                var base = String(btn.dataset.znhOrigDesc || '');
                d.textContent = base + (extra ? (' • ' + extra) : '');
            } catch (e3) {}
        }

        return _api('/api/diag-logs/status', { method: 'GET' }).then(function(r) {
            var on = false;
            try { on = !!(r && (r.active || r.enabled)); } catch (e4) { on = false; }

            // Highlight the current state.
            try {
                if (btnOn) {
                    btnOn.classList.remove('state-on', 'state-off');
                    if (on) btnOn.classList.add('state-on');
                    btnOn.disabled = !!on;
                    _setDesc(btnOn, on ? 'State: ON' : 'State: OFF');
                }
                if (btnOff) {
                    btnOff.classList.remove('state-on', 'state-off');
                    if (!on) btnOff.classList.add('state-off');
                    btnOff.disabled = !on;
                    _setDesc(btnOff, on ? 'State: ON' : 'State: OFF');
                }
            } catch (e5) {}

            return r;
        }).catch(function(_e) {
            // If API is down, do nothing.
            return null;
        });
    }
    window.znhDiagLogsRefreshUI = znhDiagLogsRefreshUI;

    function znhKernelPurgeRefreshUI() {
        // Reflect Settings -> Snapper UI state.
        // Requested UX: show green "true" / red "false".
        var raw = '';
        try {
            raw = (_settingsConfig && _settingsConfig.KERNEL_PURGE_ENABLED != null) ? String(_settingsConfig.KERNEL_PURGE_ENABLED) : '';
        } catch (e0) {
