                return r0;
            }).catch(function(e) {
                var msg = (e && e.message) ? e.message : 'start failed';
                _scrubSetOut('ERROR: ' + msg);
                toast('scrub-ghost failed to start', msg, 'err');
                return null;
            });
        }

        // Read-only actions: no confirm.
        if (!confirmAction) {
            return doRun('', '');
        }

        // Confirm flow: request token + require typed phrase.
        return _api('/api/scrub/confirm', { method: 'POST', body: JSON.stringify({ action: confirmAction, params: params }) }).then(function(r) {
            var phrase = r.phrase || '';
            var hint = r.hint || ('Type ' + phrase + ' to confirm');
            var got = prompt(hint + "\n\nEnter confirmation phrase:", "");
            if (!got) {
                toast('Cancelled', 'No confirmation entered', 'err');
                return null;
            }

            // Use background job + minimizable overlay for confirmed actions.
            return doStartJob(r.confirm_token, got);
        }).catch(function(e) {
            var msg = (e && e.message) ? e.message : 'confirm failed';
            toast('Confirm failed', msg, 'err');
            _settingsClientLog('warn', 'scrub confirm failed', { action: action, error: msg });
            return null;
        });
    }

    // --- scrub-ghost Wizard (Rocket-style overlay + background jobs) ---
    var _sg = {
        step: 1,
        action: 'auto',
        params: {},
        confirm: null,
        required_phrase: '',
        job_id: '',
        running: false,
        poll_timer: null
    };

    function _sgReset() {
        _sg.step = 1;
        _sg.action = 'auto';
        _sg.params = {};
        _sg.confirm = null;
        _sg.required_phrase = '';
        _sg.job_id = '';
        _sg.running = false;
        if (_sg.poll_timer) {
            try { clearTimeout(_sg.poll_timer); } catch (e) {}
            _sg.poll_timer = null;
        }
    }

    function _sgEscapeHtml(s) {
        return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }

    function _sgBuildCopyCmd(action, params) {
        action = String(action || '').trim();
        params = params || {};

        var args = ['sudo', 'zypper-auto-helper', 'scrub-ghost'];

        function pushFlag(f) { if (f) args.push(String(f)); }
        function pushKV(k, v) { if (k && v != null && String(v).trim()) { args.push(String(k)); args.push(String(v).trim()); } }

        var applyMode = String(params.apply_mode || 'backup').toLowerCase();
        if (applyMode !== 'backup' && applyMode !== 'delete') applyMode = 'backup';

        if (action === 'scan') {
            pushFlag('--dry-run');
        } else if (action === 'apply' || action === 'auto') {
            if (applyMode === 'delete') pushFlag('--delete');
            else pushFlag('--force');
        } else if (action === 'list-backups') {
            pushFlag('--list-backups');
        } else if (action === 'validate-latest') {
            pushFlag('--validate-latest');
        } else if (action === 'validate-pick') {
            pushFlag('--validate-pick');
            pushFlag(String(params.validate_pick || ''));
        } else if (action === 'validate-from') {
            pushFlag('--validate-from');
            pushFlag(String(params.validate_from || ''));
        } else if (action === 'restore-latest') {
            pushFlag('--restore-latest');
        } else if (action === 'restore-best') {
            pushFlag('--restore-best');
        } else if (action === 'restore-pick') {
            pushFlag('--restore-pick');
            pushFlag(String(params.restore_pick || ''));
        } else if (action === 'restore-from') {
            pushFlag('--restore-from');
            pushFlag(String(params.restore_from || ''));
        } else if (action === 'completion') {
            pushFlag('--completion');
            pushFlag(String(params.completion_shell || 'zsh'));
        } else if (action === 'menu') {
            pushFlag('--menu');
        } else if (action === 'rescue') {
            pushFlag('--rescue');
        }

        // Flags (common)
        if (params.verbose) pushFlag('--verbose');
        if (params.debug) pushFlag('--debug');
        if (params.json_output) pushFlag('--json');

        if (params.no_remount_rw) pushFlag('--no-remount-rw');
        if (params.no_backup) pushFlag('--no-backup');
        if (params.no_snapper_backup) pushFlag('--no-snapper-backup');
        if (params.no_verify_snapshots) pushFlag('--no-verify-snapshots');
        if (params.no_verify_modules) pushFlag('--no-verify-modules');

        if (params.prune_stale) pushFlag('--prune-stale-snapshots');
        if (params.prune_duplicates) pushFlag('--prune-duplicates');
        if (params.prune_zombies) pushFlag('--prune-zombies');
        if (params.prune_uninstalled) {
            pushFlag('--prune-uninstalled');
            if (params.confirm_uninstalled) pushFlag('--confirm-uninstalled');
        }

        if (params.clean_restore) pushFlag('--clean-restore');
        if (params.restore_anyway) pushFlag('--restore-anyway');

        if (params.update_sdboot) pushFlag('--update-sdboot');
        if (params.rebuild_grub) pushFlag('--rebuild-grub');

        if (params.keep_backups != null && String(params.keep_backups).trim()) {
            pushKV('--keep-backups', String(params.keep_backups));
        }

        pushKV('--entries-dir', params.entries_dir);
        pushKV('--boot-dir', params.boot_dir);
        pushKV('--backup-root', params.backup_root);
        pushKV('--backup-dir', params.backup_dir);
        pushKV('--grub-cfg', params.grub_cfg);
        pushKV('--log-file', params.log_file);

        return args.join(' ');
    }

    function _sgPresetAutoIntoForm() {
        function setChecked(id, v) {
            try { var el = document.getElementById(id); if (el) el.checked = !!v; } catch (e) {}
        }
        function setVal(id, v) {
            try { var el = document.getElementById(id); if (el) el.value = (v == null) ? '' : String(v); } catch (e) {}
        }

        setVal('sg-action', 'auto');
        setVal('sg-apply-mode', 'backup');

        setChecked('sg-prune-duplicates', true);
        setChecked('sg-prune-stale', true);
        setChecked('sg-prune-uninstalled', false);
        setChecked('sg-confirm-uninstalled', false);
        setChecked('sg-prune-zombies', false);

        setChecked('sg-update-sdboot', false);
        setChecked('sg-rebuild-grub', false);

        setChecked('sg-no-remount-rw', false);
        setChecked('sg-no-backup', false);
        setChecked('sg-no-snapper-backup', false);
        setChecked('sg-no-verify-snapshots', false);
        setChecked('sg-no-verify-modules', false);

        setChecked('sg-json', false);
        setChecked('sg-verbose', false);
        setChecked('sg-debug', false);

        setVal('sg-keep-backups', '5');
        setVal('sg-entries-dir', '');
        setVal('sg-boot-dir', '');
        setVal('sg-backup-root', '');
        setVal('sg-backup-dir', '');
        setVal('sg-grub-cfg', '');
        setVal('sg-log-file', '');
        setVal('sg-restore-pick', '');
        setVal('sg-restore-from', '');
        setVal('sg-validate-pick', '');
        setVal('sg-validate-from', '');
        setVal('sg-completion-shell', 'zsh');

        setChecked('sg-clean-restore', false);
        setChecked('sg-restore-anyway', false);
    }

    function _sgReadFormParams() {
        function cb(id, defv) {
            try { var el = document.getElementById(id); if (!el) return !!defv; return !!el.checked; } catch (e) { return !!defv; }
        }
        function val(id) {
            try { var el = document.getElementById(id); if (!el) return ''; return String(el.value || '').trim(); } catch (e) { return ''; }
        }
        function pint(id, defv, minv, maxv) {
            var n = defv;
            try { n = parseInt(val(id) || String(defv), 10); if (isNaN(n)) n = defv; } catch (e) { n = defv; }
            if (typeof minv === 'number' && n < minv) n = minv;
            if (typeof maxv === 'number' && n > maxv) n = maxv;
            return n;
        }

        var p = {
            apply_mode: val('sg-apply-mode') || 'backup',
            keep_backups: pint('sg-keep-backups', 5, 0, 50),

            prune_duplicates: cb('sg-prune-duplicates', true),
            prune_stale: cb('sg-prune-stale', true),
            prune_uninstalled: cb('sg-prune-uninstalled', false),
            confirm_uninstalled: cb('sg-confirm-uninstalled', false),
            prune_zombies: cb('sg-prune-zombies', false),

            update_sdboot: cb('sg-update-sdboot', false),
            rebuild_grub: cb('sg-rebuild-grub', false),

            no_remount_rw: cb('sg-no-remount-rw', false),
            no_backup: cb('sg-no-backup', false),
            no_snapper_backup: cb('sg-no-snapper-backup', false),
            no_verify_snapshots: cb('sg-no-verify-snapshots', false),
            no_verify_modules: cb('sg-no-verify-modules', false),

            json_output: cb('sg-json', false),
            verbose: cb('sg-verbose', false),
            debug: cb('sg-debug', false),

            entries_dir: val('sg-entries-dir'),
            boot_dir: val('sg-boot-dir'),
            backup_root: val('sg-backup-root'),
            backup_dir: val('sg-backup-dir'),
            grub_cfg: val('sg-grub-cfg'),
            log_file: val('sg-log-file'),

            restore_pick: val('sg-restore-pick'),
            restore_from: val('sg-restore-from'),
            restore_anyway: cb('sg-restore-anyway', false),
            clean_restore: cb('sg-clean-restore', false),

            validate_pick: val('sg-validate-pick'),
            validate_from: val('sg-validate-from'),

            completion_shell: val('sg-completion-shell') || 'zsh'
        };

        // normalize
        if (p.apply_mode !== 'backup' && p.apply_mode !== 'delete') p.apply_mode = 'backup';
        if (p.completion_shell !== 'bash' && p.completion_shell !== 'zsh') p.completion_shell = 'zsh';

        return p;
    }

    function _sgActionNeedsConfirm(action, params) {
        action = String(action || '').trim();
        params = params || {};
        if (action === 'apply' || action === 'auto') return true;
        if (String(action).indexOf('restore-') === 0) return true;
        return false;
    }

