        _suSetButtons({
            show_cancel: true,
            show_back: false,
            show_next: true,
            show_install: false,
            show_close: false,
            next_disabled: false,
            footer_center: false
        });

        if (e.cancel) e.cancel.onclick = function() {
            if (_sg.running) return;
            _suShow(false);
        };

        if (e.next) e.next.onclick = function() {
            if (_sg.running) return;
            var act = 'auto';
            try { act = String((document.getElementById('sg-action') || {}).value || 'auto'); } catch (e2) { act = 'auto'; }
            var p = _sgReadFormParams();
            _sg.action = act;
            _sg.params = p;

            // Terminal-only actions become copy-only here.
            if (act === 'menu' || act === 'rescue') {
                _sgRenderCopyOnly(act, p);
                return;
            }

            _sgRenderConfirm(act, p);
        };

        // Apply preset
        var pb = document.getElementById('sg-preset-auto');
        if (pb) pb.addEventListener('click', function(ev) {
            try { addRipple(pb, ev.clientX, ev.clientY); } catch (e2) {}
            _sgPresetAutoIntoForm();
            toast('AUTO preset applied', 'Review options, then click Next', 'ok');
        });

        // Copy command
        var cb = document.getElementById('sg-copy-cmd');
        if (cb) cb.addEventListener('click', function() {
            var act2 = 'auto';
            try { act2 = String((document.getElementById('sg-action') || {}).value || 'auto'); } catch (e2) { act2 = 'auto'; }
            var p2 = _sgReadFormParams();
            var cmd = _sgBuildCopyCmd(act2, p2);
            try { copyCmd(cmd, cb); } catch (e3) {}
        });

        // Initial defaults
        try { _sgPresetAutoIntoForm(); } catch (e3) {}
    }

    function _sgRenderCopyOnly(action, params) {
