        if (e.back) e.back.onclick = function() { _sgRenderConfig(); };
        if (e.close) e.close.onclick = function() { _suShow(false); };

        var b = document.getElementById('sg-copy-only-btn');
        if (b) b.addEventListener('click', function() {
            try { copyCmd(cmd, b); } catch (e2) {}
        });
    }

    function _sgRenderConfirm(action, params) {
        var e = _suEls();
        if (!e.body) return;

        var needsConfirm = _sgActionNeedsConfirm(action, params);
        var cmd = _sgBuildCopyCmd(action, params);

        _ruSetHeader('Confirm', 'Step 2/2', 'Ghost-Scrub Wizard');
        _suSetMinBtnVisible(false);

        e.body.innerHTML = [
            '<div class="overlay-alert overlay-alert-warn">',
            '  <div style="font-weight:950;">Ready to run</div>',
            '  <div style="margin-top:6px; font-weight:800;">This will run scrub-ghost in a background systemd unit and stream logs here.</div>',
            '</div>',
            '<div class="feat-badge"><span class="feat-dot" style="color: var(--accent);">●</span> Command: <code style="font-size:0.85rem;">' + _sgEscapeHtml(cmd) + '</code></div>',
            '<div id="sg-confirm-block" style="margin-top: 12px;"></div>',
            '<div class="overlay-progress" style="margin-top: 12px;">',
            '  <div class="overlay-progress-row"><span id="su-stage">Waiting</span><span id="su-percent">0%</span></div>',
            '  <div class="progress-track"><div class="progress-fill" id="su-progress-bar" style="width:0%;"></div></div>',
            '</div>',
            '<pre class="overlay-pre" id="su-live-log" style="max-height: 280px;">(output will appear here)</pre>',
            '<div style="color: var(--muted); font-size:0.88rem;">You can minimize this window and reopen it from the bottom-right bubble while it runs.</div>'
        ].join('\n');

        _suSetButtons({
            show_cancel: true,
            show_back: true,
            show_next: false,
            show_install: true,
            show_close: false,
            install_disabled: !!needsConfirm,
            footer_center: true
        });

        if (e.back) e.back.onclick = function() {
            if (_sg.running) return;
            _sgRenderConfig();
        };

        if (e.cancel) e.cancel.onclick = function() {
            if (_sg.running) return;
            _suShow(false);
        };

        function _renderConfirmUi(phrase, hint) {
            var blk = document.getElementById('sg-confirm-block');
            if (!blk) return;
            if (!needsConfirm) {
                blk.innerHTML = '<div style="color: var(--muted); font-size:0.92rem;">No confirmation required for this action.</div>';
                return;
            }
            blk.innerHTML = [
                '<div class="overlay-kv">',
                '  <div class="feat-badge"><span class="feat-dot" style="color: rgba(239,68,68,0.9);">●</span> Confirmation phrase: <strong>' + _sgEscapeHtml(phrase || 'CONFIRM') + '</strong></div>',
                '</div>',
                '<div style="color: var(--muted); font-size:0.92rem;">' + _sgEscapeHtml(hint || 'Type the phrase exactly to proceed.') + '</div>',
                '<input id="sg-phrase" type="text" placeholder="Type confirmation phrase…" style="margin-top:10px; width:100%; padding: 12px; border-radius: 12px; border: 1px solid var(--border); background: rgba(255,255,255,0.04); color: var(--text);" />'
            ].join('\n');
        }

        var _confirmInfo = null;
        if (needsConfirm) {
            _renderConfirmUi('…', 'Loading confirmation…');
            _api('/api/scrub/confirm', { method: 'POST', body: JSON.stringify({ action: action, params: params }) }).then(function(r) {
                _confirmInfo = r || null;
                var phrase = '';
                var hint = '';
                try { phrase = String((r && r.phrase) ? r.phrase : '').trim(); } catch (e0) { phrase = ''; }
                try { hint = String((r && r.hint) ? r.hint : '').trim(); } catch (e1) { hint = ''; }
                _sg.required_phrase = phrase;
                _renderConfirmUi(phrase, hint);

                function updateRunEnabled() {
                    var ok = false;
                    try {
                        var inp = document.getElementById('sg-phrase');
                        var got = inp ? String(inp.value || '').trim().toUpperCase() : '';
                        ok = (got === String(phrase || '').trim().toUpperCase());
                    } catch (e2) { ok = false; }
                    _suSetButtons({ show_cancel: true, show_back: true, show_next: false, show_install: true, show_close: false, install_disabled: !ok, footer_center: true });
                }

                var inp2 = document.getElementById('sg-phrase');
                if (inp2) inp2.addEventListener('input', updateRunEnabled);
                updateRunEnabled();
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'confirm failed';
                toast('Confirm failed', msg, 'err');
                _renderConfirmUi('', 'ERROR: ' + msg);
            });
        } else {
            _renderConfirmUi('', '');
        }

        if (e.install) e.install.textContent = 'Run';
        if (e.install) e.install.onclick = function() {
            if (_sg.running) return;

            var body = { action: action, params: params };
            if (needsConfirm) {
                var got2 = '';
                try { got2 = String((document.getElementById('sg-phrase') || {}).value || '').trim(); } catch (e) { got2 = ''; }
                var tok = '';
                try { tok = String((_confirmInfo && _confirmInfo.confirm_token) ? _confirmInfo.confirm_token : '').trim(); } catch (e2) { tok = ''; }
                body.confirm_token = tok;
                body.confirm_phrase = got2;
            }

            function doStartJob() {
                toast('Starting…', 'scrub-ghost', 'ok');
                _api('/api/scrub/start', { method: 'POST', body: JSON.stringify(body) }).then(function(r) {
                    if (!r || !r.job_id) throw new Error('missing job_id');
                    _sgPollJob(String(r.job_id), action, 'scrub-ghost');
                }).catch(function(err) {
                    var msg = (err && err.message) ? err.message : 'start failed';
                    toast('scrub-ghost failed to start', msg, 'err');
                    try { _settingsClientLog('warn', 'scrub start failed', { action: action, error: msg }); } catch (e3) {}
                });
            }

            var mayChange = (action === 'apply' || action === 'auto' || (String(action || '').indexOf('restore-') === 0));
            try {
                if (mayChange && typeof znhBootStatsCaptureBaseline === 'function') {
                    znhBootStatsCaptureBaseline('scrub-ghost').then(doStartJob).catch(doStartJob);
                } else {
                    doStartJob();
                }
            } catch (eB) {
                doStartJob();
            }
        };

        _suUpdateProgress('Waiting', 0);
        _suSetLog('');
    }

    function _sgRenderRunning(taskInfo) {
        var e = _suEls();
        if (!e.body) return;
        var title = '';
        try { title = String((taskInfo && (taskInfo.title || taskInfo.action)) || 'scrub-ghost'); } catch (e0) { title = 'scrub-ghost'; }

        _suSetMinBtnVisible(true);
        e.body.innerHTML = [
            '<div class="overlay-alert overlay-alert-warn">',
            '  <div style="font-weight:950;">scrub-ghost running</div>',
            '  <div style="margin-top:6px; font-weight:800;">This job is still running in the background. You can minimize this window and reopen it from the bottom-right bubble.</div>',
            '</div>',
            '<div class="overlay-progress">',
            '  <div class="overlay-progress-row"><span id="su-stage">Running</span><span id="su-percent">0%</span></div>',
            '  <div class="progress-track"><div class="progress-fill" id="su-progress-bar" style="width:0%;"></div></div>',
            '</div>',
            '<pre class="overlay-pre" id="su-live-log" style="max-height: 320px;">(resuming logs…)</pre>'
        ].join('\n');

        _ruSetHeader('Running', 'In progress', title);
    }

    function _sgRenderDone(ok, title, subtitle, logText) {
        var e = _suEls();
        if (!e.body) return;

        _ruSetHeader('Result', 'Complete', String(title || 'Done'));

        // Render without embedding large log text into innerHTML (can freeze the UI).
        e.body.innerHTML = [
            '<div style="font-weight:950;" id="sg-done-subtitle"></div>',
            '<div class="overlay-scroll">',
            '  <div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap; justify-content:space-between;">',
            '    <div style="font-weight:950; margin-bottom: 8px;">Output (tail)</div>',
            '    <button class="pill" type="button" id="sg-done-copy" style="margin-bottom:8px;">Copy output</button>',
            '  </div>',
            '  <pre class="overlay-pre" id="sg-done-log" style="max-height: 320px;">(no output)</pre>',
            '</div>',
            '<div style="color: var(--muted); font-size:0.88rem;">Tip: use <strong>Run again</strong> to repeat, or <strong>OK</strong> to close.</div>'
        ].join('\n');

        try {
            var sub = document.getElementById('sg-done-subtitle');
            if (sub) sub.textContent = String(subtitle || '');
        } catch (eSub) {}

        // Keep the UI responsive by limiting the displayed tail.
        var tail = '';
        try { tail = String(logText || ''); } catch (eT0) { tail = ''; }
        try {
            var maxChars = 20000;
            if (tail.length > maxChars) {
                tail = tail.slice(tail.length - maxChars);
                tail = '(output truncated; showing last ' + String(maxChars) + ' chars)\n' + tail;
            }
        } catch (eT1) {}

        try {
            var pre = document.getElementById('sg-done-log');
            if (pre) pre.textContent = tail || '(no output)';
        } catch (ePre) {}

        // Copy output
        try {
            var cb = document.getElementById('sg-done-copy');
            if (cb) cb.addEventListener('click', function() {
                try { copyTextToClipboard(tail || ''); toast('Copied', 'Output copied to clipboard', 'ok'); } catch (eC) {}
            });
        } catch (eCB) {}

        // Buttons: allow running again without reopening the wizard.
        _suSetButtons({ show_cancel: false, show_back: true, show_next: false, show_install: false, show_close: true, close_disabled: false, footer_center: true });

        if (e.back) {
            e.back.textContent = 'Run again';
            e.back.onclick = function() {
                if (_sg.running) return;
                try { _sgRenderConfirm(_sg.action || 'auto', _sg.params || {}); } catch (eR) { try { _sgRenderConfig(); } catch (eR2) {} }
            };
        }

        if (e.close) e.close.textContent = 'OK';
        if (e.close) e.close.onclick = function() {
            if (_sg.running) return;
            try { _sgReset(); } catch (eR0) {}
            _suShow(false);
        };

        try { znhTaskDone('scrub-ghost', !!ok); } catch (e0) {}

        // Refresh boot/EFI stats after scrub completes (it may prune boot entries).
        try {
            setTimeout(function() {
                try { if (typeof znhBootStatsRefreshUI === 'function') znhBootStatsRefreshUI(true); } catch (e1) {}
            }, 650);
        } catch (e2) {}
    }

    function _sgPollJob(job_id, action, title) {
        _sg.job_id = job_id;
        _sg.running = true;
        _suSetMinBtnVisible(true);

        try {
            znhTaskSet({
                type: 'scrub-ghost',
                job_id: String(job_id),
                action: String(action || ''),
                title: String(title || 'scrub-ghost')
            });
        } catch (e_task) {}

        _ruSetHeader('Running', 'In progress', String(title || 'scrub-ghost'));
        _suSetButtons({ show_cancel: false, show_back: false, show_next: false, show_install: true, show_close: false, install_disabled: true, footer_center: true });

        var installBtn = _suEls().install;
        if (installBtn) installBtn.textContent = 'Running…';

        var _pollFailures = 0;
        var _pollMaxFailures = 10;
        var _pollInFlight = false;
        var _pollWarned = false;
        var _lastPct = 0;

        function tick() {
            if (_pollInFlight) return;
            _pollInFlight = true;

            return _api('/api/scrub/job?job_id=' + encodeURIComponent(job_id), { method: 'GET' }).then(function(j) {
                if (!j) return null;

                if (_pollFailures > 0) {
                    _pollFailures = 0;
                    if (_pollWarned) {
                        toast('scrub-ghost reconnected', 'Polling resumed', 'ok');
                        _pollWarned = false;
                    }
                }

                _lastPct = parseInt(j.progress || 0, 10) || 0;
                _suUpdateProgress(j.stage || 'Running', _lastPct);
                if (j.output != null) {
                    _suSetLog(String(j.output));
                    // Mirror into the in-page scrub-ghost output panel (best-effort).
                    try { if (typeof _scrubSetOut === 'function') _scrubSetOut(String(j.output || '')); } catch (eM) {}
                }
                try { znhTaskUpdateFromJob('scrub-ghost', j); } catch (e_task2) {}

                if (j.done) {
                    if (_sg.poll_timer) {
                        try { clearTimeout(_sg.poll_timer); } catch (e) {}
                        _sg.poll_timer = null;
                    }
                    _sg.running = false;
                    var rc = (j.rc != null) ? parseInt(j.rc, 10) : -1;
                    var logText = '';
                    // Prefer the server-provided tail (already bounded). Fallback to DOM.
                    try {
                        if (j.output != null) logText = String(j.output || '');
                        else logText = '';
                    } catch (e2a) {
                        logText = '';
                    }
                    if (!logText) {
                        try { logText = String(document.getElementById('su-live-log').textContent || ''); } catch (e2) { logText = ''; }
                    }

                    // Mirror final tail into the in-page scrub-ghost output panel too.
                    try { if (typeof _scrubSetOut === 'function') _scrubSetOut(String(logText || '')); } catch (eM2) {}

                    if (rc === 0) {
                        toast('scrub-ghost complete', String(title || ''), 'ok');
                        _suUpdateProgress('Done', 100);
                        _sgRenderDone(true, String(title || 'Done'), 'Completed successfully.', logText);
                    } else {
                        toast('scrub-ghost failed', 'rc=' + String(rc), 'err');
                        _suUpdateProgress('Failed', 100);
                        _sgRenderDone(false, String(title || 'Failed'), 'Command returned a non-zero exit code (see output).', logText);
                    }
                }

                return j;
            }).catch(function(e) {
                _pollFailures++;
                var msg = (e && e.message) ? e.message : 'job poll failed';

                if (!_pollWarned) {
                    _pollWarned = true;
                    toast('scrub-ghost polling error', msg, 'err');
                }

                _suUpdateProgress('Reconnecting…', _lastPct);
                _suSetLog('ERROR polling job (' + String(_pollFailures) + '/' + String(_pollMaxFailures) + '): ' + msg + '\nRetrying…');

                if (_pollFailures >= _pollMaxFailures) {
                    try {
                        znhWatcherNotifyJobPollingFailed({
                            type: 'scrub-ghost',
                            job_id: String(job_id || ''),
                            action: String(action || ''),
                            title: String(title || 'scrub-ghost')
                        });
                    } catch (eW0) {}

                    toast('scrub-ghost polling failed', 'Too many errors. Please reload the page.', 'err');
                    if (_sg.poll_timer) {
                        try { clearTimeout(_sg.poll_timer); } catch (ee) {}
                        _sg.poll_timer = null;
                    }
                    _sg.running = false;
                    _suSetButtons({ show_cancel: false, show_back: false, show_next: false, show_install: false, show_close: true, close_disabled: false, footer_center: true });
                }
                return null;
            }).finally(function() {
                _pollInFlight = false;
                if (_sg.running) {
                    _sg.poll_timer = setTimeout(tick, 850);
                }
            });
        }

        tick();
    }

    function scrubWizardOpen() {
        // Ensure other overlay flows are stopped.
        try { _suReset(); } catch (e0) {}
        try { _ruReset(); } catch (e1) {}
        try { if (typeof _qaReset === 'function') _qaReset(); } catch (e2) {}
        _sgReset();

        _suShow(true);
        _sgRenderConfig();
    }

    function _wireScrubUI() {
        var btn = document.getElementById('scrub-run-btn');
        var wizBtn = document.getElementById('scrub-wizard-btn');
        var sel = document.getElementById('scrub-action');
        if (!btn || !sel) return;

        if (wizBtn) wizBtn.addEventListener('click', function(ev) {
            try { addRipple(wizBtn, ev.clientX, ev.clientY); } catch (e) {}
            try {
                if (typeof scrubWizardOpen === 'function') {
                    scrubWizardOpen();
                } else {
                    toast('Wizard not ready', 'Reload dashboard after reinstall', 'err');
                }
            } catch (e2) {
                var msg = (e2 && e2.message) ? e2.message : 'failed';
                toast('Wizard failed', msg, 'err');
            }
        });

        // One-time guidance window per page load.
        var _scrub_guided = false;

        function _setChecked(id, v) {
            try {
                var el = document.getElementById(id);
                if (el) el.checked = !!v;
            } catch (e) {}
        }

        function _setValue(id, v) {
            try {
                var el = document.getElementById(id);
                if (el && typeof v === 'string') el.value = v;
                if (el && typeof v === 'number') el.value = String(v);
            } catch (e) {}
        }

        function scrubPresetAuto() {
            // Recommended defaults.
            _setValue('scrub-apply-mode', 'backup');
            _setChecked('scrub-prune-duplicates', true);
            _setChecked('scrub-prune-stale', true);
            _setChecked('scrub-prune-uninstalled', false);
            _setChecked('scrub-confirm-uninstalled', false);
            _setChecked('scrub-update-sdboot', false);
            _setChecked('scrub-rebuild-grub', false);
            _setChecked('scrub-no-remount-rw', false);
            _setChecked('scrub-no-backup', false);
            _setChecked('scrub-no-snapper-backup', false);
            _setChecked('scrub-no-verify-snapshots', false);
            _setChecked('scrub-no-verify-modules', false);
            _setChecked('scrub-prune-zombies', false);
            _setChecked('scrub-json', false);
            _setValue('scrub-keep-backups', 5);
            // Leave paths empty so scrub-ghost can auto-detect.
            _setValue('scrub-entries-dir', '');
            _setValue('scrub-boot-dir', '');
            _setValue('scrub-backup-root', '');
            _setValue('scrub-backup-dir', '');
            _setValue('scrub-grub-cfg', '');
            _setValue('scrub-log-file', '');
        }

        function _cb(id, defv) {
            try {
                var el = document.getElementById(id);
                if (!el) return !!defv;
                return !!el.checked;
            } catch (e) {
                return !!defv;
            }
        }

        function _val(id) {
            try {
                var el = document.getElementById(id);
                if (!el) return '';
                return String(el.value || '').trim();
            } catch (e) {
                return '';
            }
        }

        function _pint(id, defv, minv, maxv) {
            var n = defv;
            try {
                var el = document.getElementById(id);
                n = parseInt(String((el && el.value) ? el.value : String(defv)), 10);
                if (isNaN(n)) n = defv;
            } catch (e) { n = defv; }
            if (typeof minv === 'number' && n < minv) n = minv;
            if (typeof maxv === 'number' && n > maxv) n = maxv;
            return n;
        }

        function _maybeGuidance(action) {
            if (_scrub_guided) return;
            if (action !== 'auto' && action !== 'apply') return;
            _scrub_guided = true;

            var body = ''
                + 'scrub-ghost will modify boot entries when you run AUTO/apply.\n\n'
                + 'Before you click Run, review the toggles below (they map to TUI flags).\n'
                + 'Recommended: AUTO (backup mode) + prune stale + prune duplicates.\n\n'
                + 'Tip: run scan (dry-run) first if you want to preview.';

            // Non-blocking: add to notification center (glowing bell), once.
            try {
                if (typeof window.znhNotifyAdd === 'function') {
                    window.znhNotifyAdd({
                        id: 'scrub_ghost_guidance_v1',
                        title: 'scrub-ghost: review toggles before apply',
                        body: body,
                        level: 'warn',
                        once: true
                    });
                    return;
                }
            } catch (e0) {}

            // Fallback (should be rare): use a toast instead of alert().
            try {
                toast('scrub-ghost tip', 'Review toggles before apply (see notification)', 'ok');
            } catch (e1) {}
        }

        // When AUTO is selected, auto-apply the recommended preset.
        sel.addEventListener('change', function() {
            var action = 'auto';
            try { action = String(sel.value || 'auto'); } catch (e) { action = 'auto'; }
            if (action === 'auto') {
                scrubPresetAuto();
            }
            _maybeGuidance(action);
        });

        // Apply recommended preset on initial load (since AUTO is default).
        try { scrubPresetAuto(); } catch (e0) {}
        try { _maybeGuidance('auto'); } catch (e1) {}

        btn.addEventListener('click', function() {
            var action = 'auto';
            try { action = String((document.getElementById('scrub-action') || {}).value || 'auto'); } catch (e) { action = 'auto'; }

            // AUTO is just apply with recommended defaults, but user can toggle anything.
            var effectiveAction = (action === 'auto') ? 'apply' : action;

            var applyMode = 'backup';
            try { applyMode = String((document.getElementById('scrub-apply-mode') || {}).value || 'backup'); } catch (e) { applyMode = 'backup'; }
            if (applyMode !== 'backup' && applyMode !== 'delete') applyMode = 'backup';

            var keepBackups = _pint('scrub-keep-backups', 5, 1, 50);

            var params = {
                apply_mode: applyMode,
                prune_duplicates: _cb('scrub-prune-duplicates', true),
                prune_stale: _cb('scrub-prune-stale', true),
                prune_uninstalled: _cb('scrub-prune-uninstalled', false),
                confirm_uninstalled: _cb('scrub-confirm-uninstalled', false),
                prune_zombies: _cb('scrub-prune-zombies', false),
                update_sdboot: _cb('scrub-update-sdboot', false),
                rebuild_grub: _cb('scrub-rebuild-grub', false),
                keep_backups: keepBackups,

                no_remount_rw: _cb('scrub-no-remount-rw', false),
                no_backup: _cb('scrub-no-backup', false),
                no_snapper_backup: _cb('scrub-no-snapper-backup', false),
                no_verify_snapshots: _cb('scrub-no-verify-snapshots', false),
                no_verify_modules: _cb('scrub-no-verify-modules', false),

                json_output: _cb('scrub-json', false),

                entries_dir: _val('scrub-entries-dir'),
                boot_dir: _val('scrub-boot-dir'),
                backup_root: _val('scrub-backup-root'),
                backup_dir: _val('scrub-backup-dir'),
                grub_cfg: _val('scrub-grub-cfg'),
                log_file: _val('scrub-log-file')
            };

            // Extra guidance window right before running.
            if (effectiveAction === 'apply') {
                var summary = 'About to run scrub-ghost apply:\n'
                    + '- apply mode: ' + applyMode + '\n'
                    + '- prune stale snapshots: ' + (params.prune_stale ? 'ON' : 'OFF') + '\n'
                    + '- prune duplicates: ' + (params.prune_duplicates ? 'ON' : 'OFF') + '\n'
