            try { isDry = !!(dry && dry.checked); } catch (eD0) { isDry = false; }
            if (isDry) {
                try { postSel.value = 'none'; } catch (eD1) {}
                _su.post_action = 'none';
                try { postSel.disabled = true; } catch (eD2) {}
            } else {
                try { postSel.disabled = false; } catch (eD3) {}
            }
        }

        if (postSel) {
            try { postSel.value = _suNormalizePostAction(_su.post_action); } catch (eP0) {}
            postSel.addEventListener('change', function() {
                try { _su.post_action = _suNormalizePostAction(postSel.value); } catch (eP1) { _su.post_action = 'none'; }
                syncPostActionDisabled();
            });
        }

        if (inp) inp.addEventListener('input', updateInstallEnabled);
        if (dry) dry.addEventListener('change', function() {
            _su.dry_run = !!dry.checked;
            syncPostActionDisabled();
        });
        syncPostActionDisabled();
        updateInstallEnabled();
    }

    function _suUpdateProgress(stage, percent) {
        var st = document.getElementById('su-stage');
        var pc = document.getElementById('su-percent');
        var bar = document.getElementById('su-progress-bar');
        var stTxt = String(stage || '');
        var pct = parseInt(percent || 0, 10) || 0;

        if (st) st.textContent = stTxt;
        if (pc) pc.textContent = String(pct) + '%';
        if (bar) {
            bar.style.width = String(pct) + '%';
            // Visual polish: apply a "waiting" animation class for stages that are
            // not making linear progress (locks, reconnects, early starting).
            try {
                var low = stTxt.toLowerCase();
                var isWaiting = (
                    low.indexOf('waiting') !== -1
                    || low.indexOf('starting') !== -1
                    || low.indexOf('reconnecting') !== -1
                    || low.indexOf('connecting') !== -1
                    || low.indexOf('comput') !== -1
                );
                if (isWaiting && pct < 100) {
                    bar.classList.add('waiting');
                } else {
                    bar.classList.remove('waiting');
                }
            } catch (e) {}
        }
    }

    function _suSetLog(text) {
        var pre = document.getElementById('su-live-log');
        if (!pre) return;

        var atBottom = false;
        try { atBottom = _nearBottom(pre, 60); } catch (e) { atBottom = true; }

        var t = '';
        try { t = String(text || ''); } catch (e0) { t = ''; }

        // Avoid repeated huge DOM updates (can freeze the page).
        try {
            if (pre._znh_last_text != null && String(pre._znh_last_text) === t) {
                return;
            }
            pre._znh_last_text = t;
        } catch (e1) {}

        // Keep it bounded.
        try {
            var maxChars = 24000;
            if (t.length > maxChars) {
                t = '(output truncated; showing last ' + String(maxChars) + ' chars)\n' + t.slice(t.length - maxChars);
            }
        } catch (e2) {}

        pre.textContent = t;
        if (atBottom) {
            try { pre.scrollTop = pre.scrollHeight; } catch (ee) {}
        }

        // Avoid expensive highlighting on huge logs.
        try {
            if (typeof highlightBlock === 'function' && t.length <= 12000) {
                highlightBlock('su-live-log');
            }
        } catch (eH) {}
    }

    // --- Quick Actions (run allowlisted helper commands from WebUI) ---
    var _qa = {
        action: '',
        title: '',
        desc: '',
        copy_cmd: '',
        danger: false,
        interactive: false,
        confirm: null,
        required_phrase: '',
        job_id: '',
        running: false,
        poll_timer: null
    };

    function _qaReset() {
        _qa.action = '';
        _qa.title = '';
        _qa.desc = '';
        _qa.copy_cmd = '';
        _qa.danger = false;
        _qa.interactive = false;
        _qa.confirm = null;
        _qa.required_phrase = '';
        _qa.job_id = '';
        _qa.running = false;
        if (_qa.poll_timer) {
            try { clearTimeout(_qa.poll_timer); } catch (e) {}
            _qa.poll_timer = null;
        }
    }

    function _qaSetHeader(mode, stepText, title) {
        var e = _suEls();
        if (e.title) e.title.textContent = String(title || 'Quick Action');
        if (e.mode) e.mode.textContent = String(mode || 'Quick Action');
        if (e.step) e.step.textContent = String(stepText || '');
    }

    function _qaEscapeHtml(s) {
        return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }

    function quickActionOpenFromButton(btn) {
        if (!btn) return;
        var action = String(btn.getAttribute('data-qa') || '').trim();
        if (!action) return;

        var copyCmdText = String(btn.getAttribute('data-qa-copy') || '').trim();
        var danger = String(btn.getAttribute('data-qa-danger') || '') === '1';
        var interactive = String(btn.getAttribute('data-qa-interactive') || '') === '1';

        var title = action;
        var desc = '';
        try {
            var lab = btn.querySelector('.cmd-label');
            if (lab && String(lab.textContent || '').trim()) title = String(lab.textContent || '').trim();
        } catch (e) {}
        try {
            var d = btn.querySelector('.cmd-desc');
            if (d && String(d.textContent || '').trim()) desc = String(d.textContent || '').trim();
        } catch (e2) {}
        title = title.replace(/^Run:\s*/i, '').replace(/^Open:\s*/i, '').trim();

        return quickActionOpen({ action: action, title: title, desc: desc, copy_cmd: copyCmdText, danger: danger, interactive: interactive });
    }

    function _qaTaskIsActive() {
        try {
            var t = _znhTaskLoad();
            return !!(t && t.type && t.job_id);
        } catch (e) {
            return false;
        }
    }

    function quickActionOpen(opts) {
        opts = opts || {};

        // Ensure other overlay flows are stopped.
        try { _suReset(); } catch (e0) {}
        try { _ruReset(); } catch (e1) {}
        _qaReset();

        _qa.action = String(opts.action || '').trim();
        _qa.title = String(opts.title || opts.action || 'Quick action').trim();
        _qa.desc = String(opts.desc || '').trim();
        _qa.copy_cmd = String(opts.copy_cmd || '').trim();
        _qa.danger = !!opts.danger;
        _qa.interactive = !!opts.interactive;

        if (!_qa.action) return null;

        _suShow(true);
        _suSetMinBtnVisible(false);

        // Copy-only actions are allowed even when an update job is running.
        if (_qa.interactive) {
            return _qaRenderInteractiveOnly();
        }

        // Safety: don't clobber an active long-running update job.
        if (_qaTaskIsActive()) {
            toast('Task running', 'A background job is already running. Use the bottom-right bubble to view it.', 'err');
            return _qaRenderCopyOnly('A background job is already running. This Quick Action is copy-only until the running task finishes.');
        }

        if (_qa.danger) {
            _qaSetHeader('Confirm', 'Step 1/2', _qa.title);
            var e = _suEls();
            if (e.body) e.body.innerHTML = '<div style="color: var(--muted); font-weight:900;">Loading confirmation…</div>';
            _suSetButtons({ show_cancel: true, show_back: false, show_next: false, show_install: false, show_close: false, footer_center: true });

            // Request confirm token + phrase from the API.
            return _api('/api/quick/confirm', { method: 'POST', body: JSON.stringify({ action: _qa.action }) }).then(function(r) {
                _qa.confirm = r || null;
                try { _qa.required_phrase = String((r && r.phrase) ? r.phrase : 'CONFIRM').trim(); } catch (e2) { _qa.required_phrase = 'CONFIRM'; }
                return _qaRenderForm();
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'confirm failed';
                toast('Confirm failed', msg, 'err');
                return _qaRenderCopyOnly('Confirmation failed: ' + msg);
            });
        }

        // Safe action: no confirm required.
        _qa.required_phrase = '';
        _qa.confirm = null;
        return _qaRenderForm();
    }

    function _qaRenderCopyOnly(reasonText) {
        var e = _suEls();
        if (!e.body) return;

        var cmdHtml = _qa.copy_cmd ? ('<div class="feat-badge"><span class="feat-dot" style="color: var(--accent);">●</span> Command: <code style="font-size:0.85rem;">' + _qaEscapeHtml(_qa.copy_cmd) + '</code></div>') : '';

        e.body.innerHTML = [
            '<div class="overlay-alert overlay-alert-warn">',
            '  <div style="font-weight:950;">Quick Action</div>',
