        if (ch !== 'stable' && ch !== 'rolling') ch = _selfUpdateGetChannel(_settingsConfig || {});

        _suReset();
        _su.channel = ch;
        _su.auto_dry_run = !!(opts && opts.auto_dry_run);

        _suShow(true);
        _suRenderAgreement(null);

        // Enrich agreement with live status.
        selfUpdateFetchStatus(false).then(function(st) {
            try { _suRenderAgreement(st); } catch (e) {}
        });

        var e = _suEls();
        if (!e.overlay) return;

        if (e.cancel) e.cancel.onclick = function(ev) {
            if (_su.running) return;
            try { if (ev) { ev.preventDefault(); ev.stopPropagation(); } } catch (e0) {}
            try { if (typeof window.znhJsHealthLog === 'function') window.znhJsHealthLog('debug', 'self-update overlay cancel clicked'); } catch (e1) {}
            _suShow(false);
        };
        if (e.close) e.close.onclick = function(ev) {
            try { if (ev) { ev.preventDefault(); ev.stopPropagation(); } } catch (e0) {}
            try { if (typeof window.znhJsHealthLog === 'function') window.znhJsHealthLog('debug', 'self-update overlay close clicked'); } catch (e1) {}
            _suShow(false);
        };
        if (e.back) e.back.onclick = function() {
            if (_su.running) return;
            _suRenderAgreement(null);
        };

        if (e.next) e.next.onclick = function() {
            if (!_su.accepted || _su.running) return;
            toast('Preparing install…', 'Requesting confirmation token', 'ok');
            _api('/api/self-update/confirm', { method: 'POST', body: JSON.stringify({ channel: ch }) }).then(function(r) {
                _suRenderInstall(r || {});
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'confirm failed';
                toast('Confirm failed', msg, 'err');
                _suSetLog('ERROR: ' + msg);
            });
        };

        if (e.install) e.install.onclick = function() {
            if (_su.running) return;
            var phraseInp = document.getElementById('su-phrase');
            var got = '';
            try { got = String((phraseInp && phraseInp.value) ? phraseInp.value : '').trim(); } catch (ee) { got = ''; }
            var dry = false;
            try {
                var cb = document.getElementById('su-dry-run');
                dry = !!(cb && cb.checked);
            } catch (ee2) { dry = false; }

            var confirmToken = (_su.confirm && _su.confirm.confirm_token) ? String(_su.confirm.confirm_token) : '';
            if (!confirmToken) {
                toast('Error', 'Missing confirm token (go back and try again)', 'err');
                return;
            }

            toast('Self-update starting…', dry ? 'Dry-run test (no install)' : ('Channel=' + ch), 'ok');

            var postAction = 'none';
            try {
                var sel = document.getElementById('su-post-action');
                postAction = sel ? String(sel.value || 'none') : String(_su.post_action || 'none');
            } catch (ePA0) {
                postAction = String(_su.post_action || 'none');
            }
            postAction = String(postAction || 'none').toLowerCase();
            if (postAction !== 'none' && postAction !== 'verify' && postAction !== 'install') postAction = 'none';
            if (dry) postAction = 'none';

            _api('/api/self-update/start', {
                method: 'POST',
                body: JSON.stringify({
                    channel: ch,
                    confirm_token: confirmToken,
                    confirm_phrase: got,
                    dry_run: dry,
                    post_action: postAction
                })
            }).then(function(res) {
                if (!res || !res.job_id) {
                    throw new Error('missing job_id');
                }
                _suPollJob(String(res.job_id), ch, dry, false);
                return res;
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'failed';
                toast('Self-update start failed', msg, 'err');
                _settingsClientLog('warn', 'self-update start failed', { error: msg });
            });
        };
    }

    function selfUpdateRun(btnEl) {
        // Update button now opens a blocking overlay workflow.
        // Safety: if a status check/channel toggle/job is in-flight, do not allow starting.
        if (_selfUpdateUiLocked()) {
            toast('Locked', 'Self-update is busy/running. Please wait.', 'err');
            return Promise.resolve(null);
        }
        return selfUpdateOpenOverlay(btnEl);
    }

    function selfUpdateAutoQueryInit() {
        // URL query allows opening the overlay automatically (used by CLI dry-run -> WebUI simulation).
        // Example: status.html?live=1&su=1&su_channel=stable&su_dry=1
        var sp = null;
        try { sp = new URLSearchParams(window.location.search || ''); } catch (e) { sp = null; }
        if (!sp) return;

        var su = String(sp.get('su') || sp.get('selfupdate') || sp.get('self-update') || '').toLowerCase();
        if (su !== '1' && su !== 'true' && su !== 'yes') return;

        var ch = String(sp.get('su_channel') || '').toLowerCase();
        var dry = String(sp.get('su_dry') || sp.get('dry') || '').toLowerCase();
        var autoDry = (dry === '1' || dry === 'true' || dry === 'yes');

        // Only run once per page load (settingsLoad() can be triggered multiple times).
        if (window.__znh_su_auto_open_done) return;
        window.__znh_su_auto_open_done = true;

        // Give the page a moment to render.
        setTimeout(function() {
            if (_znhOverlayGuardActive()) {
                try { if (typeof window.znhJsHealthLog === 'function') window.znhJsHealthLog('debug', 'self-update auto-open blocked (guard active)'); } catch (e1) {}
                return;
            }
            try { selfUpdateOpenOverlay({ channel: ch, auto_dry_run: autoDry }); } catch (e2) {}
        }, 400);
    }

    function rocketUpdateAutoQueryInit() {
        // URL query allows opening the Rocket Update Wizard automatically.
        // Example: status.html?live=1&ru=1&ru_dry=1
        var sp = null;
        try { sp = new URLSearchParams(window.location.search || ''); } catch (e) { sp = null; }
        if (!sp) return;

        // If self-update auto-open is requested too, prefer self-update to avoid two overlays fighting.
        var su = String(sp.get('su') || sp.get('selfupdate') || sp.get('self-update') || '').toLowerCase();
        if (su === '1' || su === 'true' || su === 'yes') return;

        var ru = String(sp.get('ru') || sp.get('rocket') || sp.get('systemupdate') || sp.get('system-update') || sp.get('dup') || '').toLowerCase();
        if (ru !== '1' && ru !== 'true' && ru !== 'yes') return;

        var dry = String(sp.get('ru_dry') || sp.get('ru_sim') || sp.get('simulate') || '').toLowerCase();
        var autoSim = (dry === '1' || dry === 'true' || dry === 'yes');

        // Only run once per page load (settingsLoad() can be triggered multiple times).
        if (window.__znh_ru_auto_open_done) return;
        window.__znh_ru_auto_open_done = true;

        setTimeout(function() {
            if (_znhOverlayGuardActive()) {
                try { if (typeof window.znhJsHealthLog === 'function') window.znhJsHealthLog('debug', 'rocket auto-open blocked (guard active)'); } catch (e1) {}
                return;
            }
            try { rocketUpdateWizardOpen({ auto_simulate: autoSim }); } catch (e2) {}
        }, 450);
    }

    function selfUpdateFetchChangelog(btnEl) {
        var btn = btnEl || document.getElementById('self-update-changelog-btn');
        if (btn) btn.disabled = true;
        _selfUpdateSetChangelog('Loading changelog from GitHub…');

        var ch = _selfUpdateGetChannel(_settingsConfig || {});
        var base = 'https://api.github.com/repos/' + encodeURIComponent(GITHUB_OWNER) + '/' + encodeURIComponent(GITHUB_REPO);

        if (ch === 'stable') {
            return _githubApiJson(base + '/releases/latest').then(function(j) {
                var out = [];
                out.push('Stable channel (GitHub Releases)');
                out.push('Tag: ' + String(j.tag_name || 'unknown'));
                if (j.published_at) out.push('Published: ' + String(j.published_at));
                out.push('');
                out.push(String(j.body || '(no release notes)'));
                _selfUpdateSetChangelog(out.join('\n'));
                toast('Changelog loaded', 'Stable release notes fetched', 'ok');
                return j;
            }).catch(function(e) {
                var msg = (e && e.message) ? e.message : 'failed';
                _selfUpdateSetChangelog('ERROR: ' + msg);
                toast('Changelog failed', msg, 'err');
                return null;
            }).finally(function() {
                if (btn) btn.disabled = false;
            });
        }

        // rolling: show latest commits on main
        return _githubApiJson(base + '/commits?per_page=12').then(function(arr) {
            var out2 = [];
            out2.push('Rolling channel (latest commits on main)');
            out2.push('');
            (arr || []).forEach(function(c) {
                var sha = (c && c.sha) ? String(c.sha).slice(0, 7) : '???????';
                var msg = '';
                try { msg = String(((c || {}).commit || {}).message || ''); } catch (e) { msg = ''; }
                msg = msg.split('\n')[0];
                var dt = '';
                try { dt = String((((c || {}).commit || {}).author || {}).date || ''); } catch (e) { dt = ''; }
                out2.push('- ' + sha + (dt ? (' ' + dt) : '') + ' ' + msg);
            });
            _selfUpdateSetChangelog(out2.join('\n'));
            toast('Changelog loaded', 'Recent commits fetched', 'ok');
            return arr;
        }).catch(function(e) {
            var msg2 = (e && e.message) ? e.message : 'failed';
            _selfUpdateSetChangelog('ERROR: ' + msg2);
            toast('Changelog failed', msg2, 'err');
            return null;
        }).finally(function() {
            if (btn) btn.disabled = false;
        });
    }

    function selfUpdateToggleChannel(btnEl) {
        var btn = btnEl || document.getElementById('self-update-toggle-btn');

        // Hard lock: do not allow channel switching while status check or job is running.
        if (_selfUpdateUiLocked()) {
            toast('Locked', 'Cannot switch channel while self-update is busy/running.', 'err');
            return Promise.resolve(null);
        }

        var cur = _selfUpdateGetChannel(_settingsConfig || {});
        var next = (cur === 'rolling') ? 'stable' : 'rolling';

        if (btn) btn.disabled = true;
        try { _self_update_ui.toggling = true; } catch (e0) {}
        try { _selfUpdateUiApplyLocks(); } catch (e1) {}
        toast('Switching channel…', 'Setting SELF_UPDATE_CHANNEL=' + next, 'ok');

        return _api('/api/config', { method: 'POST', body: JSON.stringify({ patch: { SELF_UPDATE_CHANNEL: next } }) }).then(function(r) {
            // Keep local config in sync and re-render.
            _settingsConfig = (r && r.config) ? r.config : _settingsConfig;
            selfUpdateRender();
            try { selfUpdateFetchStatus(false); } catch (e) {}

            // If settings drawer is open, update the select value too.
            try {
                var form = document.getElementById('settings-form');
                var sel = form ? form.querySelector('select[data-key="SELF_UPDATE_CHANNEL"]') : null;
                if (sel) sel.value = next;
            } catch (e) {}

            _settingsClientLog('info', 'self-update channel toggled', { from: cur, to: next });
            toast('Channel updated', 'Now: ' + next, 'ok');

            // Reload config + schema to ensure we reflect any server-side healing.
            try { settingsLoad(false); } catch (e) {}
            return r;
        }).catch(function(e) {
            var msg = (e && e.message) ? e.message : 'failed';
            toast('Toggle failed', msg, 'err');
            _settingsClientLog('warn', 'self-update channel toggle failed', { error: msg });
            return null;
        }).finally(function() {
            try { _self_update_ui.toggling = false; } catch (e0) {}
            try { _selfUpdateUiApplyLocks(); } catch (e1) {}
            if (btn) btn.disabled = false;
        });
    }

    function _wireSelfUpdateUI() {
        var chEl = document.getElementById('self-update-channel');
        var statusEl = document.getElementById('self-update-status');
        var toggleBtn = document.getElementById('self-update-toggle-btn');
        var runBtn = document.getElementById('self-update-run-btn');
        var clBtn = document.getElementById('self-update-changelog-btn');
        var simBtn = document.getElementById('self-update-sim-run-btn');
        var lockBadge = document.getElementById('self-update-lock-badge');

        if (!chEl && !statusEl && !toggleBtn && !runBtn && !clBtn && !simBtn) return;

        if (toggleBtn) toggleBtn.addEventListener('click', function(ev) {
            try { addRipple(toggleBtn, ev.clientX, ev.clientY); } catch (e) {}
            selfUpdateToggleChannel(toggleBtn);
        });

        // Clicking the LOCKED badge should open the overlay so the user can see live logs
        // (especially useful when the overlay was minimized).
        function _openSelfUpdateOverlayFromBadge(ev) {
            try { if (ev) { ev.preventDefault(); ev.stopPropagation(); } } catch (e0) {}

            // If a self-update task is running, open the existing overlay view.
            // This uses the same resume logic as the bottom-right bubble.
            try {
                if (_self_update_ui.job_running || (_su && _su.running)) {
                    znhTaskOpenOverlayFromBubble();
                    return;
                }
            } catch (e1) {}

            // If we are locked for another reason (checking/toggling), just inform the user.
            if (_selfUpdateUiLocked()) {
                toast('Locked', 'Self-update is busy. Please wait a moment…', 'err');
                return;
            }

            // Otherwise open the normal self-update flow.
            try { selfUpdateOpenOverlay({}); } catch (e2) {}
        }

        if (lockBadge) {
            try { lockBadge.style.cursor = 'pointer'; } catch (e0s) {}
            lockBadge.addEventListener('click', _openSelfUpdateOverlayFromBadge);
            lockBadge.addEventListener('keydown', function(ev) {
                if (!ev) return;
                if (ev.key === 'Enter' || ev.key === ' ') {
                    _openSelfUpdateOverlayFromBadge(ev);
                }
            });
        }

        if (runBtn) runBtn.addEventListener('click', function(ev) {
            try { addRipple(runBtn, ev.clientX, ev.clientY); } catch (e) {}
            selfUpdateRun(runBtn);
        });

        if (clBtn) clBtn.addEventListener('click', function(ev) {
            try { addRipple(clBtn, ev.clientX, ev.clientY); } catch (e) {}
            selfUpdateFetchChangelog(clBtn).finally(function() {
                try { selfUpdateFetchStatus(false); } catch (e2) {}
            });
        });

        // Debug action: open self-update overlay in SAFE dry-run simulation mode.
        if (simBtn) simBtn.addEventListener('click', function(ev) {
            try { addRipple(simBtn, ev.clientX, ev.clientY); } catch (e) {}
            try { selfUpdateOpenOverlay({ auto_dry_run: true }); } catch (e2) {}
        });

        // Initial render + status probe (best-effort)
        try { selfUpdateRender(); } catch (e) {}
        try { selfUpdateFetchStatus(false); } catch (e) {}
    }

    // --- Rocket Update Wizard (system updates via zypper dup) ---
    var _ru = {
        step: 1,
        accepted: false,
        confirm: null,
        required_phrase: 'INSTALL',
        job_id: '',
        poll_timer: null,
        running: false,
        simulate: false,
        auto_simulate: false,
        last_preview: null,
        conflict_override: false
    };

    function _ruReset() {
        _ru.step = 1;
        _ru.accepted = false;
        _ru.confirm = null;
        _ru.required_phrase = 'INSTALL';
        _ru.job_id = '';
        _ru.running = false;
        _ru.simulate = false;
        _ru.auto_simulate = false;
        _ru.last_preview = null;
        _ru.conflict_override = false;
        if (_ru.poll_timer) {
            try { clearTimeout(_ru.poll_timer); } catch (e) {}
            _ru.poll_timer = null;
        }
    }

    function _ruSetHeader(mode, stepText, title) {
        var e = _suEls();
        if (e.title) e.title.textContent = String(title || 'Install Updates');
        if (e.mode) e.mode.textContent = String(mode || 'Preview');
        if (e.step) e.step.textContent = String(stepText || '');
    }

    function _ruRenderPreview(preview) {
        var e = _suEls();
        if (!e.body) return;
        var p = preview || {};
        _ru.last_preview = p;

        var out = (p.output != null) ? String(p.output) : '';
        var rc = (p.rc != null) ? parseInt(p.rc, 10) : -1;
        var cmd = (p.cmd != null) ? String(p.cmd) : '';

        var conflictDetected = false;
        var conflictSummary = '';
        try {
            conflictDetected = !!(p && p.conflict_detected);
            conflictSummary = (p && p.conflict_summary != null) ? String(p.conflict_summary) : '';
        } catch (e_cf0) {
            conflictDetected = false;
            conflictSummary = '';
        }

        // Rocket vendor-change toggle (advanced)
        var allowVendor = false;
        try { allowVendor = String((_settingsConfig || {}).ROCKET_WIZARD_ALLOW_VENDOR_CHANGE || '').toLowerCase() === 'true'; } catch (e_av0) { allowVendor = false; }

        // Best-effort: detect whether the conflict looks like a vendor-switch scenario.
        // If so, Rocket should strongly guide the user to enable allow-vendor-change (or use terminal mode).
        var vendorConflict = false;
        try {
            var t0 = (conflictSummary || out || '');
            var low0 = String(t0 || '').toLowerCase();
            if (low0.indexOf('vendor') !== -1 && (low0.indexOf('from vendor') !== -1 || low0.indexOf('replacing') !== -1)) vendorConflict = true;
            if (low0.indexOf('allow-vendor-change') !== -1) vendorConflict = true;
        } catch (e_vc0) { vendorConflict = false; }

        _ru.conflict_override = false;

        // If there are no system updates, exit early (no need for confirmation step).
        var noUpdates = false;
        try {
            var low = out.toLowerCase();
            if (rc === 0 && (low.indexOf('nothing to do.') !== -1 || low.indexOf('\nnothing to do.') !== -1 || low.indexOf('nothing to do') !== -1)) {
                noUpdates = true;
            }
        } catch (e_noup) { noUpdates = false; }

        if (noUpdates) {
            // If the system is up to date, keep the dashboard UI consistent:
            // - Set pending updates to 0 immediately (avoid stale cached count)
            // - If live mode is enabled, request a dashboard refresh so status-data.json updates
            //   quickly (best-effort; silent on failure).
            var rebootReq = false;
            try { rebootReq = !!(p && p.reboot_required); } catch (e_rr0) { rebootReq = false; }

            var subtitle0 = rebootReq
                ? 'No system updates available (Nothing to do). Reboot is still required.'
                : 'No system updates available (Nothing to do).';

            toast('Up to date', subtitle0, 'ok');
            _ru.running = false;

            // Prevent stale UI badge/count when dry-run cache is old.
            try { setText('pending-count', 0); } catch (e_pc0) {}
            try {
                window.__znh_pending_override = 0;
                window.__znh_pending_override_until = Date.now() + 60 * 1000;
            } catch (e_po0) {}

            // Best-effort: refresh dashboard artifacts so Live mode won't keep showing a stale pending count.
            try {
                if (typeof liveEnabled !== 'undefined' && liveEnabled) {
                    _api('/api/dashboard/refresh', {
                        method: 'POST',
                        body: JSON.stringify({ reason: 'rocket-preview-no-updates' })
                    }).then(function() {
                        try {
                            if (ZNH_DEBUG) znhDebugLog('dashboard refreshed after no-updates preview');
                        } catch (e0) {}
                    }).catch(function() {
                        // ignore
                    });
                }
            } catch (e_sync0) {}

            try { znhTaskDone('system-update', true); } catch (e_task_ru_done0) {}
            _ruRenderDone('Up to date', subtitle0, out, '');
            return;
        }

        var cfBlock = '';
        if (conflictDetected) {
            cfBlock = [
                '<div class="overlay-alert overlay-alert-warn" style="border-color: rgba(255,110,110,0.55); background: rgba(255,110,110,0.08);">',
                '  <div style="font-weight:950;">Conflict detected</div>',
                '  <div style="margin-top:6px; font-weight:800;">The preview suggests solver conflicts / manual decisions. Non-interactive <code>zypper dup</code> may abort. Recommended: run the update in a terminal.</div>',
                '  <div style="margin-top:8px; color: var(--muted); font-size:0.9rem;">Rocket setting: <code>ROCKET_WIZARD_ALLOW_VENDOR_CHANGE</code> = <strong>' + (allowVendor ? 'true' : 'false') + '</strong></div>',
                (vendorConflict && !allowVendor ? '  <div style="margin-top:8px; font-weight:800;">This looks like a <strong>vendor switch</strong> conflict. To try non-interactively, enable <code>--allow-vendor-change</code> (or run the update in a terminal).</div>' : ''),
                (!allowVendor ? '  <button class="pill" type="button" id="ru-enable-vendor-change" style="margin-top:10px;" disabled>Enable allow-vendor-change (Rocket)</button>' : ''),
                (!allowVendor ? '  <div style="margin-top:6px; color: var(--muted); font-size:0.88rem;">Tip: first check the manual-intervention box below, then enable vendor change.</div>' : ''),
                (conflictSummary ? ('  <pre class="overlay-pre" style="max-height: 200px; margin-top: 10px;">' + conflictSummary.replace(/</g,'&lt;') + '</pre>') : ''),
                '</div>',
            ].join('\n');
        }

        e.body.innerHTML = [
            '<div class="overlay-alert overlay-alert-warn">',
            '  <div style="font-weight:950;">Preview first (safe)</div>',
            '  <div style="margin-top:6px; font-weight:800;">This is a <code>zypper dup --dry-run --details</code> preview. No packages are installed in this step.</div>',
            '</div>',
            cfBlock,
            '<div style="color: var(--muted); font-size:0.92rem;">',
            '  <strong>What the Rocket Wizard does next:</strong> if you continue and confirm, it will run <code>zypper dup</code> in a dedicated systemd unit and stream the output here, then run <code>zypper ps -s</code> to show what needs restarting.',
            '</div>',
            (cmd ? ('<div class="feat-badge"><span class="feat-dot" style="color: var(--accent);">●</span> Command: <code style="font-size:0.85rem;">' + cmd.replace(/</g,'&lt;') + '</code></div>') : ''),
            '<div style="display:flex; gap:10px; flex-wrap:wrap; align-items:center;">',
            '  <button class="pill" type="button" id="ru-refresh-preview">Refresh preview</button>',
            '  <label class="pill" style="gap:10px; justify-content:flex-start;"><input type="checkbox" id="ru-auto-sim" /> Simulation only (dry-run; no install)</label>',
            '  <div style="color: var(--muted); font-size:0.88rem;">rc=' + String(isNaN(rc) ? '?' : rc) + (p.used_systemd_run ? ' • via systemd-run' : '') + '</div>',
            '</div>',
            '<pre class="overlay-pre" id="ru-preview-out" style="max-height: 360px;">' + (out ? out.replace(/</g,'&lt;') : '(no output)') + '</pre>',
            '<label class="pill" style="gap:10px; justify-content:flex-start;"><input type="checkbox" id="ru-accept" /> I reviewed the preview and I want to continue.</label>',
            (conflictDetected ? '<label class="pill" style="gap:10px; justify-content:flex-start; margin-top: 8px;"><input type="checkbox" id="ru-conflict-ok" /> I understand conflicts may require manual terminal decisions, but I want to try anyway.</label>' : ''),
            '<div style="color: var(--muted); font-size:0.88rem;">Tip: if zypper reports conflicts / manual decisions in the preview, the wizard may fail in non-interactive mode. In that case, use the normal terminal-based install flow.</div>'
        ].join('\n');

        _ruSetHeader('Preview', 'Step 1/3', _ru.auto_simulate ? 'Simulate system updates (dry-run)' : 'Install system updates');

        _suSetButtons({
            show_cancel: true,
            show_back: false,
            show_next: true,
            show_install: false,
            show_close: false,
            next_disabled: true,
            footer_center: false
        });

        function _ruPreviewUpdateNextEnabled() {
            var ok = !!_ru.accepted;
            if (conflictDetected) {
                ok = ok && !!_ru.conflict_override;

                // If this looks like a vendor-switch conflict and vendor-change is OFF,
                // do not allow proceeding into a non-interactive run that will likely abort.
                if (vendorConflict && !allowVendor) {
                    ok = false;
                }
            }

            // Vendor-change enable button is intentionally gated behind the manual-intervention checkbox.
            // This makes the user explicitly acknowledge that the solver may do risky things.
            try {
                var evcBtn = document.getElementById('ru-enable-vendor-change');
                if (evcBtn) {
                    evcBtn.disabled = !(_ru.conflict_override);
                }
            } catch (e_evc_gate) {}

            _suSetButtons({
                show_cancel: true,
                show_back: false,
                show_next: true,
                show_install: false,
                show_close: false,
                next_disabled: !ok,
                footer_center: false
            });
        }

        var acc = document.getElementById('ru-accept');
        var cfok = document.getElementById('ru-conflict-ok');
        if (acc) {
            // Keep UI in sync when preview is re-rendered (e.g. Back button).
            try { acc.checked = !!_ru.accepted; } catch (e0) {}
            acc.addEventListener('change', function() {
                _ru.accepted = !!acc.checked;
                _ruPreviewUpdateNextEnabled();
