    function _ruRenderDone(title, subtitle, logText, restartText, opts) {
        var e = _suEls();
        if (!e.body) return;

        opts = opts || {};

        var safe = function(s) { return String(s || '').replace(/</g, '&lt;'); };

        _ruSetHeader('Result', 'Complete', String(title || 'Done'));
