                toast('Copied command', interactiveCmd, 'ok');
            } catch (e2) {
                toast('Copy failed', interactiveCmd, 'err');
            }
        });

        if (e.close) e.close.textContent = 'OK';
        _suSetButtons({
            show_cancel: false,
            show_back: false,
            show_next: false,
            show_install: false,
            show_close: true,
            close_disabled: false,
            footer_center: true
        });

        if (e.close) e.close.onclick = function() { _suShow(false); };
