    function _ruPollJob(job_id) {
        _ru.job_id = job_id;
        _ru.running = true;
        _suSetMinBtnVisible(true);
        try {
            znhTaskSet({
                type: 'system-update',
                job_id: String(job_id),
                simulate: !!_ru.simulate
            });
        } catch (e_task_ru) {}

        _suSetButtons({
            show_cancel: false,
            show_back: false,
            show_next: false,
            show_install: true,
            show_close: false,
            install_disabled: true,
            footer_center: true
        });

        var installBtn = _suEls().install;
        if (installBtn) installBtn.textContent = _ru.simulate ? 'Dry-run…' : 'Installing…';

        // Show immediate feedback before the first poll response arrives.
        try { _suUpdateProgress(_ru.simulate ? 'Dry-run starting' : 'Starting', 1); } catch (e0) {}

        // Polling robustness (same idea as self-update): keep polling across transient errors.
        var _pollFailures = 0;
        var _pollMaxFailures = 10;
        var _pollInFlight = false;
        var _pollWarned = false;
        var _lastPct = 0;

        function tick() {
            if (_pollInFlight) return;
            _pollInFlight = true;

            return _api('/api/system/dup/job?job_id=' + encodeURIComponent(job_id), { method: 'GET' }).then(function(j) {
                if (!j) return null;

                if (_pollFailures > 0) {
                    _pollFailures = 0;
                    if (_pollWarned) {
                        toast('Update reconnected', 'Polling resumed', 'ok');
                        _pollWarned = false;
                    }
                }

                _lastPct = parseInt(j.progress || 0, 10) || 0;
                _suUpdateProgress(j.stage || 'Running', _lastPct);
                if (j.output != null) _suSetLog(String(j.output));
                try { znhTaskUpdateFromJob('system-update', j); } catch (e_task_ru2) {}

                if (j.done) {
                    if (_ru.poll_timer) {
                        try { clearTimeout(_ru.poll_timer); } catch (e) {}
                        _ru.poll_timer = null;
                    }
                    _ru.running = false;
                    var rc = (j.rc != null) ? parseInt(j.rc, 10) : -1;

                    var logText = '';
                    try { logText = String(document.getElementById('su-live-log').textContent || ''); } catch (e2) { logText = ''; }

                    if (rc === 0) {
                        // Detect "no updates" case from output so we can exit cleanly.
                        var noUpdates2 = false;
                        try {
                            var lt = String(logText || '').toLowerCase();
                            if (lt.indexOf('nothing to do.') !== -1 || lt.indexOf('[webui] no system updates were applied') !== -1) {
                                noUpdates2 = true;
                            }
                        } catch (e_noup2) { noUpdates2 = false; }

                        toast('Update finished', noUpdates2 ? 'Nothing to do (already up to date)' : (_ru.simulate ? 'Dry-run OK (no install)' : 'Installed OK'), 'ok');
                        _suUpdateProgress(_ru.simulate ? 'Dry-run done' : 'Done', 100);

                        // Record job into Managers history
                        try {
                            if (typeof window.znhJobHistoryAdd === 'function') {
                                var sum2 = noUpdates2
                                    ? 'No system updates were available (Nothing to do).'
                                    : (_ru.simulate ? 'Dry-run OK (no install).' : 'System updates installed successfully.');
                                window.znhJobHistoryAdd({
                                    type: 'system-update',
                                    job_id: String(job_id || ''),
                                    ok: true,
                                    rc: 0,
                                    simulate: !!_ru.simulate,
                                    summary: sum2
                                });
                            }
                        } catch (eJH2) {}

                        // Persistent notification (Rocket manager)
                        try {
                            if (typeof window.znhNotifyAdd === 'function') {
                                var body = noUpdates2
                                    ? 'No system updates were available (Nothing to do).'
                                    : (_ru.simulate ? 'Dry-run finished successfully (no install).' : 'System updates installed successfully.');
                                window.znhNotifyAdd({
                                    id: 'znh_ru_job_done_' + String(job_id || ''),
                                    title: noUpdates2 ? 'System up to date' : (_ru.simulate ? 'System update dry-run complete' : 'System update complete'),
                                    body: body + ' Open to view the log.',
                                    level: 'info',
                                    action: { type: 'open-system-update-job', label: 'Open log', job_id: String(job_id || ''), simulate: !!_ru.simulate }
                                });
                            }
                        } catch (eN) {}

                        // UX: immediately reflect that updates were installed.
                        // The authoritative source is the next dashboard regeneration,
                        // but setting this to 0 avoids confusing "stuck" pending count.
                        if (!_ru.simulate) {
                            try { setText('pending-count', 0); } catch (e_pc) {}
                            try {
                                window.__znh_pending_override = 0;
                                window.__znh_pending_override_until = Date.now() + 60 * 1000;
                            } catch (e_po2) {}

                            // Best-effort: refresh dashboard artifacts so Live mode won't keep showing a stale pending count.
                            try {
                                if (typeof liveEnabled !== 'undefined' && liveEnabled) {
                                    _api('/api/dashboard/refresh', {
                                        method: 'POST',
                                        body: JSON.stringify({ reason: 'rocket-job-finished' })
                                    }).catch(function() {
                                        // ignore
                                    });
                                }
                            } catch (e_sync2) {}
                        }
                        try { znhTaskDone('system-update', true); } catch (e_task_ru3) {}

                        if (noUpdates2) {
                            _ruRenderDone('Up to date', 'No system updates were available (Nothing to do).', logText, '');
                        } else if (_ru.simulate) {
                            _ruRenderDone('Dry-run complete', 'Dry-run finished successfully (no install).', logText, j.restart_check_output || '');
                        } else {
                            _ruRenderDone('Update complete', 'System updates installed successfully.', logText, j.restart_check_output || '');
                        }

                    } else {
                        toast('Update failed', 'rc=' + String(rc), 'err');

                        // Record job into Managers history
                        try {
                            if (typeof window.znhJobHistoryAdd === 'function') {
                                window.znhJobHistoryAdd({
                                    type: 'system-update',
                                    job_id: String(job_id || ''),
                                    ok: false,
                                    rc: rc,
                                    simulate: !!_ru.simulate,
                                    summary: 'System update failed (rc=' + String(rc) + ').'
                                });
                            }
                        } catch (eJH3) {}

                        // Persistent notification (Rocket manager)
                        try {
                            if (typeof window.znhNotifyAdd === 'function') {
                                window.znhNotifyAdd({
                                    id: 'znh_ru_job_done_' + String(job_id || ''),
                                    title: 'System update failed',
                                    body: 'zypper dup returned a non-zero exit code (rc=' + String(rc) + '). Open to view the log.',
                                    level: 'error',
                                    action: { type: 'open-system-update-job', label: 'Open log', job_id: String(job_id || ''), simulate: !!_ru.simulate }
                                });
                            }
                        } catch (eN) {}

                        var cfDet3 = false;
                        var cfSum3 = '';
                        try {
                            cfDet3 = !!(j && j.conflict_detected);
                            cfSum3 = (j && j.conflict_summary != null) ? String(j.conflict_summary) : '';
                        } catch (eCFJ) {
                            cfDet3 = false;
                            cfSum3 = '';
                        }

                        // Local fallback detection (in case API is older or conflict info was missed)
                        if (!cfDet3) {
                            try {
                                var low3 = String(logText || '').toLowerCase();
                                if (low3.indexOf('problem:') !== -1 || low3.indexOf('choose from above solutions') !== -1 || low3.indexOf('solverrun solutions') !== -1) {
                                    cfDet3 = true;
                                }
                            } catch (eCFJ2) {}
                        }

                        var doneOpts = {};
                        if (cfDet3) {
                            doneOpts.conflict_detected = true;
                            doneOpts.conflict_summary = cfSum3;
                            doneOpts.interactive_cmd = 'zypper-run-install';
                        }

                        try { znhTaskDone('system-update', false); } catch (e_task_ru4) {}
                        _ruRenderDone('Update failed', 'zypper dup returned a non-zero exit code (see log).', logText, j.restart_check_output || '', doneOpts);
                    }
                }

                return j;
            }).catch(function(e) {
                _pollFailures++;
                var msg = (e && e.message) ? e.message : 'job poll failed';

                if (!_pollWarned) {
                    _pollWarned = true;
                    toast('Update polling error', msg, 'err');
                }

                _suUpdateProgress('Reconnecting…', _lastPct);
                _suSetLog('ERROR polling job (' + String(_pollFailures) + '/' + String(_pollMaxFailures) + '): ' + msg + '\nRetrying…');

                if (_pollFailures >= _pollMaxFailures) {
                    try {
                        znhWatcherNotifyJobPollingFailed({
                            type: 'system-update',
                            job_id: String(job_id || ''),
                            simulate: !!_ru.simulate
