                    } catch (eW0) {}

                    toast('Update polling failed', 'Too many errors. Please reload the page.', 'err');
                    if (_ru.poll_timer) {
                        try { clearTimeout(_ru.poll_timer); } catch (ee) {}
                        _ru.poll_timer = null;
                    }
                    _ru.running = false;
                    _suSetButtons({
                        show_cancel: false,
                        show_back: false,
                        show_next: false,
                        show_install: false,
                        show_close: true,
                        close_disabled: false,
                        footer_center: true
                    });
                }
                return null;
            }).finally(function() {
                _pollInFlight = false;
