    function rocketUpdateWizardOpen(arg) {
        var opts = {};
        try {
            // If called from a click handler, arg may be a DOM element.
            if (arg && typeof arg === 'object' && arg.nodeType) {
                opts = {};
            } else {
                opts = arg || {};
            }
        } catch (e0) { opts = {}; }

        var autoSim = false;
        var autoSimSpecified = false;
        try {
            if (opts && typeof opts === 'object') {
                if (Object.prototype.hasOwnProperty.call(opts, 'auto_simulate')) {
                    autoSimSpecified = true;
                    autoSim = !!opts.auto_simulate;
                } else if (Object.prototype.hasOwnProperty.call(opts, 'auto_dry_run')) {
                    autoSimSpecified = true;
                    autoSim = !!opts.auto_dry_run;
                } else if (Object.prototype.hasOwnProperty.call(opts, 'simulate')) {
                    autoSimSpecified = true;
                    autoSim = !!opts.simulate;
                } else if (Object.prototype.hasOwnProperty.call(opts, 'dry_run')) {
                    autoSimSpecified = true;
                    autoSim = !!opts.dry_run;
                }
            }
        } catch (e1) {
            autoSim = false;
            autoSimSpecified = false;
        }

        // Default (pre-selected) behavior: pull from settings only when caller did not specify.
        if (!autoSimSpecified) {
            try {
                autoSim = String((_settingsConfig || {}).ROCKET_WIZARD_DEFAULT_SIMULATE || '').toLowerCase() === 'true';
            } catch (e2) { autoSim = false; }
        }

        // Ensure any self-update timers are stopped so flows don't fight.
        try { _suReset(); } catch (e) {}
        _ruReset();
        _ru.auto_simulate = autoSim;

        _suShow(true);
        _ruSetHeader('Preview', 'Step 1/3', autoSim ? 'Simulate system updates (dry-run)' : 'Install system updates');

        // Fetch preview output.
        var e = _suEls();
        if (e.body) {
            e.body.innerHTML = '<div style="color: var(--muted); font-weight:900;">Loading preview (zypper dup --dry-run --details)…</div>';
        }

        _suSetButtons({
            show_cancel: true,
            show_back: false,
            show_next: false,
            show_install: false,
            show_close: false,
            footer_center: false
        });

        _api('/api/system/dup/preview', { method: 'GET' }).then(function(r) {
            _ruRenderPreview(r || {});
        }).catch(function(err) {
            // If server returned JSON (rc/output), surface it instead of hiding it behind HTTP 500.
            try {
                if (err && err.payload && (err.payload.output != null || err.payload.rc != null)) {
                    _ruRenderPreview(err.payload || {});
                    return;
                }
            } catch (e0) {}

            var msg = (err && err.message) ? err.message : 'preview failed';
            _ruRenderPreview({ rc: 1, output: 'ERROR: ' + msg, cmd: '' });
        });

        // Wire overlay buttons for this flow.
        if (e.cancel) e.cancel.onclick = function(ev) {
            if (_ru.running) return;
            try { if (ev) { ev.preventDefault(); ev.stopPropagation(); } } catch (e0) {}
            try { if (typeof window.znhJsHealthLog === 'function') window.znhJsHealthLog('debug', 'rocket overlay cancel clicked'); } catch (e1) {}
            _suShow(false);
        };
        if (e.back) e.back.onclick = function() {
            if (_ru.running) return;
            _ruRenderPreview(_ru.last_preview || {});
        };
        if (e.next) e.next.onclick = function() {
            if (!_ru.accepted || _ru.running) return;
            toast('Preparing install…', 'Requesting confirmation token', 'ok');
            _api('/api/system/dup/confirm', { method: 'POST', body: JSON.stringify({}) }).then(function(r) {
                _ruRenderConfirm(r || {});
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'confirm failed';
                toast('Confirm failed', msg, 'err');
            });
        };
        if (e.install) e.install.onclick = function() {
            if (_ru.running) return;
            var phraseInp = document.getElementById('ru-phrase');
            var got = '';
            try { got = String((phraseInp && phraseInp.value) ? phraseInp.value : '').trim(); } catch (ee) { got = ''; }

            var confirmToken = (_ru.confirm && _ru.confirm.confirm_token) ? String(_ru.confirm.confirm_token) : '';
            if (!confirmToken) {
                toast('Error', 'Missing confirm token (go back and try again)', 'err');
                return;
            }

            toast('Update starting…', _ru.simulate ? 'Simulation (dry-run only)' : 'Installing updates', 'ok');

            _api('/api/system/dup/start', {
                method: 'POST',
                body: JSON.stringify({
                    confirm_token: confirmToken,
                    confirm_phrase: got,
                    simulate: !!_ru.simulate
                })
            }).then(function(res) {
                if (!res || !res.job_id) throw new Error('missing job_id');
                _ruPollJob(String(res.job_id));
                return res;
            }).catch(function(err) {
                var msg = (err && err.message) ? err.message : 'failed';
                toast('Update start failed', msg, 'err');
            });
        };
    }

    function _renderSettingsForm(schema, cfg) {
        var form = document.getElementById('settings-form');
        if (!form) return;
        form.innerHTML = '';
        _settingsSetDirty(false);
        // Keep a copy so we can log diffs on save/autosave.
        try { _settingsLastConfig = JSON.parse(JSON.stringify(cfg || {})); } catch (e) { _settingsLastConfig = cfg || {}; }

        // Safety UX:
        // - Advanced settings are hidden by default.
        // - Advanced settings require a confirmation phrase to show (prevents accidental enable).
        // - Danger settings are disabled until explicitly unlocked (and are never persisted unlocked).
        var showAdvanced = false;
        try { showAdvanced = (localStorage.getItem('znh_settings_show_advanced') || '') === '1'; } catch (e) { showAdvanced = false; }

        // Advanced unlock is intentionally NOT persisted for safety.
        // Even if the user toggles "show advanced", they must re-unlock per page load.
        var advancedUnlocked = false;
        var dangerUnlocked = false; // never persisted for safety
        try { window.__znh_settings_danger_unlocked = false; } catch (e) {}
        try { window.__znh_settings_advanced_unlocked = false; } catch (e2) {}

        var advRows = [];
        var dangerRows = [];
        var dangerControls = [];

        function _applyAdvancedVisibility() {
            var advVisible = !!(showAdvanced && advancedUnlocked);
            (advRows || []).forEach(function(r) {
                if (!r) return;
                r.style.display = advVisible ? 'grid' : 'none';
            });
        }

        function _applyDangerLock() {
            var unlocked = !!(dangerUnlocked && advancedUnlocked);
            (dangerControls || []).forEach(function(el) {
                if (!el) return;
                try { el.disabled = !unlocked; } catch (e) {}
            });
            (dangerRows || []).forEach(function(r) {
                if (!r) return;
                try { r.style.opacity = unlocked ? '1' : '0.75'; } catch (e) {}
            });
            try { window.__znh_settings_danger_unlocked = unlocked; } catch (e) {}
        }

        function _dangerPhraseForField(f) {
            try {
                if (f && f.danger_phrase) return String(f.danger_phrase || '').trim();
                if (f && f.key) return 'DANGER-' + String(f.key);
            } catch (e) {}
            return 'DANGER';
        }

        function _dangerConfirmChange(f) {
            var req = '';
            try { req = _dangerPhraseForField(f); } catch (e) { req = 'DANGER'; }
            req = String(req || 'DANGER').trim().toUpperCase();

            var msg = 'Danger setting change: ' + String((f && f.key) ? f.key : '') + '\n\n' +
                      'Type ' + req + ' to confirm.';

            // Use a blocking prompt on purpose (hard mode).
            // If the user cancels or types wrong, we revert.
            var got = '';
            try { got = String(prompt(msg, '') || ''); } catch (e2) { got = ''; }
            got = String(got || '').trim().toUpperCase();
            return got === req;
        }

        // Gate controls (always rendered at the top)
        (function() {
            var gate = document.createElement('div');
            gate.style.border = '1px solid var(--border)';
            gate.style.borderRadius = '12px';
            gate.style.padding = '10px 12px';
            gate.style.background = 'rgba(255,255,255,0.03)';
            gate.style.marginBottom = '12px';

            var row1 = document.createElement('div');
            row1.style.display = 'flex';
            row1.style.gap = '10px';
            row1.style.flexWrap = 'wrap';
            row1.style.alignItems = 'center';

            var advLab = document.createElement('label');
            advLab.className = 'pill';
            advLab.style.gap = '10px';
            advLab.style.justifyContent = 'flex-start';
            var advCb = document.createElement('input');
            advCb.type = 'checkbox';
            try { advCb.checked = !!showAdvanced; } catch (e) {}
            advLab.appendChild(advCb);
            advLab.appendChild(document.createTextNode('Show advanced settings'));

            var dangLab = document.createElement('label');
            dangLab.className = 'pill';
            dangLab.style.gap = '10px';
            dangLab.style.justifyContent = 'flex-start';
            dangLab.style.borderColor = 'rgba(239,68,68,0.35)';
            dangLab.style.background = 'rgba(239,68,68,0.08)';
            var dangCb = document.createElement('input');
            dangCb.type = 'checkbox';
            try { dangCb.checked = false; } catch (e) {}
            dangLab.appendChild(dangCb);
            dangLab.appendChild(document.createTextNode('Unlock danger zone (temporary)'));

            row1.appendChild(advLab);
            row1.appendChild(dangLab);

            // Advanced unlock: requires typing a phrase.
            var row2 = document.createElement('div');
            row2.style.display = 'grid';
            row2.style.gridTemplateColumns = 'minmax(180px, 1fr) minmax(180px, 1fr)';
            row2.style.gap = '10px';
            row2.style.alignItems = 'center';
            row2.style.marginTop = '10px';

            var unlockInfo = document.createElement('div');
            unlockInfo.innerHTML = '<div style="font-weight:900;">Advanced unlock</div>' +
                                   '<div style="color:var(--muted); font-size:0.86rem;">Type <code>ADVANCED</code> to reveal advanced options (per page load).</div>';

            var unlockWrap = document.createElement('div');
            unlockWrap.style.display = 'grid';
            unlockWrap.style.gridTemplateColumns = '1fr auto';
            unlockWrap.style.gap = '10px';
            unlockWrap.style.alignItems = 'center';

            var unlockInp = document.createElement('input');
            unlockInp.type = 'text';
            unlockInp.placeholder = 'Type ADVANCED…';
            unlockInp.style.width = '100%';
            unlockInp.style.padding = '10px 12px';
            unlockInp.style.borderRadius = '12px';
            unlockInp.style.border = '1px solid var(--border)';
            unlockInp.style.background = 'rgba(255,255,255,0.04)';
            unlockInp.style.color = 'var(--text)';

            var unlockBtn = document.createElement('button');
            unlockBtn.type = 'button';
            unlockBtn.className = 'pill';
            unlockBtn.textContent = 'Unlock';

            unlockWrap.appendChild(unlockInp);
            unlockWrap.appendChild(unlockBtn);
            row2.appendChild(unlockInfo);
            row2.appendChild(unlockWrap);

            var hint = document.createElement('div');
            hint.style.color = 'var(--muted)';
            hint.style.fontSize = '0.86rem';
            hint.style.marginTop = '8px';
            hint.textContent = 'Tip: defaults are safe. Advanced options are hidden to reduce accidental breakage.';

            gate.appendChild(row1);
            gate.appendChild(row2);
            gate.appendChild(hint);
            form.appendChild(gate);

            function updateGateUi() {
                // Only show the unlock row when "show advanced" is checked.
                try { row2.style.display = showAdvanced ? 'grid' : 'none'; } catch (e) {}

                // Danger zone is only meaningful when advanced is actually visible.
                try { dangCb.disabled = !(showAdvanced && advancedUnlocked); } catch (e) {}
                if (!(showAdvanced && advancedUnlocked)) {
                    dangerUnlocked = false;
                    try { dangCb.checked = false; } catch (e) {}
                }

                // Expose advanced unlock state globally so other parts of the UI can
                // show extra technical details only when explicitly unlocked.
                try { window.__znh_settings_advanced_unlocked = !!(showAdvanced && advancedUnlocked); } catch (e0) {}

                _applyAdvancedVisibility();
                _applyDangerLock();

                // Best-effort: refresh any advanced-only status helpers (e.g., self-update tech line).
                try { _selfUpdateUiApplyLocks(); } catch (e1) {}
            }

            function tryUnlockAdvanced() {
                var phrase = '';
                try { phrase = String(unlockInp.value || '').trim().toUpperCase(); } catch (e) { phrase = ''; }
                if (phrase === 'ADVANCED') {
                    advancedUnlocked = true;
                    toast('Advanced unlocked', 'Advanced settings are now visible for this page load.', 'ok');
                } else {
                    advancedUnlocked = false;
                    toast('Advanced unlock failed', 'Type ADVANCED exactly.', 'err');
                }
                updateGateUi();
            }

            advCb.addEventListener('change', function() {
                showAdvanced = !!advCb.checked;
                try { localStorage.setItem('znh_settings_show_advanced', showAdvanced ? '1' : '0'); } catch (e) {}

                // Lock everything again when toggling off.
                if (!showAdvanced) {
                    advancedUnlocked = false;
                    dangerUnlocked = false;
                    try { dangCb.checked = false; } catch (e) {}
                    try { unlockInp.value = ''; } catch (e) {}
                }

                updateGateUi();
            });

            if (unlockBtn) unlockBtn.addEventListener('click', function() { tryUnlockAdvanced(); });
            if (unlockInp) unlockInp.addEventListener('keydown', function(ev) {
                if (!ev) return;
                if (ev.key === 'Enter') {
                    try { ev.preventDefault(); } catch (e) {}
                    tryUnlockAdvanced();
                }
            });

            dangCb.addEventListener('change', function() {
                dangerUnlocked = !!dangCb.checked;
                updateGateUi();
            });

            // Initial render
            updateGateUi();
        })();

        SETTINGS_FIELDS.forEach(function(f) {
            if (!schema || !schema[f.key]) return;
            var meta = schema[f.key];
            var row = document.createElement('div');
            row.className = 'znh-settings-row';
            row.style.display = 'grid';
            row.style.gridTemplateColumns = 'minmax(180px, 1fr) minmax(180px, 1fr)';
            row.style.gap = '10px';
            row.style.alignItems = 'center';
            row.style.padding = '10px 12px';
            row.style.border = '1px solid var(--border)';
            row.style.borderRadius = '12px';
            row.style.background = 'var(--subtle)';

            if (f.advanced || f.danger) {
                try { row.classList.add('znh-advanced'); } catch (e) {}
                advRows.push(row);
            }
            if (f.danger) {
                try { row.classList.add('znh-danger'); } catch (e) {}
                try { row.style.borderColor = 'rgba(239,68,68,0.35)'; } catch (e) {}
                dangerRows.push(row);
            }

            var lab = document.createElement('div');
            var helpHtml = '';
            if (f.help) {
                helpHtml = '<div style="color:var(--muted); font-size:0.82rem; margin-top:4px;">' + String(f.help).replace(/</g, '&lt;') + '</div>';
            }
            lab.innerHTML = '<div style="font-weight:950;">' + f.label + '</div>' +
                            '<div style="color:var(--muted); font-size:0.82rem;">' + f.key + '</div>' +
                            helpHtml;

            var ctrlWrap = document.createElement('div');

            if (meta.type === 'bool') {
                var c = document.createElement('label');
                c.className = 'pill';
                c.style.gap = '10px';
                var inp = document.createElement('input');
                inp.type = 'checkbox';
                inp.dataset.key = f.key;
                inp.checked = String(cfg[f.key]).toLowerCase() === 'true';
                inp.dataset.prev = inp.checked ? '1' : '0';
                if (f.danger) {
                    try { inp.disabled = true; } catch (e) {}
                    dangerControls.push(inp);
                }
                c.appendChild(inp);
                var txtNode = document.createTextNode(inp.checked ? 'ON' : 'OFF');
                c.appendChild(txtNode);
                inp.addEventListener('change', function() {
                    var prev = String(inp.dataset.prev || (inp.checked ? '1' : '0'));
                    var now = inp.checked ? '1' : '0';

                    if (f.danger && prev !== now) {
                        // Hard mode: require per-setting phrase confirmation on EVERY change.
                        if (!_dangerConfirmChange(f)) {
                            // revert
                            inp.checked = (prev === '1');
                            now = prev;
                            toast('Danger change blocked', 'Confirmation phrase mismatch.', 'err');
                            txtNode.nodeValue = inp.checked ? 'ON' : 'OFF';
                            return;
                        }
                        toast('Danger change confirmed', f.key, 'ok');
                    }

                    inp.dataset.prev = now;
                    txtNode.nodeValue = inp.checked ? 'ON' : 'OFF';
                    _settingsMarkDirty();
                });
                ctrlWrap.appendChild(c);
            } else if (meta.type === 'enum' || meta.type === 'interval') {
                var sel = document.createElement('select');
                sel.dataset.key = f.key;
                sel.style.width = '100%';
                sel.style.padding = '10px 12px';
                sel.style.borderRadius = '12px';
                sel.style.border = '1px solid var(--border)';
                sel.style.background = 'rgba(255,255,255,0.04)';
                sel.style.color = 'var(--text)';
                (meta.allowed || []).forEach(function(opt) {
                    var o = document.createElement('option');
                    o.value = opt;
                    o.textContent = opt;
                    sel.appendChild(o);
                });
                sel.value = String(cfg[f.key]);
                if (f.danger) {
                    try { sel.disabled = true; } catch (e) {}
                    dangerControls.push(sel);
                }
                sel.addEventListener('change', function() { _settingsMarkDirty(); });
                ctrlWrap.appendChild(sel);
            } else if (meta.type === 'int') {
                // Prefer predefined select options when a bounded range is provided
                var mn = (meta.min != null) ? parseInt(meta.min, 10) : 0;
                var mx = (meta.max != null) ? parseInt(meta.max, 10) : null;
                var st = (meta.step != null) ? parseInt(meta.step, 10) : 1;

                if (mx != null && isFinite(mx) && st > 0 && (mx - mn) / st <= 400) {
                    var sel2 = document.createElement('select');
                    sel2.dataset.key = f.key;
                    sel2.style.width = '100%';
                    sel2.style.padding = '10px 12px';
                    sel2.style.borderRadius = '12px';
                    sel2.style.border = '1px solid var(--border)';
                    sel2.style.background = 'rgba(255,255,255,0.04)';
                    sel2.style.color = 'var(--text)';
                    for (var i = mn; i <= mx; i += st) {
                        var o2 = document.createElement('option');
                        o2.value = String(i);
                        o2.textContent = String(i);
                        sel2.appendChild(o2);
                    }
                    sel2.value = String(cfg[f.key]);
                    if (f.danger) {
                        try { sel2.disabled = true; } catch (e) {}
                        dangerControls.push(sel2);
                    }
                    sel2.addEventListener('change', function() { _settingsMarkDirty(); });
                    ctrlWrap.appendChild(sel2);
                } else {
                    // fallback (should be rare): still allow manual number entry
                    var num = document.createElement('input');
                    num.type = 'number';
                    num.min = String(mn);
                    if (mx != null && isFinite(mx)) num.max = String(mx);
                    num.step = String(st);
                    num.dataset.key = f.key;
                    num.value = String(cfg[f.key]);
                    if (f.danger) {
                        try { num.disabled = true; } catch (e) {}
                        dangerControls.push(num);
                    }
                    num.addEventListener('input', function() { _settingsMarkDirty(); });
                    num.style.width = '100%';
                    num.style.padding = '10px 12px';
                    num.style.borderRadius = '12px';
                    num.style.border = '1px solid var(--border)';
                    num.style.background = 'rgba(255,255,255,0.04)';
                    num.style.color = 'var(--text)';
                    ctrlWrap.appendChild(num);
                }
            } else if (meta.type === 'string') {
                var presets = meta.presets || null;
                var cur = String(cfg[f.key] || '');

                if (presets && Array.isArray(presets) && presets.length > 0) {
                    var sel3 = document.createElement('select');
                    sel3.dataset.key = f.key;
                    sel3.style.width = '100%';
                    sel3.style.padding = '10px 12px';
                    sel3.style.borderRadius = '12px';
                    sel3.style.border = '1px solid var(--border)';
                    sel3.style.background = 'rgba(255,255,255,0.04)';
                    sel3.style.color = 'var(--text)';

                    (presets || []).forEach(function(p) {
                        var o3 = document.createElement('option');
                        o3.value = String(p);
                        o3.textContent = String(p);
                        sel3.appendChild(o3);
                    });
                    var oc = document.createElement('option');
                    oc.value = '__custom__';
                    oc.textContent = 'Custom...';
                    sel3.appendChild(oc);

                    var txt = document.createElement('input');
                    txt.type = 'text';
                    txt.dataset.customFor = f.key;
                    txt.value = cur;
                    txt.placeholder = (meta.default != null) ? String(meta.default) : '';
                    txt.style.display = 'none';
                    txt.style.marginTop = '8px';
                    txt.style.width = '100%';
                    txt.style.padding = '10px 12px';
                    txt.style.borderRadius = '12px';
                    txt.style.border = '1px solid var(--border)';
                    txt.style.background = 'rgba(255,255,255,0.04)';
                    txt.style.color = 'var(--text)';

                    if (presets.indexOf(cur) >= 0) {
                        sel3.value = cur;
                        txt.style.display = 'none';
                    } else {
                        sel3.value = '__custom__';
                        txt.style.display = 'block';
                    }

                    sel3.addEventListener('change', function() {
                        if (sel3.value === '__custom__') {
                            txt.style.display = 'block';
                        } else {
                            txt.style.display = 'none';
                            txt.value = sel3.value;
                        }
                        _settingsMarkDirty();
                    });
                    txt.addEventListener('input', function() { _settingsMarkDirty(); });

                    ctrlWrap.appendChild(sel3);
                    ctrlWrap.appendChild(txt);
                } else {
                    var txt2 = document.createElement('input');
                    txt2.type = 'text';
                    txt2.dataset.key = f.key;
                    txt2.value = cur;
                    txt2.placeholder = (meta.default != null) ? String(meta.default) : '';
                    txt2.addEventListener('input', function() { _settingsMarkDirty(); });
                    txt2.style.width = '100%';
                    txt2.style.padding = '10px 12px';
                    txt2.style.borderRadius = '12px';
                    txt2.style.border = '1px solid var(--border)';
                    txt2.style.background = 'rgba(255,255,255,0.04)';
                    txt2.style.color = 'var(--text)';
                    ctrlWrap.appendChild(txt2);
                }
            }

            row.appendChild(lab);
            row.appendChild(ctrlWrap);
            form.appendChild(row);
        });

        // Apply initial gate state
        _applyAdvancedVisibility();
        _applyDangerLock();
    }

    function _collectSettingsPatch(schema) {
        var form = document.getElementById('settings-form');
        if (!form) return {};
        var patch = {};
        var inputs = form.querySelectorAll('[data-key]');
        inputs.forEach(function(el) {
            var k = el.dataset.key;
            if (!schema || !schema[k]) return;

            // Safety UX: do not persist hidden advanced settings or locked danger settings.
            try {
                var row = el.closest ? el.closest('.znh-settings-row') : null;
                if (row && row.style && row.style.display === 'none') {
                    return;
                }
                if (row && row.classList && row.classList.contains('znh-danger')) {
                    if (!window.__znh_settings_danger_unlocked) {
                        return;
                    }
                }
            } catch (e) {}

            if (el.tagName.toLowerCase() === 'input' && el.type === 'checkbox') {
                patch[k] = el.checked ? 'true' : 'false';
            } else if (el.tagName.toLowerCase() === 'select') {
                if (el.value === '__custom__') {
                    var c = form.querySelector('[data-custom-for="' + k + '"]');
                    patch[k] = c ? String(c.value || '') : '';
                } else {
                    patch[k] = el.value;
                }
            } else if (el.tagName.toLowerCase() === 'input' && el.type === 'number') {
                patch[k] = el.value;
            } else if (el.tagName.toLowerCase() === 'input' && el.type === 'text') {
                // ignore custom companion inputs; read via select '__custom__'
                if (el.dataset.customFor) return;
                patch[k] = el.value;
            }
        });
        return patch;
    }

    function settingsLoad(showToast) {
        _settingsBanner('', false);
        return _api('/api/schema', { method: 'GET' }).then(function(s) {
            _settingsSchema = s.schema;
            return _api('/api/config', { method: 'GET' });
        }).then(function(c) {
            _settingsConfig = c.config
            try { znhDebugApplyFromConfig(_settingsConfig); } catch (eD) {}
            try { znhDebugUpdateToggleUi(); } catch (eDU) {}
            _renderSettingsForm(_settingsSchema, _settingsConfig)
            try { if (typeof znhKernelPurgeRefreshUI === 'function') znhKernelPurgeRefreshUI(); } catch (eKP) {}
            try { if (typeof znhBootStatsRefreshUI === 'function') znhBootStatsRefreshUI(false); } catch (eBS) {}
            try { selfUpdateRender(); } catch (e) {}
            try { selfUpdatePostSuccessInit(); } catch (e) {}
            try { selfUpdateAutoQueryInit(); } catch (e) {}
            try { rocketUpdateAutoQueryInit(); } catch (e) {}
            try { znhTaskResumeInit(); } catch (e) {}

            var inv = (c.invalid_keys || []);
            var warn = (c.warnings || []);
            if (inv.length > 0) {
                _settingsBanner('Config had invalid values: ' + inv.join(', ') + ' (defaults applied). You can Factory reset or Save to heal.', true);
            } else if (warn.length > 0) {
                _settingsBanner('Warnings: ' + warn.slice(0, 3).join(' | '), true);
            } else {
                _settingsBanner('Config OK', false);
            }

            if (showToast) {
                toast('Settings loaded', 'Read from /etc/zypper-auto.conf', 'ok');
            }
            _settingsClientLog('info', 'settingsLoad ok', { invalid_keys: inv, warnings: warn });
            return c;
        }).catch(function(e) {
            _settingsBanner('Settings API not reachable. Try re-opening dashboard so it can start the API (sudo may prompt).', true);
            if (showToast) {
                toast('Settings load failed', (e && e.message) ? e.message : 'API not reachable', 'err');
            }
            try { console && console.warn && console.warn('settingsLoad failed', e); } catch (ee) {}
            try { znhDebugUpdateToggleUi(); } catch (eDU) {}
            try { if (typeof znhKernelPurgeRefreshUI === 'function') znhKernelPurgeRefreshUI(); } catch (eKP) {}
            // Can't log via API if the API is unreachable.
            return null;
        });
    }

    function _diffForKeys(oldCfg, newCfg, keys) {
        var out = {};
        (keys || []).forEach(function(k) {
            var a = (oldCfg && oldCfg[k] != null) ? String(oldCfg[k]) : '';
            var b = (newCfg && newCfg[k] != null) ? String(newCfg[k]) : '';
            if (a !== b) out[k] = { from: a, to: b };
        });
        return out;
    }

    function settingsSave() {
        if (!_settingsSchema) return settingsLoad(true);
        if (_settingsResetInProgress) return settingsLoad(true);
        var patch = _collectSettingsPatch(_settingsSchema);
        var keys = Object.keys(patch || {});
        var p = _api('/api/config', { method: 'POST', body: JSON.stringify({ patch: patch }) }).then(function(r) {
            toast('Settings saved', 'Applied to /etc/zypper-auto.conf', 'ok');

            var changed = _diffForKeys(_settingsLastConfig || _settingsConfig || {}, (r && r.config) ? r.config : {}, keys);
            _settingsClientLog('info', 'settingsSave ok', {
                keys: keys,
                changed: changed,
                invalid_keys: (r && r.invalid_keys) ? r.invalid_keys : [],
                warnings: (r && r.warnings) ? r.warnings.slice(0, 6) : []
            });

            _settingsSetDirty(false);
            return settingsLoad(false);
        }).catch(function(e) {
            try { console && console.warn && console.warn('settingsSave failed', e); } catch (ee) {}
            toast('Save failed', (e && e.message) ? e.message : 'unknown error', 'err');
            _settingsClientLog('warn', 'settingsSave failed', { error: (e && e.message) ? e.message : 'unknown' });
            _settingsBanner('Save failed. You can click Factory reset to restore safe defaults.', true);
            return settingsLoad(false);
        }).finally(function() {
            try { _settingsAutosavePromise = null; } catch (e) {}
        });

        _settingsAutosavePromise = p;
        return p;
    }

    function settingsAutoSave() {
        if (!SETTINGS_AUTOSAVE_ENABLED) return;
        if (_settingsResetInProgress) return;
        if (_settingsAutosaveInFlight) return;
        if (!_settingsDirty) return;
        if (!_settingsSchema) {
            // Try to load schema/config first, then autosave.
            return settingsLoad(false).then(function() {
                if (_settingsDirty) return settingsAutoSave();
                return null;
            });
        }

        _settingsAutosaveInFlight = true;
        var patch = _collectSettingsPatch(_settingsSchema);
        var keys = Object.keys(patch || {});
        var p = _api('/api/config', { method: 'POST', body: JSON.stringify({ patch: patch }) }).then(function(r) {
            toast('Settings auto-saved', 'Applied to /etc/zypper-auto.conf', 'ok');

            var changed = _diffForKeys(_settingsLastConfig || _settingsConfig || {}, (r && r.config) ? r.config : {}, keys);
            _settingsClientLog('debug', 'settingsAutoSave ok', {
                keys: keys,
                changed: changed,
                invalid_keys: (r && r.invalid_keys) ? r.invalid_keys : [],
                warnings: (r && r.warnings) ? r.warnings.slice(0, 6) : []
            });

            _settingsSetDirty(false);
            return settingsLoad(false);
        }).catch(function(e) {
            try { console && console.warn && console.warn('settingsAutoSave failed', e); } catch (ee) {}
            toast('Auto-save failed', (e && e.message) ? e.message : 'unknown error', 'err');
            _settingsClientLog('warn', 'settingsAutoSave failed', { error: (e && e.message) ? e.message : 'unknown' });
            _settingsBanner('Auto-save failed (API may be restarting). Try again or click Factory reset to restore safe defaults.', true);
            // Keep dirty so user can retry (or click Save/Reset).
            _settingsSetDirty(true);
            return null;
        }).finally(function() {
            _settingsAutosaveInFlight = false;
            _settingsAutosavePendingToast = false;
            try { _settingsAutosavePromise = null; } catch (e) {}
        });

        _settingsAutosavePromise = p;
        return p;
    }

    function settingsReset() {
        if (_settingsResetInProgress) return Promise.resolve(null);

        // IMPORTANT: if auto-save (or Save) is in-flight, wait for it to finish first.
        // Otherwise it can race AFTER reset and re-apply old values.
        var wait = _settingsAutosavePromise;

        function _disableInputs(disabled) {
            try {
                var form = document.getElementById('settings-form');
                if (form) {
                    var els = form.querySelectorAll('input,select,button,textarea');
                    els.forEach(function(el) { try { el.disabled = !!disabled; } catch (e) {} });
                }
                var saveBtn = document.getElementById('settings-save');
                var reloadBtn = document.getElementById('settings-reload');
                var resetBtn = document.getElementById('settings-reset');
                if (saveBtn) saveBtn.disabled = !!disabled;
                if (reloadBtn) reloadBtn.disabled = !!disabled;
                if (resetBtn) resetBtn.disabled = !!disabled;
            } catch (e0) {}
        }

        function doResetNow() {
            _settingsResetInProgress = true;

            // Snapshot current config for diff logging (avoid confusion if reset “does nothing”).
            var beforeCfg = null;
            try { beforeCfg = JSON.parse(JSON.stringify(_settingsConfig || {})); } catch (eBC) { beforeCfg = _settingsConfig || {}; }

            // Cancel any pending autosave timer.
            try {
                if (_settingsAutosaveTimer) {
                    clearTimeout(_settingsAutosaveTimer);
                    _settingsAutosaveTimer = null;
                }
            } catch (eT) {}

            // Disable autosave during reset.
            var prevAutosave = SETTINGS_AUTOSAVE_ENABLED;
            SETTINGS_AUTOSAVE_ENABLED = false;
            _settingsAutosavePendingToast = false;

            _disableInputs(true);

            return _api('/api/reset-config', { method: 'POST', body: JSON.stringify({}) }).then(function(r) {
                toast('Factory reset complete', 'Defaults restored (backup created)', 'ok');
                _settingsSetDirty(false);

                // Optional: re-lock advanced/danger zone after reset (safer default).
                try { window.__znh_settings_advanced_unlocked = false; } catch (eA) {}
                try { window.__znh_settings_danger_unlocked = false; } catch (eD) {}

                // Apply response config immediately (don’t depend on a follow-up /api/config GET,
                // which can be stale if the browser caches or the backend is restarting).
                try {
                    if (r && r.config) {
                        _settingsConfig = r.config;
                        try { znhDebugApplyFromConfig(_settingsConfig); } catch (eD2) {}
                        try { znhDebugUpdateToggleUi(); } catch (eDU2) {}
                        try { if (_settingsSchema) _renderSettingsForm(_settingsSchema, _settingsConfig); } catch (eRF) {}
                        try { if (typeof znhKernelPurgeRefreshUI === 'function') znhKernelPurgeRefreshUI(); } catch (eKP0) {}
                        try { if (typeof znhBootStatsRefreshUI === 'function') znhBootStatsRefreshUI(false); } catch (eBS0) {}

                        // Lightweight diff log for key safety toggles.
                        try {
                            var changed = _diffForKeys(beforeCfg || {}, _settingsConfig || {}, ['KERNEL_PURGE_ENABLED']);
                            _settingsClientLog('info', 'settingsReset applied', {
                                changed: changed,
                                invalid_keys: (r && r.invalid_keys) ? r.invalid_keys : [],
                                warnings: (r && r.warnings) ? r.warnings.slice(0, 6) : []
                            });
                        } catch (eLog) {}
                    }
                } catch (eApply) {}

                // Background refresh: verify backend sees the same config.
                // Do NOT block UI on this.
                try {
                    setTimeout(function() {
                        try {
                            settingsLoad(false).then(function(c2) {
                                try {
                                    if (c2 && c2.config) {
                                        var mismatch = _diffForKeys(_settingsConfig || {}, c2.config || {}, ['KERNEL_PURGE_ENABLED']);
                                        if (mismatch && mismatch.KERNEL_PURGE_ENABLED) {
                                            _settingsClientLog('warn', 'settingsReset verify mismatch', { mismatch: mismatch });
                                            _settingsBanner('Reset applied, but API still reports different values (may be caching). Re-open Settings drawer in ~2s.', true);
                                        }
                                    }
                                } catch (eV2) {}
                            });
                        } catch (eV) {}
                    }, 900);
                } catch (eST) {}

                return r;
            }).catch(function(e) {
                var msg = (e && e.message) ? e.message : 'unknown error';
                toast('Factory reset failed', msg + ' (try: zypper-auto-helper --reset-config)', 'err');
                return settingsLoad(false);
            }).finally(function() {
                SETTINGS_AUTOSAVE_ENABLED = prevAutosave;
                _settingsResetInProgress = false;
                _disableInputs(false);
                try { _settingsAutosavePromise = null; } catch (eP) {}
            });
        }

        if (wait && typeof wait.then === 'function') {
            return wait.then(function() { return doResetNow(); }, function() { return doResetNow(); });
        }
        return doResetNow();
    }

    function _wireSettingsUI() {
        var drawer = document.getElementById('settings-drawer');
        if (!drawer) return;

        var saveBtn = document.getElementById('settings-save');
        var reloadBtn = document.getElementById('settings-reload');
        var resetBtn = document.getElementById('settings-reset');

        if (saveBtn) saveBtn.addEventListener('click', function() { settingsSave(); });
        if (reloadBtn) reloadBtn.addEventListener('click', function() { settingsLoad(true); });

        function _settingsPassiveRefresh(reason) {
            // Goal: keep small status indicators (like Kernel purge badge) in sync even
            // when config changes happen outside the WebUI (e.g. user runs --reset-config).
            // Safety: never clobber user edits.
            try {
                if (_settingsResetInProgress || _settingsAutosaveInFlight) return Promise.resolve(null);
                if (_settingsDirty) return Promise.resolve(null);
            } catch (e0) {
                return Promise.resolve(null);
            }

            // If schema isn't loaded yet, do a full settingsLoad (schema+config).
            if (!_settingsSchema) {
                try { return settingsLoad(false); } catch (e1) { return Promise.resolve(null); }
            }

            return _api('/api/config', { method: 'GET' }).then(function(c) {
                try {
                    if (c && c.config) {
                        _settingsConfig = c.config;
                        try { znhDebugApplyFromConfig(_settingsConfig); } catch (eD) {}
                        try { znhDebugUpdateToggleUi(); } catch (eDU) {}

                        // Only re-render the full form when the drawer is actually open.
                        try {
                            if (drawer && drawer.open) {
                                _renderSettingsForm(_settingsSchema, _settingsConfig);
                            }
                        } catch (eR) {}

                        try { if (typeof znhKernelPurgeRefreshUI === 'function') znhKernelPurgeRefreshUI(); } catch (eKP) {}
                        try { if (typeof znhBootStatsRefreshUI === 'function') znhBootStatsRefreshUI(false); } catch (eBS) {}
                    }
                } catch (e2) {}
                return c;
            }).catch(function(_e) {
                // If API is down, avoid spamming warnings.
                return null;
            });
        }

        // Auto-load on page open so users immediately see success/failure.
        // (Drawer toggle handler below still refreshes when opened.)
        try {
            settingsLoad(true);
        } catch (e) {}

        // Passive refresh when user returns to the tab/window.
        // This fixes the "UI still shows old value after CLI reset" confusion.
        try {
            window.addEventListener('focus', function() {
                try { _settingsPassiveRefresh('focus'); } catch (e) {}
            });
        } catch (eF) {}
        try {
            document.addEventListener('visibilitychange', function() {
                try {
                    if (document.visibilityState === 'visible') {
                        _settingsPassiveRefresh('visible');
                    }
                } catch (e) {}
            });
        } catch (eV) {}

        if (resetBtn) resetBtn.addEventListener('click', function() {
            if (confirm('Factory reset /etc/zypper-auto.conf to defaults?\n\nThis runs: zypper-auto-helper --reset-config\n\n(A backup will be created)')) {
                settingsReset();
            }
        });

        drawer.addEventListener('toggle', function() {
            if (drawer.open) {
                settingsLoad(true);
            }
        });
    }

