        echo "  if [ \\\"\\\${1:-}\\\" = \\\"--dash-open\\\" ]; then"
        echo "    /usr/local/bin/zypper-auto-helper \\\"\\\$@\\\""
        echo "  else"
        echo "    sudo /usr/local/bin/zypper-auto-helper \\\"\\\$@\\\""
        echo "  fi"
        echo "}"
    } >> "$SUDO_USER_HOME/.zshrc"

    chown "$SUDO_USER:$SUDO_USER" "$SUDO_USER_HOME/.zshrc"
    log_success "Added zypper-auto-helper wrapper to .zshrc"
fi

log_success "zypper-auto-helper command aliases configured for all shells."

# --- 7d. Install shell completions (bash/zsh/fish) ---
install_shell_completions() {
    log_info ">>> Installing shell completion scripts for zypper-auto-helper (bash/zsh/fish)..."

    # Top-level commands/options (first word after 'zypper-auto-helper')
    local ZNH_CLI_WORDS
    # Keep this as a single line so the generated completion scripts are
    # syntactically robust across distros/shells.
ZNH_CLI_WORDS="install debug snapper scrub-ghost --verify --repair --diagnose --check --self-check --self-update --self-update-rollback --rollback --soar --brew --pip-package --pipx --setup-SF --reset-config --reset-downloads --reset-state --rm-conflict --logs --log --live-logs --analyze --health --test-notify --status --dashboard --generate-dashboard --dash-open --dash-stop --dash-install --dash-api-on --dash-api-off --dash-api-status --send-webhook --webhook --diag-logs-on --diag-logs-off --snapshot-state --diag-bundle --diag-logs-runner --show-logs --show-loggs --uninstall-zypper --uninstall-zypper-helper --debug --help -h help"

    # Snapper submenu
    local ZNH_SNAPPER_SUB
    ZNH_SNAPPER_SUB="status list create cleanup auto auto-off"
        local ZNH_SNAPPER_CLEANUP_ALGOS
        ZNH_SNAPPER_CLEANUP_ALGOS="all number timeline empty-pre-post"

    # scrub-ghost flags (for: zypper-auto-helper scrub-ghost ...)
    local ZNH_SCRUB_GHOST_OPTS
    ZNH_SCRUB_GHOST_OPTS="--dry-run --force --delete --backup-dir --backup-root --keep-backups --entries-dir --boot-dir --rebuild-grub --grub-cfg --update-sdboot --no-remount-rw --json --no-color --verbose --debug --log-file --menu --rescue --list-backups --restore-latest --restore-best --restore-pick --restore-from --clean-restore --restore-anyway --validate-latest --validate-pick --validate-from --no-backup --no-snapper-backup --no-verify-snapshots --no-verify-modules --prune-stale-snapshots --prune-uninstalled --prune-duplicates --prune-zombies --confirm-uninstalled --completion --help -h"

    # --- bash completion (system-wide) ---
    local bash_dir bash_file
    bash_dir=""
    if [ -d "/etc/bash_completion.d" ]; then
        bash_dir="/etc/bash_completion.d"
    elif [ -d "/usr/share/bash-completion/completions" ]; then
        bash_dir="/usr/share/bash-completion/completions"
    fi

    if [ -n "${bash_dir}" ]; then
        bash_file="${bash_dir}/zypper-auto-helper"
        log_debug "Writing bash completion file: ${bash_file}"
        write_atomic "${bash_file}" <<EOF
# bash completion for zypper-auto-helper (installed by zypper-auto-helper)

_znh_zypper_auto_helper() {
    local cur prev cword words
    cur="\${COMP_WORDS[COMP_CWORD]}"
    prev="\${COMP_WORDS[COMP_CWORD-1]}"
    cword=\${COMP_CWORD}
    words=("\${COMP_WORDS[@]}")

    # Complete first argument
    if [ \${cword} -eq 1 ]; then
        COMPREPLY=( \$(compgen -W "${ZNH_CLI_WORDS}" -- "\${cur}") )
        return 0
    fi

    # Snapper submenu
    if [ "\${words[1]}" = "snapper" ]; then
        if [ \${cword} -eq 2 ]; then
            COMPREPLY=( \$(compgen -W "${ZNH_SNAPPER_SUB}" -- "\${cur}") )
            return 0
        fi
        if [ "\${words[2]}" = "cleanup" ] && [ \${cword} -eq 3 ]; then
            COMPREPLY=( \$(compgen -W "${ZNH_SNAPPER_CLEANUP_ALGOS}" -- "\${cur}") )
            return 0
        fi
    fi

    # scrub-ghost flags
    if [ "\${words[1]}" = "scrub-ghost" ]; then
        COMPREPLY=( \$(compgen -W "${ZNH_SCRUB_GHOST_OPTS}" -- "\${cur}") )
        return 0
    fi

    COMPREPLY=()
    return 0
}

complete -F _znh_zypper_auto_helper zypper-auto-helper 2>/dev/null || true
EOF
        chmod 644 "${bash_file}" 2>/dev/null || true
        log_success "Installed bash completion: ${bash_file}"

        # Also install completion for scrub-ghost as a standalone command.
        local bash_file_sg
        bash_file_sg="${bash_dir}/scrub-ghost"
        log_debug "Writing bash completion file: ${bash_file_sg}"
        write_atomic "${bash_file_sg}" <<EOF
# bash completion for scrub-ghost (installed by zypper-auto-helper)

_scrub_ghost_complete() {
  local cur
  cur="\${COMP_WORDS[COMP_CWORD]}"
  local opts="${ZNH_SCRUB_GHOST_OPTS}"
  COMPREPLY=( \$(compgen -W "\${opts}" -- "\${cur}") )
}

complete -F _scrub_ghost_complete scrub-ghost zypper-scrub-ghost 2>/dev/null || true
EOF
        chmod 644 "${bash_file_sg}" 2>/dev/null || true
