case $state in
  cmds)
    _values 'zypper-auto-helper command' $_znh_cmds
    ;;
  args)
    if [[ ${words[2]} == snapper ]]; then
      if (( CURRENT == 3 )); then
        _values 'snapper subcommand' $_znh_snapper_sub
