def _write_atomic_text(path: str, text: str, *, mode: int = 0o644) -> None:
    tmp = f"{path}.tmp.{os.getpid()}.{secrets.token_hex(4)}"
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(text or "")
        if text and not text.endswith("\n"):
            f.write("\n")
    try:
        os.chmod(tmp, mode)
    except Exception:
        pass
    os.replace(tmp, path)


def _reboot_required() -> bool:
    # Prefer zypper's own hint when available.
    try:
        p = subprocess.run(
            [ZYPPER_BIN, "needs-reboot"],
            check=False,
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            timeout=8,
        )
        # On openSUSE, rc=1 means reboot needed, rc=0 means no reboot.
        if int(p.returncode) == 1:
            return True
        if int(p.returncode) == 0:
            return False
    except Exception:
        pass

    # Fallback marker files used by various tools.
    for f in (
        "/run/reboot-needed",
        "/var/run/reboot-needed",
        "/run/reboot-required",
        "/var/run/reboot-required",
    ):
        try:
            if os.path.exists(f):
                return True
        except Exception:
            continue

    return False

def _zypp_lock_info() -> tuple[str, str, bool]:
    """Return (lock_file, pid, active)."""
    lock_file = ""
    pid = ""

    try:
        if os.path.exists("/run/zypp.pid"):
            lock_file = "/run/zypp.pid"
        elif os.path.exists("/var/run/zypp.pid"):
            lock_file = "/var/run/zypp.pid"
    except Exception:
        lock_file = ""

    if not lock_file:
        return "", "", False

    try:
        with open(lock_file, "r", encoding="utf-8", errors="replace") as f:
            pid = (f.read() or "").strip()
    except Exception:
        pid = ""

    # Active if PID exists and is alive, OR if any zypper process exists.
    active = False
    try:
        if pid and re.fullmatch(r"[0-9]+", pid or ""):
            p = subprocess.run(["/usr/bin/kill", "-0", pid], check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            if p.returncode == 0:
                active = True
    except Exception:
        pass

    if not active:
        try:
            p2 = subprocess.run(["/usr/bin/pgrep", "-x", "zypper"], check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            if p2.returncode == 0:
                active = True
        except Exception:
            pass

    return lock_file, pid, bool(active)


def _wait_for_zypp_lock(max_wait_s: int, *, step_s: float = 5.0) -> tuple[int, str, str, bool]:
    """Wait for zypp lock up to max_wait_s. Returns (waited_s, lock_file, pid, timed_out)."""
    waited = 0
    timed_out = False

    while waited < int(max_wait_s):
        lf, pid, active = _zypp_lock_info()
        if not active:
            return waited, lf, pid, False
        time.sleep(step_s)
        waited += int(step_s)

    lf, pid, active = _zypp_lock_info()
    if active:
        timed_out = True
    return waited, lf, pid, bool(timed_out)


def _detect_solver_conflict(text: str, rc: int) -> tuple[bool, str]:
    """Best-effort solver conflict detection for zypper output."""
    if rc == 0:
        return False, ""

    t = (text or "")
    low = t.lower()

    # Common patterns for libzypp/zypper solver problems.
    markers = [
        "problem:",
        "solverrun solutions:",
        "choose from above solutions",
        "choose from above solutions by number",
        "nothing provides",
        "conflict",
        "package requires",
        "unresolvable",
        "found incompatible",
        "requires:",
    ]

    if not any(m in low for m in markers):
        return False, ""

    # Try to extract a short, readable summary block.
    lines = t.splitlines()
    start = 0
    for i, ln in enumerate(lines):
        if "problem:" in (ln or "").lower():
            start = i
            break
    snippet = "\n".join(lines[start:start + 30]).strip()
    if len(snippet) > 4000:
        snippet = snippet[:4000] + "\n..."
    return True, snippet


def _zypper_xml_pretty(text: str) -> str:
    """Convert zypper --xmlout output to a more readable text form (best-effort)."""
    if not text:
        return ""
    if "<" not in text:
        return text

    out_lines = []
    for ln in (text or "").splitlines():
        s = (ln or "").strip()
        if not s:
            out_lines.append("")
            continue
        if s.startswith("<?xml"):
            continue
        if s.startswith("<") and ">" in s:
            # Remove tags; keep inner text.
            cleaned = re.sub(r"<[^>]+>", " ", s)
            cleaned = re.sub(r"\s+", " ", cleaned).strip()
            if cleaned:
                out_lines.append(cleaned)
            continue
        out_lines.append(ln)

    return "\n".join(out_lines)



def _parse_extra_flags(raw: str) -> list[str]:
    if not raw:
        return []
    try:
        return [str(x) for x in shlex.split(raw) if str(x).strip()]
    except Exception:
        # Fallback: whitespace split (best-effort)
        return [p for p in raw.split() if p.strip()]


def _github_get_json(path: str, timeout_s: int = 10) -> dict:
    url = f"https://api.github.com/repos/{GITHUB_OWNER}/{GITHUB_REPO}{path}"
    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "znh-dashboard-api",
            "Accept": "application/vnd.github+json",
        },
    )
    with urllib.request.urlopen(req, timeout=timeout_s) as r:
        data = r.read().decode("utf-8", errors="replace")
    return json.loads(data)


def _tag_to_int(tag: str) -> int | None:
    # Supports tags like: v65
    m = re.fullmatch(r"v([0-9]+)", (tag or "").strip())
    if not m:
        return None
    try:
        return int(m.group(1))
    except Exception:
        return None


def _read_installed_version_header(path: str) -> int:
    # Parse: #       VERSION 65 - ...
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for i, line in enumerate(f):
                if i > 200:
                    break
                m = re.match(r"^#\s*VERSION\s+([0-9]+)", line)
                if m:
                    return int(m.group(1))
    except Exception:
        return 0
    return 0


def _read_embedded_sha(path: str) -> str:
    # Parse: __ZNH_EMBEDDED_SHA="<sha>" (optional CI stamp)
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for i, line in enumerate(f):
                if i > 250:
                    break
                m = re.match(r'^__ZNH_EMBEDDED_SHA\s*=\s*"([0-9a-fA-F]{7,40})"\s*$', line.strip())
                if m:
                    v = (m.group(1) or "").strip().lower()
                    return v
    except Exception:
        return ""
    return ""


def _read_self_update_state() -> dict:
    try:
        with open(SELF_UPDATE_STATE_FILE, "r", encoding="utf-8") as f:
            d = json.load(f)
        return d if isinstance(d, dict) else {}
    except Exception:
        return {}


# --- Self-update job runner (dashboard API) ---
JOB_MAX_OUTPUT_CHARS = 200_000
JOB_OUTPUT_TAIL_CHARS = 40_000
JOB_TTL_SECONDS = 30 * 60

# Rocket Update Wizard (system dup) needs to survive dashboard API restarts.
# The systemd-run unit keeps running even if this API service restarts, so the
# in-memory job map can be lost. We therefore support stateless resume by using
# deterministic log/status paths derived from job_id.
DUP_LOG_DIR = "/var/log/zypper-auto/service-logs"
DUP_STATUS_DIR = "/var/lib/zypper-auto"

# --- Quick Actions job runner (dashboard API) ---
# These are allowlisted helper operations that can be started from the WebUI and
# streamed into the terminal-like overlay.
QUICK_LOG_DIR = DUP_LOG_DIR
QUICK_STATUS_DIR = DUP_STATUS_DIR

# --- scrub-ghost job runner (dashboard API) ---
# Runs boot-entry scrub operations in a transient systemd unit so it survives
# dashboard API restarts and browser crashes (WebUI resumes via job_id).
SCRUB_LOG_DIR = DUP_LOG_DIR
SCRUB_STATUS_DIR = DUP_STATUS_DIR


def _scrub_paths(job_id: str) -> tuple[str, str, str, str]:
    jid = (job_id or "").strip()
    unit = f"znh-webui-scrub-{jid[:8]}"
    log_path = f"{SCRUB_LOG_DIR}/webui-scrub-{jid[:10]}.log"
    status_path = f"{SCRUB_STATUS_DIR}/webui-scrub-{jid[:10]}.status"
    script_path = f"{SCRUB_STATUS_DIR}/webui-scrub-{jid[:10]}.sh"
    return unit, log_path, status_path, script_path


def _recover_scrub_job(job_id: str) -> dict | None:
    # token_urlsafe() uses [A-Za-z0-9_-]. Reject anything else.
    jid = (job_id or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{10,}", jid or ""):
        return None

    unit, log_path, status_path, _script_path = _scrub_paths(jid)

    have_any = os.path.exists(log_path) or os.path.exists(status_path)

    props = {}
    rc_show, out_show = _run_cmd(
        ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState", "-p", "ExecMainStatus"],
        timeout_s=3,
        log=None,
    )
    if rc_show == 0:
        for line in (out_show or "").splitlines():
            if "=" in line:
                k, v = line.split("=", 1)
                props[k.strip()] = v.strip()
        if props.get("ActiveState"):
            have_any = True

    if not have_any:
        return None

    active = props.get("ActiveState", "")
    sub = props.get("SubState", "")

    status = _read_kv_status(status_path) if os.path.exists(status_path) else {}

    done = False
    rc = None

    try:
        done = str(status.get("done", "")).strip() in ("1", "true", "yes")
    except Exception:
        done = False

    if done:
        try:
            rc = int(str(status.get("rc", "1") or "1"))
        except Exception:
            rc = 1

    if not done and active == "inactive" and sub in ("dead", "failed", "exited"):
        done = True
        try:
            rc = int(props.get("ExecMainStatus", "1") or "1")
        except Exception:
            rc = 1

    running = not done

    tail, truncated = _tail_file(log_path, JOB_OUTPUT_TAIL_CHARS) if os.path.exists(log_path) else ("", False)

    stage = str(status.get("stage") or ("Running" if active == "active" else "Starting"))
    if done:
        if rc == 0:
            stage = "Done"
        else:
            stage = "Failed"

    progress = 0
    try:
        if done:
            progress = 100
        elif stage.lower().startswith("starting"):
            progress = 5
        else:
            progress = 25
    except Exception:
        progress = 0

    action = str(status.get("action", "") or "").strip()
    title = str(status.get("title", "") or "").strip()

    return {
        "job_id": jid,
        "type": "scrub-ghost",
        "action": action,
        "title": title,
        "running": bool(running),
        "done": bool(done),
        "rc": rc,
        "stage": stage,
        "progress": int(progress),
        "output": tail,
        "output_truncated": bool(truncated),
        "resumed": True,
        "unit": unit,
        "log_path": log_path,
        "status_path": status_path,
    }


def _scrub_any_running() -> dict:
    """Best-effort: detect if any scrub-ghost unit is currently running."""
    out = {
        "running": False,
        "action": "",
        "title": "",
        "unit": "",
        "status_path": "",
        "checked": 0,
    }

    try:
        paths = glob.glob(os.path.join(SCRUB_STATUS_DIR, "webui-scrub-*.status"))
    except Exception:
        paths = []

    # Prefer newest status files.
    try:
        paths = sorted(paths, key=lambda p: os.path.getmtime(p), reverse=True)
    except Exception:
        pass

    now = time.time()
    for p in (paths or [])[:40]:
        out["checked"] = out.get("checked", 0) + 1

        # Ignore very old leftovers.
        age = 0.0
        try:
            age = float(now - os.path.getmtime(p))
        except Exception:
            age = 0.0
        if age > 6 * 3600:
            continue

        st = {}
        try:
            st = _read_kv_status(p)
        except Exception:
            st = {}

        done = False
        try:
            done = str(st.get("done", "")).strip() in ("1", "true", "yes")
        except Exception:
            done = False
        if done:
            continue

        base = os.path.basename(p)
        prefix = ""
        try:
            prefix = base.replace("webui-scrub-", "", 1).replace(".status", "", 1)
        except Exception:
            prefix = ""
        unit = f"znh-webui-scrub-{prefix[:8]}" if prefix else ""

        active = ""
        sub = ""
        if unit:
            try:
                rc_show, out_show = _run_cmd(
                    ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState"],
                    timeout_s=2,
                    log=None,
                )
                if rc_show == 0:
                    for line in (out_show or "").splitlines():
                        if "=" in line:
                            k, v = line.split("=", 1)
                            if k.strip() == "ActiveState":
                                active = v.strip()
                            if k.strip() == "SubState":
                                sub = v.strip()
            except Exception:
                pass

        is_running = (active == "active") or (age < 30 * 60)
        if is_running:
            out["running"] = True
            out["action"] = str(st.get("action", "") or "").strip()
            out["title"] = str(st.get("title", "") or "").strip()
            out["unit"] = unit
            out["status_path"] = p
            return out

    return out


