def _recover_quick_job(job_id: str) -> dict | None:
    # token_urlsafe() uses [A-Za-z0-9_-]. Reject anything else.
    jid = (job_id or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{10,}", jid or ""):
        return None

    unit, log_path, status_path, _script_path = _quick_paths(jid)

    have_any = os.path.exists(log_path) or os.path.exists(status_path)

    props = {}
    rc_show, out_show = _run_cmd(
        ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState", "-p", "ExecMainStatus"],
        timeout_s=3,
        log=None,
    )
    if rc_show == 0:
        for line in (out_show or "").splitlines():
            if "=" in line:
                k, v = line.split("=", 1)
                props[k.strip()] = v.strip()
        if props.get("ActiveState"):
            have_any = True

    if not have_any:
        return None

    active = props.get("ActiveState", "")
    sub = props.get("SubState", "")

    status = _read_kv_status(status_path) if os.path.exists(status_path) else {}

    done = False
    rc = None

    try:
        done = str(status.get("done", "")).strip() in ("1", "true", "yes")
    except Exception:
        done = False

    if done:
        try:
            rc = int(str(status.get("rc", "1") or "1"))
        except Exception:
            rc = 1

    if not done and active == "inactive" and sub in ("dead", "failed", "exited"):
        done = True
        try:
            rc = int(props.get("ExecMainStatus", "1") or "1")
        except Exception:
            rc = 1

    running = not done

    tail, truncated = _tail_file(log_path, JOB_OUTPUT_TAIL_CHARS) if os.path.exists(log_path) else ("", False)

    stage = str(status.get("stage") or ("Running" if active == "active" else "Starting"))
    if done:
        if rc == 0:
            stage = "Done"
        else:
            stage = "Failed"

    progress = 0
    try:
        if done:
            progress = 100
        elif stage.lower().startswith("starting"):
            progress = 5
        else:
            progress = 20
    except Exception:
        progress = 0

    action = str(status.get("action", "") or "").strip()
    title = str(status.get("title", "") or "").strip()

    return {
        "job_id": jid,
        "type": "quick-action",
        "action": action,
        "title": title,
        "running": bool(running),
        "done": bool(done),
        "rc": rc,
        "stage": stage,
        "progress": int(progress),
        "output": tail,
        "output_truncated": bool(truncated),
        "resumed": True,
        "unit": unit,
        "log_path": log_path,
        "status_path": status_path,
    }


def _quick_any_running() -> dict:
    """Best-effort: detect if any quick-action unit is currently running."""
    out = {
        "running": False,
        "action": "",
        "title": "",
        "unit": "",
        "status_path": "",
        "checked": 0,
    }

    try:
        paths = glob.glob(os.path.join(QUICK_STATUS_DIR, "webui-quick-*.status"))
    except Exception:
        paths = []

    # Prefer newest status files.
    try:
        paths = sorted(paths, key=lambda p: os.path.getmtime(p), reverse=True)
    except Exception:
        pass

    now = time.time()
    for p in (paths or [])[:40]:
        out["checked"] = out.get("checked", 0) + 1

        # Ignore very old leftovers.
        age = 0.0
        try:
            age = float(now - os.path.getmtime(p))
        except Exception:
            age = 0.0
        if age > 6 * 3600:
            continue

        st = {}
        try:
            st = _read_kv_status(p)
        except Exception:
            st = {}

        done = False
        try:
            done = str(st.get("done", "")).strip() in ("1", "true", "yes")
        except Exception:
            done = False
        if done:
            continue

        # Derive unit name from status file prefix.
        base = os.path.basename(p)
        prefix = ""
        try:
            prefix = base.replace("webui-quick-", "", 1).replace(".status", "", 1)
        except Exception:
            prefix = ""
        unit = f"znh-webui-quick-{prefix[:8]}" if prefix else ""

        active = ""
        sub = ""
        if unit:
            try:
                rc_show, out_show = _run_cmd(
                    ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState"],
                    timeout_s=2,
                    log=None,
                )
                if rc_show == 0:
                    for line in (out_show or "").splitlines():
                        if "=" in line:
                            k, v = line.split("=", 1)
                            if k.strip() == "ActiveState":
                                active = v.strip()
                            if k.strip() == "SubState":
                                sub = v.strip()
            except Exception:
                pass

        is_running = (active == "active") or (age < 30 * 60)
        if is_running:
            out["running"] = True
            out["action"] = str(st.get("action", "") or "").strip()
            out["title"] = str(st.get("title", "") or "").strip()
            out["unit"] = unit
            out["status_path"] = p
            return out

    return out


def _dup_paths(job_id: str) -> tuple[str, str, str]:
    jid = (job_id or "").strip()
    unit = f"znh-webui-dup-{jid[:8]}"
    log_path = f"{DUP_LOG_DIR}/webui-dup-{jid[:10]}.log"
    status_path = f"{DUP_STATUS_DIR}/webui-dup-{jid[:10]}.status"
    return unit, log_path, status_path


def _tail_file(path: str, max_chars: int) -> tuple[str, bool]:
    """Return (tail_text, truncated)."""
    try:
        with open(path, "rb") as f:
            f.seek(0, os.SEEK_END)
            size = f.tell()
            start = max(0, size - int(max_chars))
            f.seek(start)
            data = f.read()
        txt = data.decode("utf-8", errors="replace")
        return txt, bool(start > 0)
    except Exception:
        return "", False


def _read_kv_status(path: str) -> dict:
    out = {}
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#"):
                    continue
                if "=" not in line:
                    continue
                k, v = line.split("=", 1)
                out[k.strip()] = v.strip()
    except Exception:
        return {}
    return out


def _recover_system_dup_job(job_id: str) -> dict | None:
    # token_urlsafe() uses [A-Za-z0-9_-]. Reject anything else.
    jid = (job_id or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{10,}", jid or ""):
        return None

    unit, log_path, status_path = _dup_paths(jid)

    have_any = os.path.exists(log_path) or os.path.exists(status_path)

    props = {}
    rc_show, out_show = _run_cmd(
        ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState", "-p", "ExecMainStatus"],
        timeout_s=3,
        log=None,
    )
    if rc_show == 0:
        for line in (out_show or "").splitlines():
            if "=" in line:
                k, v = line.split("=", 1)
                props[k.strip()] = v.strip()
        if props.get("ActiveState"):
            have_any = True

    if not have_any:
        return None

    active = props.get("ActiveState", "")
    sub = props.get("SubState", "")

    status = _read_kv_status(status_path) if os.path.exists(status_path) else {}

    done = False
    rc = None

    try:
        done = str(status.get("done", "")).strip() in ("1", "true", "yes")
    except Exception:
        done = False

    if done:
        try:
            rc = int(str(status.get("rc", "1") or "1"))
        except Exception:
            rc = 1

    if not done and active == "inactive" and sub in ("dead", "failed", "exited"):
        done = True
        try:
            rc = int(props.get("ExecMainStatus", "1") or "1")
        except Exception:
            rc = 1

    running = not done

    tail, truncated = _tail_file(log_path, JOB_OUTPUT_TAIL_CHARS) if os.path.exists(log_path) else ("", False)

    # Best-effort progress from log tail
    jtmp = {
        "stage": status.get("stage") or ("Running" if active == "active" else "Starting"),
        "progress": 0,
    }
    try:
        for ln in (tail or "").splitlines(True):
            _job_update_progress_dup(jtmp, ln)
    except Exception:
        pass

    stage = str(jtmp.get("stage") or "Starting")
    progress = int(jtmp.get("progress") or 0)

    if done and progress < 100:
        if rc == 0:
            progress = 100
            stage = "Done"
        else:
            stage = "Failed"

    # Restart check section (best-effort from tail)
    restart_out = ""
    try:
        marker = "=== ZYPPER PS -s (restart check) ==="
        if marker in (tail or ""):
            restart_out = (tail.split(marker, 1)[1] or "").strip()
            if len(restart_out) > 60_000:
                restart_out = restart_out[-60_000:]
    except Exception:
        restart_out = ""

    tail_pretty = _zypper_xml_pretty(tail)

    conflict_detected = False
    conflict_summary = ""
    try:
        if rc is not None:
            conflict_detected, conflict_summary = _detect_solver_conflict(tail_pretty, int(rc))
    except Exception:
        conflict_detected, conflict_summary = False, ""

    return {
        "job_id": jid,
        "type": "system-dup",
        "simulate": bool(str(status.get("simulate", "0")).strip() in ("1", "true", "yes")),
        "running": bool(running),
        "done": bool(done),
        "rc": rc,
        "stage": stage,
        "progress": int(progress),
        "output": tail_pretty,
        "output_truncated": bool(truncated),
        "restart_check_output": restart_out,
        "conflict_detected": bool(conflict_detected),
        "conflict_summary": str(conflict_summary or ""),
        "resumed": True,
        "unit": unit,
        "log_path": log_path,
        "status_path": status_path,
    }


# --- Self-update resume helpers (WebUI) ---
SU_LOG_DIR = "/var/log/zypper-auto/service-logs"
SU_STATUS_DIR = "/var/lib/zypper-auto"


def _self_update_any_running() -> dict:
    """Best-effort: detect if any WebUI self-update unit is currently running.

    This is used as a safety guard so users cannot switch channels or start a second update
    while one is already in progress.
    """
    out = {
        "running": False,
        "channel": "",
        "unit": "",
        "status_path": "",
        "checked": 0,
    }

    try:
        paths = glob.glob(os.path.join(SU_STATUS_DIR, "webui-self-update-*.status"))
    except Exception:
        paths = []

    # Prefer newest status files.
    try:
        paths = sorted(paths, key=lambda p: os.path.getmtime(p), reverse=True)
    except Exception:
        pass

    now = time.time()
    for p in (paths or [])[:30]:
        out["checked"] = out.get("checked", 0) + 1
        st = {}
        try:
            st = _read_kv_status(p)
        except Exception:
            st = {}

        done = False
        try:
            done = str(st.get("done", "")).strip() in ("1", "true", "yes")
        except Exception:
            done = False
        if done:
            continue

        # Ignore very old leftovers.
        age = 0.0
        try:
            age = float(now - os.path.getmtime(p))
        except Exception:
            age = 0.0
        if age > 12 * 3600:
            continue

        ch = str(st.get("channel", "") or "").strip().lower()
        if ch not in ("stable", "rolling"):
            ch = ""

        # Derive unit name from status file prefix.
        base = os.path.basename(p)
        prefix = ""
        try:
            prefix = base.replace("webui-self-update-", "", 1).replace(".status", "", 1)
        except Exception:
            prefix = ""
        unit = f"znh-webui-self-update-{prefix[:8]}" if prefix else ""

        active = ""
        sub = ""
        if unit:
            try:
                rc_show, out_show = _run_cmd(
                    ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState"],
                    timeout_s=2,
                    log=None,
                )
                if rc_show == 0:
                    for line in (out_show or "").splitlines():
                        if "=" in line:
                            k, v = line.split("=", 1)
                            if k.strip() == "ActiveState":
                                active = v.strip()
                            if k.strip() == "SubState":
                                sub = v.strip()
            except Exception:
                pass

        # If systemd says it's active, it's definitely running.
        # If systemd isn't available but the status is fresh + not done, still treat as running.
        is_running = (active == "active") or (age < 30 * 60)

        if is_running:
            out["running"] = True
            out["channel"] = ch
            out["unit"] = unit
            out["status_path"] = p
            return out

    return out


def _su_paths(job_id: str) -> tuple[str, str, str, str]:
    jid = (job_id or "").strip()
    unit = f"znh-webui-self-update-{jid[:8]}"
    log_path = f"{SU_LOG_DIR}/webui-self-update-{jid[:10]}.log"
    status_path = f"{SU_STATUS_DIR}/webui-self-update-{jid[:10]}.status"
    script_path = f"{SU_STATUS_DIR}/webui-self-update-{jid[:10]}.sh"
    return unit, log_path, status_path, script_path


def _recover_self_update_job(job_id: str) -> dict | None:
    # token_urlsafe() uses [A-Za-z0-9_-]. Reject anything else.
    jid = (job_id or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{10,}", jid or ""):
        return None

    unit, log_path, status_path, _script_path = _su_paths(jid)

    have_any = os.path.exists(log_path) or os.path.exists(status_path)

    props = {}
    rc_show, out_show = _run_cmd(
        ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState", "-p", "ExecMainStatus"],
        timeout_s=3,
        log=None,
    )
    if rc_show == 0:
        for line in (out_show or "").splitlines():
            if "=" in line:
                k, v = line.split("=", 1)
                props[k.strip()] = v.strip()
        if props.get("ActiveState"):
            have_any = True

    if not have_any:
        return None

    active = props.get("ActiveState", "")
    sub = props.get("SubState", "")

    status = _read_kv_status(status_path) if os.path.exists(status_path) else {}

    ch = str(status.get("channel", "") or "").strip().lower()
    if ch not in ("stable", "rolling"):
        ch = ""

    dry_run = str(status.get("dry_run", "") or "").strip() in ("1", "true", "yes")

    done = False
    rc = None

    try:
        done = str(status.get("done", "")).strip() in ("1", "true", "yes")
    except Exception:
        done = False

    if done:
        try:
            rc = int(str(status.get("rc", "1") or "1"))
        except Exception:
            rc = 1

    if not done and active == "inactive" and sub in ("dead", "failed", "exited"):
        done = True
        try:
            rc = int(props.get("ExecMainStatus", "1") or "1")
        except Exception:
            rc = 1

    running = not done

    tail, truncated = _tail_file(log_path, JOB_OUTPUT_TAIL_CHARS) if os.path.exists(log_path) else ("", False)

    # Best-effort progress from log tail
    jtmp = {
        "stage": status.get("stage") or ("Running" if active == "active" else "Starting"),
        "progress": 0,
    }
    try:
        for ln in (tail or "").splitlines(True):
            _job_update_progress(jtmp, ln)
    except Exception:
        pass

    stage = str(jtmp.get("stage") or "Starting")
    progress = int(jtmp.get("progress") or 0)

    if done and progress < 100:
        if rc == 0:
            progress = 100
            stage = "Dry-run done" if dry_run else "Done"
        else:
            stage = "Failed"

    # UX fix: the progress parser may hit 100% early (e.g. on "update complete") while
    # the unit is still running post-actions (verify/install). Never show 100% until done.
    if not done and progress >= 100:
        progress = 99
        try:
            low = stage.lower()
            if low in ("done", "dry-run done", "up-to-date"):
                stage = "Finishing…"
        except Exception:
            stage = "Finishing…"

    post_action = str(status.get("post_action", "") or "").strip().lower()
    if post_action not in ("none", "verify", "install"):
        post_action = "none"

    post_action_rc = 0
    try:
        post_action_rc = int(str(status.get("post_action_rc", "0") or "0").strip() or "0")
    except Exception:
        post_action_rc = 0

    update_rc = rc
    try:
        update_rc = int(str(status.get("update_rc", rc if rc is not None else 0) or "0").strip() or "0")
    except Exception:
        update_rc = rc

    return {
        "job_id": jid,
        "type": "self-update",
        "channel": ch,
        "dry_run": bool(dry_run),
        "simulate": False,
        "running": bool(running),
        "done": bool(done),
        "rc": rc,
        "update_rc": update_rc,
        "post_action": post_action,
        "post_action_rc": post_action_rc,
        "stage": stage,
        "progress": int(progress),
        "output": tail,
        "output_truncated": bool(truncated),
        "restart_check_output": "",
        "resumed": True,
        "unit": unit,
        "log_path": log_path,
        "status_path": status_path,
    }


def _job_output_append(job: dict, s: str) -> None:
    if not s:
        return
    out = str(job.get("output", "")) + s
    if len(out) > JOB_MAX_OUTPUT_CHARS:
        out = out[-JOB_MAX_OUTPUT_CHARS:]
        job["output_truncated"] = True
    job["output"] = out


def _job_update_progress(job: dict, line: str) -> None:
    l = (line or "").lower()
    stage = job.get("stage") or "Starting"
    prog = int(job.get("progress") or 0)

    def bump(p: int, st: str):
        nonlocal stage, prog
        if p > prog:
            prog = p
        stage = st

    if "already up-to-date" in l or "already up to date" in l:
        bump(100, "Up-to-date")
    elif "downloading update" in l:
        bump(25, "Downloading")
    elif "verification" in l or "syntax check" in l or "sha256" in l:
        bump(55, "Verifying")
    elif "installing stable" in l or "installing rolling" in l or "atomic swap" in l or "backup created" in l:
        bump(80, "Installing")
    elif "running post-update self-test" in l or "post-update self-test" in l:
        bump(92, "Self-test")
    elif "update complete" in l:
        bump(100, "Done")
    elif "dry-run ok" in l or "dry run ok" in l:
        bump(100, "Dry-run done")

    job["stage"] = stage
    job["progress"] = prog


def _job_update_progress_dup(job: dict, line: str) -> None:
    """Best-effort progress estimation for system updates (zypper dup).

    This is heuristic: zypper output varies by version/locale.
    If zypper is run with --xmlout, we also attempt to parse percent progress.
    """
    raw = (line or "")
    l = raw.lower()
    stage = job.get("stage") or "Starting"
    prog = int(job.get("progress") or 0)

    def bump(p: int, st: str):
        nonlocal stage, prog
        if p > prog:
            prog = p
        stage = st

    # Lock wait UX
    if "zypp" in l and "lock" in l and "wait" in l:
        bump(5, "Waiting for lock")

    # XML progress parsing (zypper --xmlout)
    # Example patterns vary, but many include percent="NN".
    try:
        if "<progress" in l and "percent=\"" in l:
            m = re.search(r"percent=\"([0-9]{1,3})\"", raw)
            if m:
                p = int(m.group(1))
                nm = re.search(r"name=\"([^\"]+)\"", raw)
                if nm:
                    bump(p, str(nm.group(1)))
                else:
                    bump(p, stage)
    except Exception:
        pass

    if "dry run" in l or "dry-run" in l:
        bump(10, "Dry-run")
    elif "loading repository data" in l or "retrieving" in l or "refreshing" in l:
        bump(15, "Refreshing")
    elif "computing distribution upgrade" in l or "computing" in l:
        bump(28, "Computing")
    elif "overall download size" in l or "downloading" in l or "download" in l:
        bump(60, "Downloading")
    elif "installing" in l:
        bump(78, "Installing")
    elif "removing" in l:
        bump(82, "Removing")
    elif "committing" in l or "verifying" in l:
        bump(88, "Committing")
    elif "restart check" in l or "zypper ps" in l:
        bump(96, "Restart check")
    elif "done" in l or "complete" in l or "finished" in l:
        bump(100, "Done")

    job["stage"] = stage
    job["progress"] = prog


class Handler(BaseHTTPRequestHandler):
    server_version = "ZNH-Dashboard-API/1.0"

    def do_OPTIONS(self):
        origin = _allowed_origin(self.headers.get("Origin"))
        self.send_response(204)
        if origin:
            self.send_header("Access-Control-Allow-Origin", origin)
            self.send_header("Vary", "Origin")
            self.send_header("Access-Control-Allow-Headers", "Content-Type, X-ZNH-Token")
            self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.end_headers()

    def _auth_ok(self) -> bool:
        token = getattr(self.server, "token", "")
        provided = self.headers.get("X-ZNH-Token", "")
        return bool(token) and provided == token

    def log_message(self, fmt, *args):
        # Quiet default HTTP logs (systemd journal has enough noise already).
        return

    def do_GET(self):
        origin = _allowed_origin(self.headers.get("Origin"))
        parsed = urlparse(self.path)
        path = parsed.path
        qs = parse_qs(parsed.query or "")
        try:
            getattr(self.server, "_znh_log", lambda *_: None)("debug", f"GET {path} from {self.client_address[0]}")
        except Exception:
            pass

        # Snapper, self-update, system-update, scrub-ghost, quick-action, and diag-logs endpoints always require auth.
        if path.startswith("/api/snapper/") or path.startswith("/api/self-update/") or path.startswith("/api/system/") or path.startswith("/api/scrub/") or path.startswith("/api/quick/") or path.startswith("/api/diag-logs/") or path.startswith("/api/boot/"):
            if not self._auth_ok():
                try:
                    getattr(self.server, "_znh_log", lambda *_: None)("warn", f"Unauthorized GET {path} from {self.client_address[0]}")
                except Exception:
                    pass
                return _json_response(self, 401, {"error": "unauthorized"}, origin)

        def _statvfs_usage(path0: str) -> dict:
            p = str(path0 or "").strip()
            out = {
                "ok": False,
                "path": p,
                "total_kb": 0,
                "used_kb": 0,
                "avail_kb": 0,
                "used_pct": 0,
            }
            if not p:
                return out
            try:
                st = os.statvfs(p)
                fr = int(getattr(st, "f_frsize", 0) or getattr(st, "f_bsize", 0) or 0)
                if fr <= 0:
                    fr = int(getattr(st, "f_bsize", 4096) or 4096)
                blocks = int(getattr(st, "f_blocks", 0) or 0)
                bavail = int(getattr(st, "f_bavail", 0) or 0)
                bfree = int(getattr(st, "f_bfree", 0) or 0)
                total = blocks * fr
                avail = bavail * fr
                used = (blocks - bfree) * fr
                if total <= 0:
                    return out
                total_kb = int(total / 1024)
                used_kb = int(used / 1024)
                avail_kb = int(avail / 1024)
                used_pct = int(round((used / total) * 100.0))
                if used_pct < 0:
                    used_pct = 0
                if used_pct > 100:
                    used_pct = 100
                out.update({
                    "ok": True,
                    "total_kb": total_kb,
                    "used_kb": used_kb,
                    "avail_kb": avail_kb,
                    "used_pct": used_pct,
                })
                return out
            except Exception:
                return out

        def _bls_entries_stats() -> dict:
            out = {
                "ok": False,
                "dir": "",
                "total_conf": 0,
                "snapper_conf": 0,
                "other_conf": 0,
                "total_bytes": 0,
            }

            entries_dir = ""
            try:
                for d in ("/boot/efi/loader/entries", "/boot/loader/entries", "/efi/loader/entries"):
                    if os.path.isdir(d):
                        entries_dir = d
                        break
            except Exception:
                entries_dir = ""

            if not entries_dir:
                return out

            try:
                files = glob.glob(os.path.join(entries_dir, "*.conf"))
            except Exception:
                files = []

            total = 0
            snapper = 0
            size = 0
            for f in files or []:
                bn = os.path.basename(f)
                if not bn.endswith(".conf"):
                    continue
                total += 1
                if bn.startswith("snapper-"):
                    snapper += 1
                try:
                    size += int(os.path.getsize(f) or 0)
                except Exception:
                    pass

            out.update({
                "ok": True,
                "dir": entries_dir,
                "total_conf": int(total),
                "snapper_conf": int(snapper),
                "other_conf": int(total - snapper),
                "total_bytes": int(size),
            })
            return out

        def _grub_stats() -> dict:
            # GRUB config location varies by distro/setup.
            candidates = [
                "/boot/grub2/grub.cfg",  # openSUSE/Fedora
                "/boot/grub/grub.cfg",   # Debian-like
            ]
            try:
                # Some EFI installs place a minimal cfg under the ESP.
                candidates.extend(sorted(glob.glob("/boot/efi/EFI/*/grub*.cfg")))
                candidates.extend(sorted(glob.glob("/boot/efi/EFI/*/*grub*.cfg")))
            except Exception:
                pass

            cfg = ""
            for c in candidates:
                try:
                    if c and os.path.exists(c) and os.path.isfile(c):
                        cfg = c
                        break
                except Exception:
                    continue

            out = {
                "ok": False,
                "present": bool(cfg),
                "reason": "",
                "cfg_path": cfg or (candidates[0] if candidates else ""),
                "menuentries": 0,
                "submenus": 0,
                "bls_mode": False,
            }

            if not cfg:
                out["reason"] = "grub.cfg not found (systemd-boot/BLS likely active). This is normal on many newer openSUSE installs. If you switch your bootloader to GRUB later, this stat will appear — but switching bootloaders is an advanced change and not required for scrub-ghost/BLS hygiene."
                return out

            try:
                # grub.cfg can be large; stream line-by-line.
                me = 0
                sm = 0
                bls_mode = False
                with open(cfg, "r", encoding="utf-8", errors="replace") as f:
                    for line in f:
                        l0 = (line or "")
                        l = l0.lstrip().lower()
                        if not bls_mode:
                            # GRUB BLS integration typically uses: insmod blscfg + blscfg
                            if "blscfg" in l:
                                bls_mode = True
                        if l.startswith("menuentry "):
                            me += 1
                        elif l.startswith("submenu "):
                            sm += 1
                out.update({
                    "ok": True,
                    "reason": "",
                    "menuentries": int(me),
                    "submenus": int(sm),
                    "bls_mode": bool(bls_mode),
                })
                return out
            except Exception as e:
                out["reason"] = f"failed to read grub cfg: {e}"
                return out

        if path == "/api/boot/stats":
            efi = _statvfs_usage("/boot/efi")
            boot = _statvfs_usage("/boot")
            bls = _bls_entries_stats()
            grub = _grub_stats()

            # If GRUB is configured for BLS (blscfg), the actual boot menu entries are
            # effectively the BLS entry files (not the literal menuentry lines in grub.cfg).
            try:
                if grub.get("ok") and grub.get("bls_mode") and bls.get("ok"):
                    grub["effective_entries"] = int(bls.get("total_conf") or 0)
                    grub["effective_snapper_entries"] = int(bls.get("snapper_conf") or 0)
                    grub["effective_other_entries"] = int(bls.get("other_conf") or 0)
            except Exception:
                pass

            return _json_response(self, 200, {
                "ok": True,
                "ts": time.time(),
                "efi": efi,
                "boot": boot,
                "bls_entries": bls,
                "grub": grub,
            }, origin)

        # --- Snapper (dashboard) ---
        if path == "/api/snapper/status":
            cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "status"]
            rc, out = _run_cmd(cmd, timeout_s=30, log=getattr(self.server, "_znh_log", None))
            # Always return HTTP 200 so the WebUI can render output even on non-zero rc.
            return _json_response(self, 200, {"ok": (rc == 0), "rc": rc, "output": out}, origin)

        if path == "/api/snapper/list":
            n = "10"
            try:
                n = (qs.get("n") or ["10"])[0]
            except Exception:
                n = "10"
            if not re.fullmatch(r"[0-9]+", str(n)):
                n = "10"
            # Bound list size
            try:
                nn = int(n)
            except Exception:
                nn = 10
            if nn < 1:
                nn = 1
            if nn > 50:
                nn = 50
            cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "list", str(nn)]
            rc, out = _run_cmd(cmd, timeout_s=30, log=getattr(self.server, "_znh_log", None))
            # Always return HTTP 200 so the WebUI can render output even on non-zero rc.
            return _json_response(self, 200, {"ok": (rc == 0), "rc": rc, "output": out}, origin)

        # --- Snapper job status (dashboard) ---
        if path == "/api/snapper/job":
            job_id = ""
            try:
                job_id = str((qs.get("job_id") or [""])[0]).strip()
            except Exception:
                job_id = ""
            if not job_id:
                return _json_response(self, 400, {"error": "job_id required"}, origin)

            recovered = _recover_snapper_job(job_id)
            if recovered:
                return _json_response(self, 200, recovered, origin)
            return _json_response(self, 404, {"error": "job not found"}, origin)

        # --- Self-update status (dashboard) ---
        if path == "/api/self-update/status":
            # Query: ?channel=stable|rolling (optional)
            eff, _warnings, _invalid = _read_conf(self.server.conf_path)
            ch = ""
            try:
                ch = str((qs.get("channel") or [""])[0]).strip().lower()
            except Exception:
                ch = ""
            if ch not in ("stable", "rolling"):
                ch = str(eff.get("SELF_UPDATE_CHANNEL", "stable")).strip().lower()
            if ch not in ("stable", "rolling"):
                ch = "stable"

            state = _read_self_update_state()
            installed_stable = str(state.get("stable_tag", "") or "").strip()
            installed_rolling = str(state.get("rolling_sha", "") or "").strip()

            install_source = str(state.get("install_source", "") or "").strip()
            installed_sha_state = str(state.get("installed_file_sha256", "") or "").strip().lower()
            installed_helper_path_state = str(state.get("installed_helper_path", "") or "").strip()

            # Externally-managed installs should not be self-updated (RPM/OS package manager, etc.)
            helper_real = ""
            try:
                helper_real = os.path.realpath(HELPER_BIN)
            except Exception:
                helper_real = HELPER_BIN
            is_externally_managed = not str(helper_real).startswith("/usr/local/bin/")

            # Calculate current helper file sha256 (for dirty/manual-edit detection)
            installed_sha_current = ""
            try:
                import hashlib

                h = hashlib.sha256()
                with open(HELPER_BIN, "rb") as f:
                    for chunk in iter(lambda: f.read(1024 * 1024), b""):
                        h.update(chunk)
                installed_sha_current = h.hexdigest().strip().lower()
            except Exception:
                installed_sha_current = ""

            sha_tracked = bool(installed_sha_state)
            is_dirty = bool(installed_sha_state and installed_sha_current and installed_sha_state != installed_sha_current)

            # Track what channel the current install *came from* (last updater run).
            # This is important for avoiding false "Update available" statuses when a user
            # switches channel (stable <-> rolling).
            active_channel = str(state.get("last_update_channel", "") or "").strip().lower()
            active_ref = str(state.get("last_update_ref", "") or "").strip()
            if active_channel not in ("stable", "rolling"):
                active_channel = ""
                active_ref = ""

            channel_switch = bool(active_channel and active_channel != ch)

            installed_ref = installed_stable if ch == "stable" else installed_rolling
            known_installed = bool(installed_ref)
            guessed = False

            # Rolling installs done via raw script copy may not have a state file or git metadata.
            # If the helper was CI-stamped with __ZNH_EMBEDDED_SHA, use that as the installed ref.
            if ch == "rolling" and not installed_ref:
                emb = _read_embedded_sha(HELPER_BIN)
                if emb:
                    installed_ref = emb
                    known_installed = True
                    guessed = True

            installed_ver = _read_installed_version_header(HELPER_BIN)
            if ch == "stable" and not installed_ref and installed_ver > 0:
                installed_ref = f"v{installed_ver}"
                known_installed = True
                guessed = True

            remote_ref = ""
            err = ""
            try:
                if ch == "stable":
                    j = _github_get_json("/releases/latest", timeout_s=10)
                    remote_ref = str(j.get("tag_name", "") or "").strip()
                else:
                    j = _github_get_json("/commits/main", timeout_s=10)
                    remote_ref = str(j.get("sha", "") or "").strip()
            except (urllib.error.URLError, urllib.error.HTTPError, json.JSONDecodeError) as e:
                err = str(e)
            except Exception as e:
                err = str(e)

            # Rolling content-compare (bulletproof):
            # Compare the installed helper file SHA256 against the *remote raw helper script* at the
            # latest rolling commit.
            #
            # Why?
            # - Rolling commit SHAs can change even when zypper-auto.sh did not change (docs-only commits).
            # - Comparing contents avoids false "Update available" statuses.
            remote_script_sha256 = ""
            remote_script_path = ""
            rolling_checksum_used = False
            try:
                if ch == "rolling" and remote_ref and installed_sha_current:
                    import hashlib

                    # Try common raw paths (repo layout can evolve; keep this best-effort).
                    candidates = [
                        "zypper-auto.sh",
                        "zypper-auto-helper",
                        "zypper-auto-helper.sh",
                    ]

                    for pth in candidates:
                        try:
                            raw_url = f"https://raw.githubusercontent.com/{GITHUB_OWNER}/{GITHUB_REPO}/{remote_ref}/{pth}"
                            req = urllib.request.Request(raw_url, headers={"User-Agent": "znh-dashboard-api"})
                            with urllib.request.urlopen(req, timeout=15) as r:
                                data = r.read()
                            remote_script_sha256 = hashlib.sha256(data).hexdigest().strip().lower()
                            remote_script_path = pth
                            rolling_checksum_used = True
                            break
                        except Exception:
                            continue
            except Exception:
                remote_script_sha256 = ""
                remote_script_path = ""
                rolling_checksum_used = False

            up_to_date = False
            update_available = False
            install_available = False
            remote_is_older = False

            # Even when switching channel, we can still detect stable downgrade risk
            # (stable tags are comparable to each other).
            if ch == "stable" and installed_ref and remote_ref:
                iv = _tag_to_int(installed_ref)
                rv = _tag_to_int(remote_ref)
                if iv is not None and rv is not None and rv < iv:
                    remote_is_older = True

            if channel_switch:
                # We do not attempt to compare rolling SHA vs stable tag. Treat this as a
                # channel switch (explicit user choice), not an update.
                install_available = bool(remote_ref)

                # Prefer showing the *actual* installed build reference if we have it.
                if active_ref:
                    installed_ref = active_ref
                    known_installed = True
                    guessed = False
                else:
                    # Fall back to whatever we know.
                    known_installed = bool(installed_ref)

            else:
                if ch == "rolling" and remote_ref and not installed_ref:
                    # Checksum fallback (raw script installs without git SHA).
                    if installed_sha_current and remote_script_sha256:
                        known_installed = True
                        guessed = True
                        if installed_sha_current == remote_script_sha256:
                            up_to_date = True
                            installed_ref = remote_ref
                        else:
                            update_available = True
                            installed_ref = f"sha256:{installed_sha_current[:12]}"
                    elif remote_ref:
                        # No checksum available; still treat as install.
                        install_available = True

                elif installed_ref and remote_ref:
                    if ch == "rolling" and installed_sha_current and remote_script_sha256:
                        # Bulletproof rolling: treat as up-to-date when contents match,
                        # even if commit SHAs differ (docs-only commits, etc.).
                        if installed_sha_current == remote_script_sha256:
                            up_to_date = True
                        else:
                            update_available = True
                    elif installed_ref == remote_ref:
                        up_to_date = True
                    elif ch == "stable":
                        # remote_is_older already computed above
                        if not remote_is_older:
                            update_available = True
                    else:
                        update_available = True

                elif remote_ref:
                    # Remote exists but installed ref is unknown. This is an INSTALL,
                    # not an UPDATE. The UI will label it correctly.
                    install_available = True

            # Consolidated evaluation: compute the actual action so the UI doesn't guess.
            action_type = "none"
            msg = ""
            can_safely_execute = not is_externally_managed

            if is_externally_managed:
                action_type = "managed"
                msg = "Updates managed by system package manager"
            elif channel_switch:
                action_type = "switch"
                msg = f"Switch channel {active_channel or 'unknown'} → {ch}"
            elif remote_is_older and ch == "stable":
                action_type = "none"
                msg = "Remote stable tag is older (downgrade blocked by default)"
            elif update_available:
                action_type = "update"
                msg = "Update available"
                if rolling_checksum_used and ch == "rolling":
                    msg = "Update available (rolling checksum mismatch)"
            elif install_available:
                action_type = "install"
                msg = "Install available"
            elif up_to_date:
                action_type = "none"
                msg = "Up to date"
                if rolling_checksum_used and ch == "rolling":
                    msg = "Up to date (rolling checksum match)"

            running_info = _self_update_any_running()

            # Download source transparency (requested): show exactly where the helper would be fetched from.
            # NOTE: stable prefers a release asset if it exists, but still exposes the raw-tag URL.
            download_urls = []
            download_url = ""
            try:
                if remote_ref:
                    if ch == "stable":
                        download_urls = [
                            f"https://github.com/{GITHUB_OWNER}/{GITHUB_REPO}/releases/download/{remote_ref}/zypper-auto.sh",
                            f"https://raw.githubusercontent.com/{GITHUB_OWNER}/{GITHUB_REPO}/{remote_ref}/zypper-auto.sh",
                        ]
                    else:
                        pth = remote_script_path or "zypper-auto.sh"
                        download_urls = [
                            f"https://raw.githubusercontent.com/{GITHUB_OWNER}/{GITHUB_REPO}/{remote_ref}/{pth}",
                        ]
            except Exception:
                download_urls = []

            try:
                if download_urls:
                    download_url = str(download_urls[0] or "")
            except Exception:
                download_url = ""

            payload = {
                # Legacy fields (keep UI backward compatible)
                "channel": ch,
                "download_url": download_url,
                "download_urls": download_urls,
                "destination_path": helper_real,
                "active_channel": active_channel,
                "active_ref": active_ref,
                "channel_switch": channel_switch,
                "known_installed": known_installed,
                "guessed_from_version": guessed,
                "installed_ref": installed_ref,
                "remote_ref": remote_ref,
                "installed_version_header": installed_ver,
                "up_to_date": up_to_date,
                "update_available": update_available,
                "install_available": install_available,
                "remote_is_older": remote_is_older,
                "state_file": SELF_UPDATE_STATE_FILE,
                "install_source": install_source,
                "error": err,

                # New flags
                "is_externally_managed": is_externally_managed,
                "is_dirty": is_dirty,
                "sha_tracked": sha_tracked,
                "installed_helper_path": helper_real,
                "installed_helper_path_state": installed_helper_path_state,

                # Consolidated schema
                "installed": {
                    "channel": active_channel,
                    "stable_tag": installed_stable,
                    "rolling_sha": installed_rolling,
                    "ref": active_ref or installed_ref,
                    "version": f"v{installed_ver}" if installed_ver > 0 else "",
                    "source": install_source,
                    "is_dirty": is_dirty,
                    "is_externally_managed": is_externally_managed,
                    "script_sha256": installed_sha_current,
                    "rolling_checksum_used": bool(rolling_checksum_used),
                    "destination_path": helper_real,
                },
                "remote": {
                    "ref": remote_ref,
                    "stable_tag": remote_ref if ch == "stable" else "",
                    "rolling_sha": remote_ref if ch == "rolling" else "",
                    "script_sha256": remote_script_sha256,
                    "script_path": remote_script_path,
                    "download_url": download_url,
                    "download_urls": download_urls,
                },
                "configured_target_channel": ch,
                "evaluation": {
                    "action_type": action_type,
                    "can_safely_execute": can_safely_execute,
                    "message": msg,
                },

                # Safety: if any self-update job is running, lock channel switching in the UI.
                "job_running": bool(running_info.get("running")),
                "job_running_channel": str(running_info.get("channel", "") or ""),
                "job_running_unit": str(running_info.get("unit", "") or ""),
                "job_running_status_path": str(running_info.get("status_path", "") or ""),
            }

            return _json_response(self, 200, payload, origin)

        # --- Self-update job status (dashboard) ---
        if path == "/api/self-update/job":
            job_id = ""
            try:
                job_id = str((qs.get("job_id") or [""])[0]).strip()
            except Exception:
                job_id = ""
            if not job_id:
                return _json_response(self, 400, {"error": "job_id required"}, origin)

            now_ts = time.time()
            try:
                lock = getattr(self.server, "jobs_lock", None)
                jobs = getattr(self.server, "jobs", {})
                if lock:
                    with lock:
                        # purge old jobs
                        dead = []
                        for k, j in jobs.items():
                            if not isinstance(j, dict):
                                dead.append(k)
                                continue
                            if j.get("done") and (now_ts - float(j.get("finished_at", 0))) > JOB_TTL_SECONDS:
                                dead.append(k)
                        for k in dead:
                            jobs.pop(k, None)

                        job = jobs.get(job_id)
                        if not job:
                            recovered = _recover_self_update_job(job_id)
                            if recovered:
                                return _json_response(self, 200, recovered, origin)
                            return _json_response(self, 404, {"error": "job not found"}, origin)
                        out = str(job.get("output", ""))
                        tail_raw = out[-JOB_OUTPUT_TAIL_CHARS:] if len(out) > JOB_OUTPUT_TAIL_CHARS else out
                        tail = _zypper_xml_pretty(tail_raw)
                        stage = job.get("stage")
                        progress = int(job.get("progress") or 0)
                        running = bool(job.get("running"))
                        done = bool(job.get("done"))
                        if running and not done and progress >= 100:
                            progress = 99
                            try:
                                low = str(stage or "").lower()
                                if low in ("done", "dry-run done", "up-to-date"):
                                    stage = "Finishing…"
                            except Exception:
                                stage = "Finishing…"

                        return _json_response(self, 200, {
                            "job_id": job_id,
                            "type": job.get("type"),
                            "channel": job.get("channel"),
                            "dry_run": bool(job.get("dry_run")),
                            "simulate": bool(job.get("simulate")),
                            "running": running,
                            "done": done,
                            "rc": job.get("rc"),
                            "stage": stage,
                            "progress": int(progress),
                            "output": tail,
                            "output_truncated": bool(job.get("output_truncated")),
                            "restart_check_output": job.get("restart_check_output"),
                            "log_path": job.get("log_path"),
                            "status_path": job.get("status_path"),
                        }, origin)
                else:
                    job = jobs.get(job_id)
                    if not job:
                        recovered = _recover_self_update_job(job_id)
                        if recovered:
                            return _json_response(self, 200, recovered, origin)
                        return _json_response(self, 404, {"error": "job not found"}, origin)
                    out = str(job.get("output", ""))
                    tail_raw = out[-JOB_OUTPUT_TAIL_CHARS:] if len(out) > JOB_OUTPUT_TAIL_CHARS else out
                    tail = _zypper_xml_pretty(tail_raw)
                    stage = job.get("stage")
                    progress = int(job.get("progress") or 0)
                    running = bool(job.get("running"))
                    done = bool(job.get("done"))
                    if running and not done and progress >= 100:
                        progress = 99
                        try:
                            low = str(stage or "").lower()
                            if low in ("done", "dry-run done", "up-to-date"):
                                stage = "Finishing…"
                        except Exception:
                            stage = "Finishing…"

                    return _json_response(self, 200, {
                        "job_id": job_id,
                        "type": job.get("type"),
                        "channel": job.get("channel"),
                        "dry_run": bool(job.get("dry_run")),
                        "simulate": bool(job.get("simulate")),
                        "running": running,
                        "done": done,
                        "rc": job.get("rc"),
                        "stage": stage,
                        "progress": int(progress),
                        "output": tail,
                        "output_truncated": bool(job.get("output_truncated")),
                        "restart_check_output": job.get("restart_check_output"),
                        "log_path": job.get("log_path"),
                        "status_path": job.get("status_path"),
                    }, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"job lookup failed: {e}"}, origin)

        # --- System update (Rocket) preview ---
        if path == "/api/system/dup/preview":
            eff, _warnings, _invalid = _read_conf(self.server.conf_path)
            extra_flags = _parse_extra_flags(str(eff.get("DUP_EXTRA_FLAGS", "") or ""))

            # Rocket-specific vendor policy (does not affect background downloader/notifier).
            allow_vendor_change = False
            try:
                allow_vendor_change = str(eff.get("ROCKET_WIZARD_ALLOW_VENDOR_CHANGE", "false") or "false").strip().lower() == "true"
            except Exception:
                allow_vendor_change = False
            if allow_vendor_change and "--allow-vendor-change" not in extra_flags:
                extra_flags = ["--allow-vendor-change"] + list(extra_flags)

            # Better lock handling: if zypper/YaST is running, wait a bit instead of failing instantly.
            # Controlled via /etc/zypper-auto.conf (and WebUI Settings).
            lock_wait_s = 180
            try:
                lock_wait_s = int(str(eff.get("ROCKET_WIZARD_PREVIEW_LOCK_WAIT_SECONDS", "180") or "180").strip() or "180")
            except Exception:
                lock_wait_s = 180
            if lock_wait_s < 0:
                lock_wait_s = 0
            if lock_wait_s > 600:
                lock_wait_s = 600

            if lock_wait_s <= 0:
                waited_s, lock_file, lock_pid, timed_out = 0, "", "", False
            else:
                waited_s, lock_file, lock_pid, timed_out = _wait_for_zypp_lock(float(lock_wait_s), step_s=5.0)
            preface = ""
            if waited_s > 0:
                who = f"pid={lock_pid}" if lock_pid else "(unknown pid)"
                preface = f"[webui] Waiting for zypp lock: {lock_file} {who} (waited {waited_s}s)\n"
            if timed_out:
                msg = preface + "[webui] ERROR: zypp lock still active. Please close YaST/zypper and try again.\n"
                return _json_response(self, 200, {
                    "ok": False,
                    "rc": 1,
                    "output": msg,
                    "cmd": "(preview blocked by zypp lock)",
                    "used_systemd_run": True,
                    "zypp_lock_waited_seconds": waited_s,
                    "zypp_lock_file": lock_file,
                    "zypp_lock_pid": lock_pid,
                    "zypp_lock_timed_out": True,
                    "conflict_detected": False,
                    "conflict_summary": "",
                }, origin)

            cmd = [ZYPPER_BIN, "--non-interactive", "dup", "--dry-run", "--details"] + extra_flags

            # Prefer running via systemd-run so the zypper process is not confined
            # by this API service's sandbox (ProtectSystem=strict).
            unit = f"znh-webui-dup-preview-{secrets.token_hex(4)}"
            sys_cmd = ["systemd-run", "--quiet", "--wait", "--pipe", "--collect", "--unit", unit, "--"] + cmd

            used_systemd_run = True
            rc, out = _run_cmd(sys_cmd, timeout_s=240, log=getattr(self.server, "_znh_log", None))

            # Some systems appear to have issues with `systemd-run --pipe` (or transient unit start)
            # and may error with strings like:
            #   "Failed to start transient service unit: Connection reset by peer"
            # In that case, retry without --pipe and capture output via StandardOutput to a log file.
            if rc != 0:
                lower = (out or "").lower()
                if (
                    "failed to start transient service unit" in lower
                    or "connection reset by peer" in lower
                    or "failed to connect to bus" in lower
                ):
                    preview_log = f"/var/log/zypper-auto/service-logs/webui-dup-preview-{secrets.token_hex(4)}.log"
                    unit2 = f"znh-webui-dup-preview2-{secrets.token_hex(4)}"
                    sys_cmd2 = [
                        "systemd-run",
                        "--quiet",
                        "--wait",
                        "--collect",
                        "--unit",
                        unit2,
                        "--property",
                        f"StandardOutput=append:{preview_log}",
                        "--property",
                        f"StandardError=append:{preview_log}",
                        "--",
                    ] + cmd
                    rc2, out2 = _run_cmd(sys_cmd2, timeout_s=240, log=getattr(self.server, "_znh_log", None))
                    # Prefer reading the captured log output (best-effort)
                    try:
                        with open(preview_log, "r", encoding="utf-8", errors="replace") as f:
                            out = f.read()
                    except Exception:
                        out = out2
                    rc = rc2

            if rc != 0 and ("systemd-run" in (out or "").lower() or "no such file" in (out or "").lower()):
                # Fallback: run directly (may fail under sandbox, but still best-effort).
                used_systemd_run = False
                rc, out = _run_cmd(cmd, timeout_s=240, log=getattr(self.server, "_znh_log", None))

            out_zypper = out or ""
            out_full = (preface or "") + out_zypper
            conflict_detected, conflict_summary = _detect_solver_conflict(out_full, rc)

            reboot_required = False
            try:
                reboot_required = bool(_reboot_required())
            except Exception:
                reboot_required = False

            # Keep dry-run cache in sync so the dashboard pending_count can't drift.
            # Only update the cache on successful previews.
            cache_updated = False
            try:
                if rc == 0:
                    _write_atomic_text(DRYRUN_OUTPUT_FILE, out_zypper)
                    cache_updated = True
            except Exception as e:
                try:
                    getattr(self.server, "_znh_log", lambda *_: None)("warn", f"Could not persist dry-run cache: {e}")
                except Exception:
                    pass

            # IMPORTANT: Always return HTTP 200 so the WebUI can display the full zypper output,
            # even when zypper returns a non-zero rc (lock/conflict/manual decision/etc.).
            return _json_response(self, 200, {
                "ok": (rc == 0),
                "rc": rc,
                "output": out_full,
                "cmd": " ".join(cmd),
                "used_systemd_run": used_systemd_run,
                "zypp_lock_waited_seconds": waited_s,
                "zypp_lock_file": lock_file,
                "zypp_lock_pid": lock_pid,
                "zypp_lock_timed_out": False,
                "conflict_detected": bool(conflict_detected),
                "conflict_summary": conflict_summary,
                "reboot_required": bool(reboot_required),
                "cache_updated": bool(cache_updated),
            }, origin)

        # --- System update (Rocket) job status ---
        if path == "/api/system/dup/job":
            job_id = ""
            try:
                job_id = str((qs.get("job_id") or [""])[0]).strip()
            except Exception:
                job_id = ""
            if not job_id:
                return _json_response(self, 400, {"error": "job_id required"}, origin)

            now_ts = time.time()
            try:
                lock = getattr(self.server, "jobs_lock", None)
                jobs = getattr(self.server, "jobs", {})
                if lock:
                    with lock:
                        # purge old jobs
                        dead = []
                        for k, j in jobs.items():
                            if not isinstance(j, dict):
                                dead.append(k)
                                continue
                            if j.get("done") and (now_ts - float(j.get("finished_at", 0))) > JOB_TTL_SECONDS:
                                dead.append(k)
                        for k in dead:
                            jobs.pop(k, None)

                        job = jobs.get(job_id)
                        if not job:
                            recovered = _recover_system_dup_job(job_id)
                            if recovered:
                                return _json_response(self, 200, recovered, origin)
                            return _json_response(self, 404, {"error": "job not found"}, origin)
                        out = str(job.get("output", ""))
                        tail_raw = out[-JOB_OUTPUT_TAIL_CHARS:] if len(out) > JOB_OUTPUT_TAIL_CHARS else out
                        tail = _zypper_xml_pretty(tail_raw)
                        return _json_response(self, 200, {
                            "job_id": job_id,
                            "type": job.get("type"),
                            "simulate": bool(job.get("simulate")),
                            "running": bool(job.get("running")),
                            "done": bool(job.get("done")),
                            "rc": job.get("rc"),
                            "stage": job.get("stage"),
                            "progress": int(job.get("progress") or 0),
                            "output": tail,
                            "output_truncated": bool(job.get("output_truncated")),
                            "restart_check_output": job.get("restart_check_output"),
                            "conflict_detected": bool(job.get("conflict_detected")),
                            "conflict_summary": str(job.get("conflict_summary") or ""),
                        }, origin)
                else:
                    job = jobs.get(job_id)
                    if not job:
                        recovered = _recover_system_dup_job(job_id)
                        if recovered:
                            return _json_response(self, 200, recovered, origin)
                        return _json_response(self, 404, {"error": "job not found"}, origin)
                    out = str(job.get("output", ""))
                    tail_raw = out[-JOB_OUTPUT_TAIL_CHARS:] if len(out) > JOB_OUTPUT_TAIL_CHARS else out
                    tail = _zypper_xml_pretty(tail_raw)
                    return _json_response(self, 200, {
                        "job_id": job_id,
                        "type": job.get("type"),
                        "simulate": bool(job.get("simulate")),
                        "running": bool(job.get("running")),
                        "done": bool(job.get("done")),
                        "rc": job.get("rc"),
                        "stage": job.get("stage"),
                        "progress": int(job.get("progress") or 0),
                        "output": tail,
                        "output_truncated": bool(job.get("output_truncated")),
                        "restart_check_output": job.get("restart_check_output"),
                        "conflict_detected": bool(job.get("conflict_detected")),
                        "conflict_summary": str(job.get("conflict_summary") or ""),
                    }, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"job lookup failed: {e}"}, origin)

        # --- scrub-ghost job status ---
        if path == "/api/scrub/job":
            job_id = ""
            try:
                job_id = str((qs.get("job_id") or [""])[0]).strip()
            except Exception:
                job_id = ""
            if not job_id:
                return _json_response(self, 400, {"error": "job_id required"}, origin)

            recovered = _recover_scrub_job(job_id)
            if recovered:
                return _json_response(self, 200, recovered, origin)
            return _json_response(self, 404, {"error": "job not found"}, origin)

        # --- Quick Actions job status ---
        if path == "/api/quick/job":
            job_id = ""
            try:
                job_id = str((qs.get("job_id") or [""])[0]).strip()
            except Exception:
                job_id = ""
            if not job_id:
                return _json_response(self, 400, {"error": "job_id required"}, origin)

            recovered = _recover_quick_job(job_id)
            if recovered:
                return _json_response(self, 200, recovered, origin)
            return _json_response(self, 404, {"error": "job not found"}, origin)

        # --- Diagnostics log follower status (dashboard) ---
        if path == "/api/diag-logs/status":
            unit = "zypper-auto-diag-logs.service"
            active = False
            enabled = False
            try:
                rc, _out = _run_cmd(["systemctl", "is-active", unit], timeout_s=2, log=None)
                active = (rc == 0)
            except Exception:
                active = False
            try:
                rc2, _out2 = _run_cmd(["systemctl", "is-enabled", unit], timeout_s=2, log=None)
                enabled = (rc2 == 0)
            except Exception:
                enabled = False
            return _json_response(self, 200, {
                "unit": unit,
                "active": bool(active),
                "enabled": bool(enabled),
            }, origin)

        # If we got here and the path is under an auth-required prefix, it's not implemented.
        if path.startswith("/api/snapper/") or path.startswith("/api/self-update/") or path.startswith("/api/system/") or path.startswith("/api/scrub/") or path.startswith("/api/quick/") or path.startswith("/api/diag-logs/"):
            return _json_response(self, 404, {"error": "not found"}, origin)

        if path == "/api/ping":
            # Unauthenticated health probe used by auto-repair to detect
            # whether the running service has been restarted after upgrades.
            return _json_response(self, 200, {
                "ok": True,
                "ts": time.time(),
                "features": {
                    "dashboard_refresh": True,
                    "snapper": True,
                    "settings": True,
                    "quick_actions": True,
                },
            }, origin)

        if path == "/api/schema":
            return _json_response(self, 200, {"schema": SCHEMA}, origin)
        if path == "/api/config":
            eff, warnings, invalid = _read_conf(self.server.conf_path)
            return _json_response(self, 200, {"config": eff, "warnings": warnings, "invalid_keys": invalid}, origin)
        return _json_response(self, 404, {"error": "not found"}, origin)

    def do_POST(self):
        origin = _allowed_origin(self.headers.get("Origin"))
        path = urlparse(self.path).path
        try:
            getattr(self.server, "_znh_log", lambda *_: None)("info", f"POST {path} from {self.client_address[0]}")
        except Exception:
            pass
        if not self._auth_ok():
            try:
                getattr(self.server, "_znh_log", lambda *_: None)("warn", f"Unauthorized POST {path} from {self.client_address[0]}")
            except Exception:
                pass
            return _json_response(self, 401, {"error": "unauthorized"}, origin)

        # Thread-safety: token cache is accessed concurrently.
        tokens_lock = getattr(self.server, "tokens_lock", None)
        if tokens_lock is None:
            # Fallback for older/misconfigured servers.
            self.server.tokens_lock = threading.Lock()
            tokens_lock = self.server.tokens_lock

        # --- Dashboard maintenance (safe) ---
        if path == "/api/dashboard/refresh":
            # Regenerate the root dashboard artifacts. The user's dashboard copy
            # will be kept in sync by the dashboard sync worker started by --dash-open.
            cmd = ["/usr/local/bin/zypper-auto-helper", "--dashboard"]
            rc, out = _run_cmd(cmd, timeout_s=120, log=getattr(self.server, "_znh_log", None))
            return _json_response(self, 200 if rc == 0 else 500, {"rc": rc, "output": out}, origin)

        # --- Confirmation token cache (shared) ---
        def _confirm_purge(now_ts: float):
            try:
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    dead = []
                    # Iterate over a snapshot to avoid "dict changed size" even if a
                    # future refactor accidentally mutates during iteration.
                    for k, v in list(items.items()):
                        if float(v.get("exp", 0)) < now_ts:
                            dead.append(k)
                    for k in dead:
                        items.pop(k, None)
            except Exception:
                return

        # --- Quick Actions control (dashboard) ---
        if path == "/api/quick/confirm":
            body = _read_json(self)
            action = str(body.get("action", "") or "").strip()
            tbl = _quick_action_table()
            meta = tbl.get(action)
            if not meta:
                return _json_response(self, 400, {"error": f"unsupported action: {action}"}, origin)

            if not bool(meta.get("needs_confirm")):
                return _json_response(self, 400, {"error": "confirmation not required"}, origin)

            now_ts = time.time()
            _confirm_purge(now_ts)

            token = secrets.token_urlsafe(24)
            exp = now_ts + 120.0
            phrase = str(meta.get("phrase", "") or "").strip().upper()
            if not phrase:
                phrase = "CONFIRM"

            try:
                with tokens_lock:
                    if not hasattr(self.server, "confirm_tokens"):
                        self.server.confirm_tokens = {}
                    self.server.confirm_tokens[token] = {
                        "action": "quick",
                        "quick_action": action,
                        "exp": exp,
                        "phrase": phrase,
                    }
            except Exception:
                return _json_response(self, 500, {"error": "failed to store confirm token"}, origin)

            title = str(meta.get("title", action) or action)
            hint = f"Type {phrase} to confirm: {title}"

            explain = str(meta.get("explain", "") or meta.get("description", "") or "").strip()
            warn = str(meta.get("warning", "") or meta.get("warn", "") or "").strip()

            cmd_preview = ""
            try:
                cmd_preview = " ".join(shlex.quote(str(x)) for x in (meta.get("cmd") or []))
            except Exception:
                cmd_preview = ""

            timeout_s = 0
            try:
                timeout_s = int(meta.get("timeout_s", 0) or 0)
            except Exception:
                timeout_s = 0

            return _json_response(self, 200, {
                "confirm_token": token,
                "expires_in_seconds": 120,
                "phrase": phrase,
                "hint": hint,
                "title": title,
                "explain": explain,
                "warning": warn,
                "timeout_s": timeout_s,
                "cmd_preview": cmd_preview,
            }, origin)

        if path == "/api/quick/start":
            # Best-effort concurrency guard: avoid clobbering the single-task bubble UX.
            try:
                ri = _quick_any_running()
                if ri.get("running"):
                    return _json_response(self, 409, {
                        "error": "a quick action is already running",
                        "job_running": True,
                        "unit": ri.get("unit"),
                        "status_path": ri.get("status_path"),
                        "action": ri.get("action"),
                        "title": ri.get("title"),
                    }, origin)
            except Exception:
                pass

            body = _read_json(self)
            action = str(body.get("action", "") or "").strip()

            tbl = _quick_action_table()
            meta = tbl.get(action)
            if not meta:
                return _json_response(self, 400, {"error": f"unsupported action: {action}"}, origin)

            cmd = meta.get("cmd")
            if not isinstance(cmd, list) or not cmd:
                return _json_response(self, 500, {"error": "invalid action command"}, origin)

            # Some helper actions expect to be invoked via sudo and use SUDO_USER.
            # The API service can store the desktop user identity via its EnvironmentFile.
            dash_user = str(os.environ.get("DASH_API_USER", "") or "").strip()
            dash_home = str(os.environ.get("DASH_API_USER_HOME", "") or "").strip()
            needs_dash_user_env = bool(meta.get("needs_dash_user_env"))
            if needs_dash_user_env and not dash_user:
                return _json_response(self, 400, {"error": "dashboard API missing DASH_API_USER; re-open dashboard via --dash-open"}, origin)

            title = str(meta.get("title", action) or action)

            needs_confirm = bool(meta.get("needs_confirm"))
            required_phrase = str(meta.get("phrase", "") or "").strip().upper()

            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip().upper()

            if needs_confirm:
                now_ts = time.time()
                _confirm_purge(now_ts)
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    m = items.get(confirm_token)
                    if not m:
                        return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                    if m.get("action") != "quick":
                        return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                    if m.get("quick_action") != action:
                        return _json_response(self, 400, {"error": "confirm token does not match quick action"}, origin)
                    if float(m.get("exp", 0)) < now_ts:
                        return _json_response(self, 400, {"error": "confirm token expired"}, origin)

                    exp_phrase = str(m.get("phrase", "") or "").strip().upper()
                    if exp_phrase and confirm_phrase != exp_phrase:
                        return _json_response(self, 400, {"error": "confirmation phrase incorrect"}, origin)
                    if required_phrase and confirm_phrase != required_phrase:
                        return _json_response(self, 400, {"error": "confirmation phrase incorrect"}, origin)

                    # One-time token.
                    try:
                        items.pop(confirm_token, None)
                    except Exception:
                        pass

            timeout_s = 300
            try:
                timeout_s = int(meta.get("timeout_s", 300))
            except Exception:
                timeout_s = 300
            if timeout_s < 10:
                timeout_s = 10
            if timeout_s > 2 * 3600:
                timeout_s = 2 * 3600

            job_id = secrets.token_urlsafe(18)
            unit, log_path, status_path, script_file = _quick_paths(job_id)

            # Precreate log + status so the first poll can't race before the unit writes anything.
            try:
                os.makedirs(QUICK_LOG_DIR, exist_ok=True)
                os.makedirs(QUICK_STATUS_DIR, exist_ok=True)
                with open(log_path, "a", encoding="utf-8"):
                    pass
                with open(status_path, "w", encoding="utf-8") as f:
                    f.write("done=0\n")
                    f.write("rc=0\n")
                    f.write("stage=starting\n")
                    f.write(f"action={action}\n")
                    f.write(f"title={title}\n")
            except Exception:
                pass

            # Compose a shell script for the transient unit.
            cmd_str = " ".join(shlex.quote(str(x)) for x in cmd)

            inject_user = ""
            try:
                if needs_dash_user_env and dash_user:
                    # Inject SUDO_USER so helper subcommands that expect sudo still work.
                    # SUDO_USER_HOME is optional but improves behavior for a few paths.
                    inject_user = "\n".join([
                        f'export SUDO_USER={shlex.quote(dash_user)}',
                        f'export SUDO_USER_HOME={shlex.quote(dash_home)}' if dash_home else 'true',
                    ])
            except Exception:
                inject_user = ""

            script_text = "\n".join([
                'set -euo pipefail',
                f'LOG={shlex.quote(log_path)}',
                f'STATUS={shlex.quote(status_path)}',
                f'ACTION={shlex.quote(action)}',
                f'TITLE={shlex.quote(title)}',
                f'TIMEOUT_S={timeout_s}',
                'mkdir -p /var/log/zypper-auto/service-logs || true',
                'mkdir -p /var/lib/zypper-auto || true',
                'STARTED_AT="$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                'write_status() {',
                '  local done="$1"; local rc="$2"; local stage="$3"',
                '  local tmp="${STATUS}.tmp.$$"',
                '  {',
                '    echo "done=${done}"',
                '    echo "rc=${rc}"',
                '    echo "stage=${stage}"',
                '    echo "action=${ACTION:-}"',
                '    echo "title=${TITLE:-}"',
                '    echo "started_at_utc=${STARTED_AT}"',
                '    echo "updated_at_utc=$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                '  } >"${tmp}" 2>/dev/null || true',
                '  mv -f "${tmp}" "${STATUS}" 2>/dev/null || true',
                '}',
                'write_status 0 0 starting',
                'echo "==========================================" >>"$LOG" || true',
                'echo " WebUI Quick Action job " >>"$LOG" || true',
                'echo "==========================================" >>"$LOG" || true',
                'date >>"$LOG" 2>/dev/null || true',
                'echo "" >>"$LOG" || true',
                'echo "ACTION: ${ACTION}" >>"$LOG" || true',
                'echo "TITLE : ${TITLE}" >>"$LOG" || true',
                f'echo "CMD   : {cmd_str}" >>"$LOG" || true',
                'echo "" >>"$LOG" || true',
                'export ZNH_NON_INTERACTIVE=1',
                inject_user if inject_user else 'true',
                'write_status 0 0 running',
                'set +e',
                f'( timeout "${{TIMEOUT_S}}" {cmd_str} ) 2>&1 | tee -a "$LOG"',
                'rc=${PIPESTATUS[0]}',
                'set -e',
                'echo "" >>"$LOG" || true',
                'echo "[webui] quick action rc=${rc}" >>"$LOG" || true',
                'if [ ${rc} -eq 124 ] 2>/dev/null; then',
                '  write_status 1 ${rc} timed-out',
                '  echo "[webui] ERROR: timed out" >>"$LOG" || true',
                '  rm -f "$0" >/dev/null 2>&1 || true',
                '  exit ${rc}',
                'fi',
                'if [ ${rc} -eq 0 ]; then',
                '  write_status 1 ${rc} done',
                'else',
                '  write_status 1 ${rc} failed',
                'fi',
                'rm -f "$0" >/dev/null 2>&1 || true',
                'exit ${rc}',
            ])

            # Write unit script to disk (inside the API service sandbox).
            try:
                os.makedirs(QUICK_STATUS_DIR, exist_ok=True)
                with open(script_file, "w", encoding="utf-8") as f:
                    f.write("#!/usr/bin/env bash\n")
                    f.write(script_text)
                    f.write("\n")
                os.chmod(script_file, 0o700)
            except Exception as e:
                return _json_response(self, 500, {"error": f"failed to write quick-action unit script: {e}"}, origin)

            sys_cmd = [
                "systemd-run",
                "--quiet",
                "--collect",
                "--unit",
                unit,
                "--",
                "/usr/bin/bash",
                script_file,
            ]

            try:
                p = subprocess.run(
                    sys_cmd,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=15,
                )
                if p.returncode != 0:
                    out = (p.stdout or "").strip()
                    return _json_response(self, 500, {"error": f"systemd-run failed rc={p.returncode}", "output": out}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"systemd-run exception: {e}"}, origin)

            return _json_response(self, 200, {"job_id": job_id}, origin)

        # --- Self-update control (dashboard) ---
        if path == "/api/self-update/confirm":
            # Safety: do not allow a second confirm flow while an update is already running.
            try:
                ri = _self_update_any_running()
                if ri.get("running"):
                    return _json_response(self, 409, {"error": "self-update already running", "job_running": True, "unit": ri.get("unit"), "status_path": ri.get("status_path")}, origin)
            except Exception:
                pass

            # Guard: do not allow self-update if the helper looks OS-managed.
            try:
                helper_real = os.path.realpath(HELPER_BIN)
            except Exception:
                helper_real = HELPER_BIN
            if not str(helper_real).startswith("/usr/local/bin/"):
                return _json_response(self, 400, {
                    "error": "self-update disabled (externally managed install)",
                    "is_externally_managed": True,
                    "helper_path": helper_real,
                }, origin)

            body = _read_json(self)
            ch = str(body.get("channel", "") or "").strip().lower()
            if ch not in ("stable", "rolling"):
                ch = "stable"

            now_ts = time.time()
            _confirm_purge(now_ts)

            token = secrets.token_urlsafe(24)
            exp = now_ts + 120.0
            try:
                with tokens_lock:
                    if not hasattr(self.server, "confirm_tokens"):
                        self.server.confirm_tokens = {}
                    self.server.confirm_tokens[token] = {
                        "action": "self-update",
                        "channel": ch,
                        "exp": exp,
                    }
            except Exception:
                return _json_response(self, 500, {"error": "failed to store confirm token"}, origin)

            return _json_response(self, 200, {
                "confirm_token": token,
                "expires_in_seconds": 120,
                "phrase": "UPDATE",
                "hint": "Type UPDATE to confirm self-update (downloads code and replaces /usr/local/bin/zypper-auto-helper).",
            }, origin)

        if path == "/api/self-update/start":
            # Safety: prevent concurrent self-update jobs.
            try:
                ri = _self_update_any_running()
                if ri.get("running"):
                    return _json_response(self, 409, {"error": "self-update already running", "job_running": True, "unit": ri.get("unit"), "status_path": ri.get("status_path")}, origin)
            except Exception:
                pass

            # Guard: do not allow self-update if the helper looks OS-managed.
            try:
                helper_real = os.path.realpath(HELPER_BIN)
            except Exception:
                helper_real = HELPER_BIN
            if not str(helper_real).startswith("/usr/local/bin/"):
                return _json_response(self, 400, {
                    "error": "self-update disabled (externally managed install)",
                    "is_externally_managed": True,
                    "helper_path": helper_real,
                }, origin)

            body = _read_json(self)
            ch = str(body.get("channel", "") or "").strip().lower()
            if ch not in ("stable", "rolling"):
                ch = "stable"

            dry_run = bool(body.get("dry_run", False))
            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip().upper()

            post_action = str(body.get("post_action", "none") or "none").strip().lower()
            if post_action not in ("none", "verify", "install"):
                post_action = "none"
            if dry_run:
                post_action = "none"

            now_ts = time.time()
            _confirm_purge(now_ts)
            with tokens_lock:
                items = getattr(self.server, "confirm_tokens", {})
                meta = items.get(confirm_token)
                if not meta:
                    return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                if meta.get("action") != "self-update":
                    return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                if meta.get("channel") != ch:
                    return _json_response(self, 400, {"error": "confirm token does not match channel"}, origin)
                if float(meta.get("exp", 0)) < now_ts:
                    return _json_response(self, 400, {"error": "confirm token expired"}, origin)
                if confirm_phrase != "UPDATE":
                    return _json_response(self, 400, {"error": "confirmation phrase incorrect"}, origin)

                # One-time token.
                try:
                    items.pop(confirm_token, None)
                except Exception:
                    pass

            # Run self-update via systemd-run so it is not confined by this API service's sandbox
            # and so the job survives dashboard API restarts.
            job_id = secrets.token_urlsafe(18)
            unit, log_path, status_path, script_file = _su_paths(job_id)

            # Precreate log + status so the first poll can't race before the unit writes anything.
            try:
                os.makedirs("/var/log/zypper-auto/service-logs", exist_ok=True)
                os.makedirs("/var/lib/zypper-auto", exist_ok=True)
                with open(log_path, "a", encoding="utf-8"):
                    pass
                with open(status_path, "w", encoding="utf-8") as f:
                    f.write(f"done=0\n")
                    f.write(f"rc=0\n")
                    f.write(f"update_rc=0\n")
                    f.write(f"post_action={post_action}\n")
                    f.write(f"post_action_rc=0\n")
                    f.write(f"stage=starting\n")
                    f.write(f"channel={ch}\n")
                    f.write(f"dry_run={1 if dry_run else 0}\n")
            except Exception:
                pass

            su_cmd = f"{HELPER_BIN} --self-update {ch}".strip()
            if dry_run:
                su_cmd = (su_cmd + " --dry-run").strip()

            script_text = "\n".join([
                'set -euo pipefail',
                f'LOG={shlex.quote(log_path)}',
                f'STATUS={shlex.quote(status_path)}',
                f'CHANNEL={shlex.quote(ch)}',
                f'DRY_RUN={"1" if dry_run else "0"}',
                f'POST_ACTION={shlex.quote(post_action)}',
                'mkdir -p /var/log/zypper-auto/service-logs || true',
                'mkdir -p /var/lib/zypper-auto || true',
                'STARTED_AT="$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                'UPDATE_RC=0',
                'POST_ACTION_RC=0',
                'write_status() {',
                '  local done="$1"; local rc="$2"; local stage="$3"',
                '  local tmp="${STATUS}.tmp.$$"',
                '  {',
                '    echo "done=${done}"',
                '    echo "rc=${rc}"',
                '    echo "update_rc=${UPDATE_RC:-0}"',
                '    echo "post_action=${POST_ACTION:-none}"',
                '    echo "post_action_rc=${POST_ACTION_RC:-0}"',
                '    echo "stage=${stage}"',
                '    echo "channel=${CHANNEL:-}"',
                '    echo "dry_run=${DRY_RUN:-0}"',
                '    echo "started_at_utc=${STARTED_AT}"',
                '    echo "updated_at_utc=$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                '  } >"${tmp}" 2>/dev/null || true',
                '  mv -f "${tmp}" "${STATUS}" 2>/dev/null || true',
                '}',
                'write_status 0 0 starting',
                'echo "==========================================" >>"$LOG" || true',
                'echo " WebUI self-update job " >>"$LOG" || true',
                'echo "==========================================" >>"$LOG" || true',
                'date >>"$LOG" 2>/dev/null || true',
                'echo "" >>"$LOG" || true',
                f'echo "CMD: {su_cmd}" >>"$LOG" || true',
                'echo "" >>"$LOG" || true',
                f'echo "POST_ACTION: {post_action}" >>"$LOG" || true',
                'echo "" >>"$LOG" || true',
                'export ZNH_SELF_UPDATE_NO_UI=1',
                'export ZNH_NON_INTERACTIVE=1',
                'write_status 0 0 running',
                'set +e',
                f'( {su_cmd} ) 2>&1 | tee -a "$LOG"',
                'rc=${PIPESTATUS[0]}',
                'set -e',
                'UPDATE_RC=${rc}',
                'echo "" >>"$LOG" || true',
                'echo "[webui] self-update rc=$rc" >>"$LOG" || true',
                'if [ ${rc} -eq 0 ] && [ "${DRY_RUN:-0}" != "1" ]; then',
                '  write_status 0 ${rc} refreshing-dashboard',
                f'  ( {HELPER_BIN} --dashboard ) >>"$LOG" 2>&1 || echo "[WARN] dashboard refresh failed (continuing)" >>"$LOG" || true',
                '  if [ "${POST_ACTION:-none}" = "verify" ]; then',
                '    write_status 0 ${rc} post-verify',
                '    set +e',
                f'    ( {HELPER_BIN} --verify ) >>"$LOG" 2>&1',
                '    POST_ACTION_RC=$?',
                '    set -e',
                '    echo "[webui] post-verify rc=${POST_ACTION_RC}" >>"$LOG" || true',
                '    if [ "${POST_ACTION_RC}" -ne 0 ] 2>/dev/null; then echo "[webui] WARNING: verify reported issues (rc=${POST_ACTION_RC})" >>"$LOG" || true; fi',
                '  elif [ "${POST_ACTION:-none}" = "install" ]; then',
                '    write_status 0 ${rc} post-install',
                '    set +e',
                f'    ( {HELPER_BIN} install ) >>"$LOG" 2>&1',
                '    POST_ACTION_RC=$?',
                '    set -e',
                '    echo "[webui] post-install rc=${POST_ACTION_RC}" >>"$LOG" || true',
                '    if [ "${POST_ACTION_RC}" -ne 0 ] 2>/dev/null; then rc=${POST_ACTION_RC}; fi',
                '  fi',
                'fi',
                'if [ ${rc} -eq 0 ]; then',
                '  if [ "${DRY_RUN:-0}" = "1" ]; then write_status 1 ${rc} dry-run-done; else write_status 1 ${rc} done; fi',
                'else',
                '  write_status 1 ${rc} failed',
                'fi',
                'rm -f "$0" >/dev/null 2>&1 || true',
                'exit ${rc}',
            ])

            # Write unit script to disk (inside the API service sandbox).
            try:
                os.makedirs("/var/lib/zypper-auto", exist_ok=True)
                with open(script_file, "w", encoding="utf-8") as f:
                    f.write("#!/usr/bin/env bash\n")
                    f.write(script_text)
                    f.write("\n")
                os.chmod(script_file, 0o700)
            except Exception as e:
                return _json_response(self, 500, {"error": f"failed to write self-update unit script: {e}"}, origin)

            sys_cmd = [
                "systemd-run",
                "--quiet",
                "--collect",
                "--unit",
                unit,
                "--property",
                "After=network-online.target",
                "--property",
                "Wants=network-online.target",
                "--",
                "/usr/bin/bash",
                script_file,
            ]

            try:
                p = subprocess.run(
                    sys_cmd,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=15,
                )
                if p.returncode != 0:
                    out = (p.stdout or "").strip()
                    return _json_response(self, 500, {"error": f"systemd-run failed rc={p.returncode}", "output": out}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"systemd-run exception: {e}"}, origin)

            return _json_response(self, 200, {"job_id": job_id}, origin)

        # Backward-compatible synchronous endpoint (no live progress; returns full output).
        if path == "/api/self-update/run":
            # Guard: do not allow self-update if the helper looks OS-managed.
            try:
                helper_real = os.path.realpath(HELPER_BIN)
            except Exception:
                helper_real = HELPER_BIN
            if not str(helper_real).startswith("/usr/local/bin/"):
                return _json_response(self, 400, {
                    "error": "self-update disabled (externally managed install)",
                    "is_externally_managed": True,
                    "helper_path": helper_real,
                }, origin)

            body = _read_json(self)
            ch = str(body.get("channel", "") or "").strip().lower()
            if ch not in ("stable", "rolling"):
                ch = "stable"

            dry_run = bool(body.get("dry_run", False))
            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip().upper()

            now_ts = time.time()
            _confirm_purge(now_ts)
            with tokens_lock:
                items = getattr(self.server, "confirm_tokens", {})
                meta = items.get(confirm_token)
                if not meta:
                    return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                if meta.get("action") != "self-update":
                    return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                if meta.get("channel") != ch:
                    return _json_response(self, 400, {"error": "confirm token does not match channel"}, origin)
                if float(meta.get("exp", 0)) < now_ts:
                    return _json_response(self, 400, {"error": "confirm token expired"}, origin)
                if confirm_phrase != "UPDATE":
                    return _json_response(self, 400, {"error": "confirmation phrase incorrect"}, origin)

                # One-time token.
                try:
                    items.pop(confirm_token, None)
                except Exception:
                    pass

            cmd = [HELPER_BIN, "--self-update", ch]
            if dry_run:
                cmd.append("--dry-run")
            rc, out = _run_cmd(cmd, timeout_s=300, log=getattr(self.server, "_znh_log", None), extra_env={"ZNH_SELF_UPDATE_NO_UI": "1"})

            # Best-effort: regenerate dashboard after updating.
            dash_rc = -1
            if rc == 0 and not dry_run:
                dash_rc, _dash_out = _run_cmd([HELPER_BIN, "--dashboard"], timeout_s=120, log=getattr(self.server, "_znh_log", None))

            return _json_response(self, 200 if rc == 0 else 500, {
                "rc": rc,
                "output": out,
                "dashboard_refresh_rc": dash_rc,
                "dry_run": dry_run,
            }, origin)

        # --- System update (Rocket) control ---
        if path == "/api/system/dup/confirm":
            now_ts = time.time()
            _confirm_purge(now_ts)

            token = secrets.token_urlsafe(24)
            exp = now_ts + 120.0
            try:
                with tokens_lock:
                    if not hasattr(self.server, "confirm_tokens"):
                        self.server.confirm_tokens = {}
                    self.server.confirm_tokens[token] = {
                        "action": "system-dup",
                        "exp": exp,
                    }
            except Exception:
                return _json_response(self, 500, {"error": "failed to store confirm token"}, origin)

            return _json_response(self, 200, {
                "confirm_token": token,
                "expires_in_seconds": 120,
                "phrase": "INSTALL",
                "hint": "Type INSTALL to confirm installing system updates (runs zypper dup).",
            }, origin)

        if path == "/api/system/dup/start":
            body = _read_json(self)
            simulate = bool(body.get("simulate", False))
            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip().upper()

            now_ts = time.time()
            _confirm_purge(now_ts)
            with tokens_lock:
                items = getattr(self.server, "confirm_tokens", {})
                meta = items.get(confirm_token)
                if not meta:
                    return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                if meta.get("action") != "system-dup":
                    return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                if float(meta.get("exp", 0)) < now_ts:
                    return _json_response(self, 400, {"error": "confirm token expired"}, origin)
                if confirm_phrase != "INSTALL":
                    return _json_response(self, 400, {"error": "confirmation phrase incorrect"}, origin)

                # One-time token.
                try:
                    items.pop(confirm_token, None)
                except Exception:
                    pass

            # Compute dup flags from config at start time so the job is deterministic.
            eff, _warnings, _invalid = _read_conf(self.server.conf_path)
            extra_flags = _parse_extra_flags(str(eff.get("DUP_EXTRA_FLAGS", "") or ""))

            # Rocket defaults (UI pre-selected / allowed values)
            lock_wait_install_s = 1800
            try:
                lock_wait_install_s = int(str(eff.get("ROCKET_WIZARD_INSTALL_LOCK_WAIT_SECONDS", "1800") or "1800").strip() or "1800")
            except Exception:
                lock_wait_install_s = 1800
            if lock_wait_install_s < 0:
                lock_wait_install_s = 0
            if lock_wait_install_s > 7200:
                lock_wait_install_s = 7200

            use_xmlout = True
            try:
                use_xmlout = str(eff.get("ROCKET_WIZARD_USE_XMLOUT", "true") or "true").strip().lower() == "true"
            except Exception:
                use_xmlout = True

            force_resolution = False
            try:
                force_resolution = str(eff.get("ROCKET_WIZARD_FORCE_RESOLUTION", "false") or "false").strip().lower() == "true"
            except Exception:
                force_resolution = False

            if force_resolution and "--force-resolution" not in extra_flags:
                extra_flags = ["--force-resolution"] + list(extra_flags)

            # Rocket-specific vendor policy (does not affect background downloader/notifier).
            allow_vendor_change = False
            try:
                allow_vendor_change = str(eff.get("ROCKET_WIZARD_ALLOW_VENDOR_CHANGE", "false") or "false").strip().lower() == "true"
            except Exception:
                allow_vendor_change = False
            if allow_vendor_change and "--allow-vendor-change" not in extra_flags:
                extra_flags = ["--allow-vendor-change"] + list(extra_flags)

            job_id = secrets.token_urlsafe(18)
            unit = f"znh-webui-dup-{job_id[:8]}"
            log_path = f"/var/log/zypper-auto/service-logs/webui-dup-{job_id[:10]}.log"
            status_path = f"/var/lib/zypper-auto/webui-dup-{job_id[:10]}.status"

            # Precreate log + status so job recovery can't race before the unit writes anything.
            try:
                os.makedirs("/var/log/zypper-auto/service-logs", exist_ok=True)
                os.makedirs("/var/lib/zypper-auto", exist_ok=True)
                with open(log_path, "a", encoding="utf-8"):
                    pass
                with open(status_path, "w", encoding="utf-8") as f:
                    f.write("done=0\n")
                    f.write("rc=0\n")
                    f.write("stage=starting\n")
                    f.write(f"simulate={1 if simulate else 0}\n")
            except Exception:
                pass

            job = {
                "job_id": job_id,
                "type": "system-dup",
                "simulate": simulate,
                "running": True,
                "done": False,
                "rc": None,
                "stage": "Starting",
                "progress": 0,
                "output": "",
                "output_truncated": False,
                "started_at": now_ts,
                "finished_at": 0,
                "unit": unit,
                "log_path": log_path,
                "status_path": status_path,
                "restart_check_output": "",
                "conflict_detected": False,
                "conflict_summary": "",
            }

            lock = getattr(self.server, "jobs_lock", None)
            jobs = getattr(self.server, "jobs", None)
            if jobs is None:
                self.server.jobs = {}
                jobs = self.server.jobs
            if lock is None:
                self.server.jobs_lock = threading.Lock()
                lock = self.server.jobs_lock

            with lock:
                jobs[job_id] = job

            def worker():
                # Compose a shell script for the transient unit.
                # We run outside this API service's sandbox by using systemd-run.
                # IMPORTANT: write the script to disk (instead of passing a huge inline string
                # via argv) to avoid systemd-run / D-Bus message-size / argv-length issues on
                # some systems.
                # Output is written into /var/log/zypper-auto where the dashboard already reads.
                extra = " ".join(shlex.quote(x) for x in extra_flags)
                xml_flag = "--xmlout" if use_xmlout else ""
                if simulate:
                    zcmd = f"{ZYPPER_BIN} --non-interactive {xml_flag} dup --dry-run --details {extra}".strip()
                else:
                    zcmd = f"{ZYPPER_BIN} --non-interactive {xml_flag} dup -y --details {extra}".strip()

                script_text = "\n".join([
                    'set -euo pipefail',
                    f'LOG={shlex.quote(log_path)}',
                    f'STATUS={shlex.quote(status_path)}',
                    'mkdir -p /var/log/zypper-auto/service-logs || true',
                    'mkdir -p /var/lib/zypper-auto || true',
                    f'SIMULATE={"1" if simulate else "0"}',
                    'STARTED_AT="$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                    'write_status() {',
                    '  local done="$1"; local rc="$2"; local stage="$3"',
                    '  local tmp="${STATUS}.tmp.$$"',
                    '  {',
                    '    echo "done=${done}"',
                    '    echo "rc=${rc}"',
                    '    echo "stage=${stage}"',
                    '    echo "simulate=${SIMULATE:-0}"',
                    '    echo "started_at_utc=${STARTED_AT}"',
                    '    echo "updated_at_utc=$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                    '  } >"${tmp}" 2>/dev/null || true',
                    '  mv -f "${tmp}" "${STATUS}" 2>/dev/null || true',
                    '}',
                    'write_status 0 0 starting',

                    # Load config toggles for optional post-update refresh.
                    'CONFIG=/etc/zypper-auto.conf',
                    'ENABLE_FLATPAK_UPDATES="true"',
                    'ENABLE_SNAP_UPDATES="true"',
                    'ENABLE_SOAR_UPDATES="true"',
                    'ENABLE_BREW_UPDATES="true"',
                    'ENABLE_PIPX_UPDATES="true"',
                    'OPTIONAL_UPDATES_ALWAYS_REFRESH="false"',
                    'if [ -r "$CONFIG" ]; then . "$CONFIG"; fi',

                    # Best-effort: detect a non-root desktop user for user-scoped tools.
                    'RUN_USER=""',
                    "if command -v loginctl >/dev/null 2>&1; then RUN_USER=\"$(loginctl list-users --no-legend 2>/dev/null | awk '$1 != 0 {print $2; exit}')\"; fi",
                    'RUN_HOME=""',
                    'if [ -n "${RUN_USER}" ]; then RUN_HOME="$(getent passwd "${RUN_USER}" 2>/dev/null | cut -d: -f6)"; fi',
                    'USER_PATH="${RUN_HOME}/.local/bin:/home/linuxbrew/.linuxbrew/bin:/usr/local/bin:/usr/bin:/bin"',

                    'run_user_cmd() {',
                    '  if [ -n "${RUN_USER}" ] && command -v runuser >/dev/null 2>&1; then',
                    '    runuser -u "${RUN_USER}" -- env HOME="${RUN_HOME}" PATH="${USER_PATH}" "$@"',
                    '    return $?',
                    '  fi',
                    '  env PATH="${USER_PATH}" "$@"',
                    '}',

                    # Better lock handling (match CLI): wait for zypp lock instead of failing instantly.
                    'zypp_lock_file() {',
                    '  if [ -f /run/zypp.pid ]; then echo /run/zypp.pid; return 0; fi',
                    '  if [ -f /var/run/zypp.pid ]; then echo /var/run/zypp.pid; return 0; fi',
                    '  echo ""',
                    '  return 1',
                    '}',
                    'zypp_lock_active() {',
                    '  local lf pid',
                    '  lf="$(zypp_lock_file 2>/dev/null || true)"',
                    '  [ -z "${lf}" ] && return 1',
                    '  pid="$(cat "${lf}" 2>/dev/null || true)"',
                    '  if echo "${pid}" | grep -qE "^[0-9]+$" && kill -0 "${pid}" 2>/dev/null; then return 0; fi',
                    '  if command -v pgrep >/dev/null 2>&1 && pgrep -x zypper >/dev/null 2>&1; then return 0; fi',
                    '  return 1',
                    '}',
                    '# Smart lock waiting with exponential backoff and process identity',
                    'wait_for_zypp_lock_smart() {',
                    f'  local max_wait_seconds={lock_wait_install_s}',
                    '  if [ "${max_wait_seconds}" -le 0 ] 2>/dev/null; then return 0; fi',
                    '  local start_time current_time elapsed backoff attempt',
                    '  start_time="$(date +%s 2>/dev/null || echo 0)"',
                    '  attempt=1',
                    '  backoff=2',
                    '  while true; do',
                    '    if ! zypp_lock_active; then return 0; fi',
                    '    local lf pid owner',
                    '    lf="$(zypp_lock_file 2>/dev/null || true)"',
                    '    pid="$(cat "${lf}" 2>/dev/null || true)"',
                    '    owner=""',
                    '    if echo "${pid}" | grep -qE "^[0-9]+$"; then',
                    '      owner="$(ps -p "${pid}" -o comm= 2>/dev/null || echo "")"',
                    '    fi',
                    '    current_time="$(date +%s 2>/dev/null || echo 0)"',
                    '    elapsed=$((current_time - start_time))',
                    '    if [ "${elapsed}" -ge "${max_wait_seconds}" ] 2>/dev/null; then',
                    '      echo "[webui] ERROR: Timeout: Zypp lock held by PID ${pid:-unknown} (${owner:-Unknown}) for over ${max_wait_seconds}s." >>"$LOG" || true',
                    '      write_status 1 1 lock-timeout',
                    '      return 1',
                    '    fi',
                    '    echo "[webui] Zypp lock held by PID ${pid:-unknown} (${owner:-Unknown}). Attempt ${attempt}. Retrying in ${backoff}s..." >>"$LOG" || true',
                    '    write_status 0 0 waiting-for-lock',
                    '    sleep "${backoff}"',
                    '    backoff=$((backoff * 2))',
                    '    if [ "${backoff}" -gt 30 ] 2>/dev/null; then backoff=30; fi',
                    '    attempt=$((attempt + 1))',
                    '  done',
                    '}',
                    'wait_for_zypp_lock_smart || exit 1',

                    'echo "==========================================" >>"$LOG"',
                    'echo " Rocket Update Wizard: zypper dup " >>"$LOG"',
                    'echo "==========================================" >>"$LOG"',
                    'date >>"$LOG" || true',
                    'echo "" >>"$LOG"',
                    f'echo "CMD: {zcmd}" >>"$LOG"',
                    'echo "" >>"$LOG"',

                    # Run zypper and stream output live into $LOG.
                    # We also keep a temporary copy so we can detect "Nothing to do." reliably.
                    'TMP_OUT="$(mktemp /tmp/znh-webui-dup.XXXXXX 2>/dev/null || echo /tmp/znh-webui-dup.$$)"',
                    'set +e',
                    f'( {zcmd} ) 2>&1 | tee -a "$LOG" >"$TMP_OUT"',
                    'rc=$?',
                    'set -e',
                    'did_updates=1',
                    # With --xmlout, the phrase may appear inside XML message tags; be case-insensitive.
                    'if grep -qi "nothing to do" "$TMP_OUT" 2>/dev/null; then did_updates=0; fi',
                    'rm -f "$TMP_OUT" 2>/dev/null || true',
                    'echo "" >>"$LOG"',
                    'echo "[webui] zypper dup rc=$rc" >>"$LOG"',
                    'if [ ${rc} -eq 0 ]; then write_status 0 ${rc} running; else write_status 0 ${rc} failed; fi',
                    'if [ "${SIMULATE:-0}" = "1" ]; then echo "[webui] Simulation mode: skipping optional updates." >>"$LOG"; fi',
                    'if [ ${rc} -ne 0 ]; then echo "[webui] zypper dup failed; skipping optional updates." >>"$LOG"; fi',

                    # Optional app updates only run on real installs (not simulation) and only when
                    # updates occurred, unless OPTIONAL_UPDATES_ALWAYS_REFRESH=true.
                    'if [ ${rc} -eq 0 ] && [ "${SIMULATE:-0}" != "1" ]; then',
                    '  do_optional=0',
                    '  if [ "${OPTIONAL_UPDATES_ALWAYS_REFRESH,,}" = "true" ]; then do_optional=1; fi',
                    '  if [ ${did_updates} -eq 1 ]; then do_optional=1; fi',
                    '  if [ ${do_optional} -eq 1 ]; then',
                    '    echo "" >>"$LOG"',
                    '    if [ ${did_updates} -eq 1 ]; then echo "[webui] System updates were applied; running optional updates." >>"$LOG"; fi',
                    '    if [ ${did_updates} -eq 0 ] && [ "${OPTIONAL_UPDATES_ALWAYS_REFRESH,,}" = "true" ]; then echo "[webui] No system updates were applied, but OPTIONAL_UPDATES_ALWAYS_REFRESH=true so optional updates will run." >>"$LOG"; fi',
                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Optional Updates (Flatpak/Snap/Soar/Brew/pipx)" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    echo "RUN_USER=${RUN_USER:-unknown}" >>"$LOG"',
                    '    echo "" >>"$LOG"',

                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Flatpak Updates" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    if [ "${ENABLE_FLATPAK_UPDATES,,}" = "true" ]; then',
                    '      if command -v flatpak >/dev/null 2>&1; then',
                    '        run_user_cmd flatpak update -y >>"$LOG" 2>&1 || echo "[WARN] flatpak update failed (continuing)" >>"$LOG"',
                    '      else',
                    '        echo "[INFO] flatpak not installed; skipping" >>"$LOG"',
                    '      fi',
                    '    else',
                    '      echo "[INFO] Flatpak updates disabled (ENABLE_FLATPAK_UPDATES=false)" >>"$LOG"',
                    '    fi',
                    '    echo "" >>"$LOG"',

                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Snap Updates" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    if [ "${ENABLE_SNAP_UPDATES,,}" = "true" ]; then',
                    '      if command -v snap >/dev/null 2>&1; then',
                    '        snap refresh >>"$LOG" 2>&1 || echo "[WARN] snap refresh failed (continuing)" >>"$LOG"',
                    '      else',
                    '        echo "[INFO] snap not installed; skipping" >>"$LOG"',
                    '      fi',
                    '    else',
                    '      echo "[INFO] Snap updates disabled (ENABLE_SNAP_UPDATES=false)" >>"$LOG"',
                    '    fi',
                    '    echo "" >>"$LOG"',

                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Soar Updates (optional)" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    if [ "${ENABLE_SOAR_UPDATES,,}" = "true" ]; then',
                    '      if run_user_cmd bash -lc "command -v soar >/dev/null 2>&1"; then',
                    '        run_user_cmd bash -lc "soar sync" >>"$LOG" 2>&1 || echo "[WARN] soar sync failed (continuing)" >>"$LOG"',
                    '        run_user_cmd bash -lc "soar update" >>"$LOG" 2>&1 || echo "[WARN] soar update failed (continuing)" >>"$LOG"',
                    '      else',
                    '        echo "[INFO] soar not installed for user; skipping" >>"$LOG"',
                    '      fi',
                    '    else',
                    '      echo "[INFO] Soar updates disabled (ENABLE_SOAR_UPDATES=false)" >>"$LOG"',
                    '    fi',
                    '    echo "" >>"$LOG"',

                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Homebrew (brew) Updates (optional)" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    if [ "${ENABLE_BREW_UPDATES,,}" = "true" ]; then',
                    '      if run_user_cmd bash -lc "command -v brew >/dev/null 2>&1"; then',
                    '        run_user_cmd bash -lc "brew update" >>"$LOG" 2>&1 || echo "[WARN] brew update failed (continuing)" >>"$LOG"',
                    '        run_user_cmd bash -lc "if brew outdated --quiet 2>/dev/null | grep -q .; then echo brew: upgrading outdated formulae; brew upgrade; else echo brew: already up to date; fi" >>"$LOG" 2>&1 || echo "[WARN] brew upgrade step failed (continuing)" >>"$LOG"',
                    '      else',
                    '        echo "[INFO] brew not installed for user; skipping" >>"$LOG"',
                    '      fi',
                    '    else',
                    '      echo "[INFO] Homebrew updates disabled (ENABLE_BREW_UPDATES=false)" >>"$LOG"',
                    '    fi',
                    '    echo "" >>"$LOG"',

                    '    echo "==========================================" >>"$LOG"',
                    '    echo "  Python (pipx) Updates (optional)" >>"$LOG"',
                    '    echo "==========================================" >>"$LOG"',
                    '    if [ "${ENABLE_PIPX_UPDATES,,}" = "true" ]; then',
                    '      if run_user_cmd bash -lc "command -v pipx >/dev/null 2>&1"; then',
                    '        run_user_cmd bash -lc "pipx upgrade-all" >>"$LOG" 2>&1 || echo "[WARN] pipx upgrade-all failed (continuing)" >>"$LOG"',
                    '      else',
                    '        echo "[INFO] pipx not installed for user; skipping" >>"$LOG"',
                    '      fi',
                    '    else',
                    '      echo "[INFO] pipx updates disabled (ENABLE_PIPX_UPDATES=false)" >>"$LOG"',
                    '    fi',
                    '    echo "" >>"$LOG"',
                    '  else',
                    '    echo "" >>"$LOG"',
                    '    echo "[webui] No system updates were applied (Nothing to do). Skipping optional updates to conserve CPU." >>"$LOG"',
                    '  fi',
                    'fi',

                    # Restart check: only meaningful when system packages changed.
                    'if [ ${rc} -eq 0 ] && [ ${did_updates} -eq 1 ] && [ "${SIMULATE:-0}" != "1" ]; then',
                    '  echo "" >>"$LOG"',
                    '  echo "=== ZYPPER PS -s (restart check) ===" >>"$LOG"',
                    f'  {ZYPPER_BIN} ps -s >>"$LOG" 2>&1 || true',
                    'fi',
                    '',
                    '# Self-cleanup: remove this temporary script file so /var/lib/zypper-auto does not fill up over time.',
                    'if [ ${rc} -eq 0 ]; then write_status 1 ${rc} done; else write_status 1 ${rc} failed; fi',
                    'rm -f "$0" >/dev/null 2>&1 || true',
                    'exit ${rc}',
                ])

                # Write unit script to disk (inside the API service sandbox).
                script_file = f"/var/lib/zypper-auto/webui-dup-{job_id[:10]}.sh"
                try:
                    os.makedirs("/var/lib/zypper-auto", exist_ok=True)
                    with open(script_file, "w", encoding="utf-8") as f:
                        f.write("#!/usr/bin/env bash\n")
                        f.write(script_text)
                        f.write("\n")
                    os.chmod(script_file, 0o700)
                except Exception as e:
                    with lock:
                        j = jobs.get(job_id)
                        if j:
                            j["rc"] = 1
                            j["running"] = False
                            j["done"] = True
                            j["finished_at"] = time.time()
                            j["stage"] = "Failed"
                            _job_output_append(j, f"[dashboard-api] Failed to write unit script: {e}\n")
                    try:
                        if script_file and os.path.exists(script_file):
                            os.remove(script_file)
                    except Exception:
                        pass
                    return

                env = {
                    "PATH": "/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin",
                    "LANG": "C.UTF-8",
                    "LC_ALL": "C.UTF-8",
                    "HOME": os.environ.get("HOME", "/root"),
                    "SIMULATE": "1" if simulate else "0",
                }

                # Start transient unit
                sys_cmd = [
                    "systemd-run",
                    "--quiet",
                    "--collect",
                    "--unit",
                    unit,
                    "--property",
                    "After=network-online.target",
                    "--property",
                    "Wants=network-online.target",
                    "--",
                    "/usr/bin/bash",
                    script_file,
                ]

                try:
                    with lock:
                        j = jobs.get(job_id)
                        if j:
                            _job_output_append(j, f"[dashboard-api] Starting system update unit: {unit}\n")
                            _job_output_append(j, f"[dashboard-api] Unit script: {script_file}\n")
                            _job_update_progress_dup(j, "starting")

                    p = subprocess.run(
                        sys_cmd,
                        check=False,
                        stdout=subprocess.PIPE,
                        stderr=subprocess.STDOUT,
                        text=True,
                        encoding="utf-8",
                        errors="replace",
                        env=env,
                        timeout=15,
                    )
                    if p.returncode != 0:
                        with lock:
                            j = jobs.get(job_id)
                            if j:
                                _job_output_append(j, f"[dashboard-api] systemd-run failed rc={p.returncode}\n")
                                if p.stdout:
                                    _job_output_append(j, p.stdout + "\n")
                        raise RuntimeError(f"systemd-run failed rc={p.returncode}")

                except Exception as e:
                    with lock:
                        j = jobs.get(job_id)
                        if j:
                            j["rc"] = 1
                            j["running"] = False
                            j["done"] = True
                            j["finished_at"] = time.time()
                            j["stage"] = "Failed"
                            _job_output_append(j, f"\n[dashboard-api] Failed to start update: {e}\n")
                    try:
                        if script_file and os.path.exists(script_file):
                            os.remove(script_file)
                    except Exception:
                        pass
                    return

                # Stream the log file + poll unit state.
                offset = 0
                start_ts = time.time()
                finished_rc = None

                while True:
                    # Append new log output (best-effort)
                    try:
                        with open(log_path, "r", encoding="utf-8", errors="replace") as f:
                            f.seek(offset)
                            chunk = f.read()
                            offset = f.tell()
                        if chunk:
                            for ln in chunk.splitlines(True):
                                with lock:
                                    j = jobs.get(job_id)
                                    if j:
                                        _job_output_append(j, ln)
                                        _job_update_progress_dup(j, ln)
                    except Exception:
                        pass

                    # If the unit disappears (collected) or the API restarts, the unit script
                    # still writes a status file. Use it as an authoritative done/rc signal.
                    try:
                        if os.path.exists(status_path):
                            st = _read_kv_status(status_path)
                            if str(st.get("done", "")).strip() in ("1", "true", "yes"):
                                try:
                                    finished_rc = int(str(st.get("rc", "1") or "1"))
                                except Exception:
                                    finished_rc = 1
                                break
                    except Exception:
                        pass

                    # Poll unit state
                    rc_show, out_show = _run_cmd(
                        ["systemctl", "show", unit, "-p", "ActiveState", "-p", "SubState", "-p", "ExecMainStatus"],
                        timeout_s=3,
                        log=None,
                    )
                    props = {}
                    for line in (out_show or "").splitlines():
                        if "=" in line:
                            k, v = line.split("=", 1)
                            props[k.strip()] = v.strip()
                    active = props.get("ActiveState", "")
                    sub = props.get("SubState", "")

                    # If the unit is running, reflect that in the UI even if there is a
                    # short delay before new log lines arrive.
                    if active == "active":
                        with lock:
                            j = jobs.get(job_id)
                            if j and j.get("stage") in ("Starting", "starting"):
                                j["stage"] = "Running" if not simulate else "Dry-run running"
                                if int(j.get("progress") or 0) < 1:
                                    j["progress"] = 1

                    if active == "inactive" and sub in ("dead", "failed", "exited"):
                        try:
                            finished_rc = int(props.get("ExecMainStatus", "1") or "1")
                        except Exception:
                            finished_rc = 1
                        break

                    # Safety timeout
                    if (time.time() - start_ts) > 4 * 60 * 60:
                        finished_rc = 124
                        with lock:
                            j = jobs.get(job_id)
                            if j:
                                _job_output_append(j, "\n[dashboard-api] Timed out waiting for system update unit to finish.\n")
                                j["stage"] = "Timed out"
                        break

                    time.sleep(0.35)

                # Final read to capture remainder
                try:
                    with open(log_path, "r", encoding="utf-8", errors="replace") as f:
                        f.seek(offset)
                        chunk2 = f.read()
                        offset = f.tell()
                    if chunk2:
                        with lock:
                            j = jobs.get(job_id)
                            if j:
                                _job_output_append(j, chunk2)
                except Exception:
                    pass

                # Extract restart check section (best-effort)
                restart_out = ""
                try:
                    with open(log_path, "r", encoding="utf-8", errors="replace") as f:
                        full = f.read()
                    marker = "=== ZYPPER PS -s (restart check) ==="
                    if marker in full:
                        restart_out = full.split(marker, 1)[1].strip()
                        if len(restart_out) > 60_000:
                            restart_out = restart_out[-60_000:]
                except Exception:
                    restart_out = ""

                with lock:
                    j = jobs.get(job_id)
                    if j:
                        j["rc"] = int(finished_rc if finished_rc is not None else 1)
                        j["running"] = False
                        j["done"] = True
                        j["finished_at"] = time.time()
                        j["restart_check_output"] = restart_out

                        # Best-effort: surface solver conflicts in the job payload so the WebUI
                        # can show actionable guidance.
                        try:
                            cd, cs = _detect_solver_conflict(str(j.get("output", "")), int(j["rc"]))
                            j["conflict_detected"] = bool(cd)
                            j["conflict_summary"] = str(cs or "")
                        except Exception:
                            j["conflict_detected"] = False
                            j["conflict_summary"] = ""

                        if j["rc"] == 0:
                            j["progress"] = 100
                            j["stage"] = "Done" if not simulate else "Dry-run done"
                        else:
                            j["stage"] = "Failed"


                # CLEANUP (best-effort): if the unit script still exists, remove it.
                # In normal operation the script self-deletes (rm -f "$0").
                try:
                    if script_file and os.path.exists(script_file):
                        os.remove(script_file)
                except Exception:
                    pass

            threading.Thread(target=worker, daemon=True).start()
            return _json_response(self, 200, {"job_id": job_id}, origin)

        if path == "/api/snapper/confirm":
            body = _read_json(self)
            action = str(body.get("action", "")).strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            allowed = {
                "create": "Type SNAPSHOT to confirm snapshot creation.",
                "cleanup": "Type CLEANUP to confirm Snapper cleanup (may delete snapshots).",
                "auto-enable": "Type ENABLE to confirm enabling Snapper timers.",
                "auto-disable": "Type DISABLE to confirm disabling Snapper timers.",
            }
            if action not in allowed:
                return _json_response(self, 400, {"error": f"unsupported confirm action: {action}"}, origin)

            now_ts = time.time()
            _confirm_purge(now_ts)

            token = secrets.token_urlsafe(24)
            exp = now_ts + 120.0
            try:
                with tokens_lock:
                    if not hasattr(self.server, "confirm_tokens"):
                        self.server.confirm_tokens = {}
                    self.server.confirm_tokens[token] = {
                        "action": action,
                        "params": params,
                        "exp": exp,
                    }
            except Exception:
                return _json_response(self, 500, {"error": "failed to store confirm token"}, origin)

            phrase = ""
            if action == "create":
                phrase = "SNAPSHOT"
            elif action == "cleanup":
                phrase = "CLEANUP"
            elif action == "auto-enable":
                phrase = "ENABLE"
            elif action == "auto-disable":
                phrase = "DISABLE"

            return _json_response(self, 200, {
                "confirm_token": token,
                "expires_in_seconds": 120,
                "phrase": phrase,
                "hint": allowed[action],
            }, origin)

        if path == "/api/snapper/start":
            # Best-effort concurrency guard: avoid clobbering the single-task UX.
            try:
                ri = _snapper_any_running()
                if ri.get("running"):
                    return _json_response(self, 409, {
                        "error": "a snapper job is already running",
                        "job_running": True,
                        "unit": ri.get("unit"),
                        "status_path": ri.get("status_path"),
                        "action": ri.get("action"),
                        "title": ri.get("title"),
                    }, origin)
            except Exception:
                pass

            body = _read_json(self)
            action = str(body.get("action", "") or "").strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            # Determine if action requires confirmation.
            needs_confirm = action in ("create", "cleanup", "auto-enable", "auto-disable")
            if action in ("status", "list"):
                needs_confirm = False

            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip()

            if needs_confirm:
                now_ts = time.time()
                _confirm_purge(now_ts)
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    meta = items.get(confirm_token)
                    if not meta:
                        return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                    if meta.get("action") != action:
                        return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)

                    required_phrase = {
                        "create": "SNAPSHOT",
                        "cleanup": "CLEANUP",
                        "auto-enable": "ENABLE",
                        "auto-disable": "DISABLE",
                    }.get(action, "")

                    if required_phrase and confirm_phrase.upper() != required_phrase:
                        return _json_response(self, 400, {"error": f"confirmation phrase mismatch (expected {required_phrase})"}, origin)

                    # One-time token.
                    try:
                        items.pop(confirm_token, None)
                    except Exception:
                        pass

            # Map actions to helper subcommands.
            cmd = None
            timeout_s = 120
            title = f"snapper {action}".strip()

            if action == "status":
                cmd = [HELPER_BIN, "snapper", "status"]
                timeout_s = 60
                title = "snapper status"
            elif action == "list":
                n = str(params.get("n", "10"))
                if not re.fullmatch(r"[0-9]+", n):
                    n = "10"
                nn = 10
                try:
                    nn = int(n)
                except Exception:
                    nn = 10
                if nn < 1:
                    nn = 1
                if nn > 50:
                    nn = 50
                cmd = [HELPER_BIN, "snapper", "list", str(nn)]
                timeout_s = 60
                title = f"snapper list ({nn})"
            elif action == "create":
                desc = str(params.get("desc", "")).strip()
                if len(desc) > 200:
                    desc = desc[:200]
                cmd = [HELPER_BIN, "snapper", "create", desc]
                timeout_s = 5 * 60
                title = "snapper create"
            elif action == "cleanup":
                mode = str(params.get("mode", "all")).strip()
                if mode not in ("all", "force-prune", "number", "timeline", "empty-pre-post"):
                    mode = "all"
                cmd = [HELPER_BIN, "snapper", "cleanup", mode]
                timeout_s = 60 * 60
                title = f"snapper cleanup ({mode})"
            elif action == "auto-enable":
                cmd = [HELPER_BIN, "snapper", "auto"]
                timeout_s = 20 * 60
                title = "snapper auto-enable"
            elif action == "auto-disable":
                cmd = [HELPER_BIN, "snapper", "auto-off"]
                timeout_s = 20 * 60
                title = "snapper auto-disable"
            else:
                return _json_response(self, 400, {"error": f"unsupported action: {action}"}, origin)

            # Run via systemd-run (persist across API/browser restarts)
            job_id = secrets.token_urlsafe(18)
            unit, log_path, status_path, script_file = _snapper_paths(job_id)

            # Precreate log + status so the first poll can't race before the unit writes anything.
            try:
                os.makedirs(SNAPPER_LOG_DIR, exist_ok=True)
                os.makedirs(SNAPPER_STATUS_DIR, exist_ok=True)
                with open(log_path, "a", encoding="utf-8"):
                    pass
                with open(status_path, "w", encoding="utf-8") as f:
                    f.write("done=0\n")
                    f.write("rc=0\n")
                    f.write("stage=starting\n")
                    f.write(f"action={action}\n")
                    f.write(f"title={title}\n")
            except Exception:
                pass

            cmd_str = " ".join(shlex.quote(str(x)) for x in cmd)

            script_text = "\n".join([
                'set -euo pipefail',
                f'LOG={shlex.quote(log_path)}',
                f'STATUS={shlex.quote(status_path)}',
                f'ACTION={shlex.quote(action)}',
                f'TITLE={shlex.quote(title)}',
                f'TIMEOUT_S={int(timeout_s)}',
                'mkdir -p /var/log/zypper-auto/service-logs || true',
                'mkdir -p /var/lib/zypper-auto || true',
                'STARTED_AT="$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                'write_status() {',
                '  local done="$1"; local rc="$2"; local stage="$3"',
                '  local tmp="${STATUS}.tmp.$$"',
                '  {',
                '    echo "done=${done}"',
                '    echo "rc=${rc}"',
                '    echo "stage=${stage}"',
                '    echo "action=${ACTION:-}"',
                '    echo "title=${TITLE:-}"',
                '    echo "started_at_utc=${STARTED_AT}"',
                '    echo "updated_at_utc=$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                '  } >"${tmp}" 2>/dev/null || true',
                '  mv -f "${tmp}" "${STATUS}" 2>/dev/null || true',
                '}',
                'write_status 0 0 starting',
                'echo "==========================================" >>"$LOG" || true',
                'echo " WebUI Snapper job " >>"$LOG" || true',
                'echo "==========================================" >>"$LOG" || true',
                'date >>"$LOG" 2>/dev/null || true',
                'echo "" >>"$LOG" || true',
                'echo "ACTION: ${ACTION}" >>"$LOG" || true',
                'echo "TITLE : ${TITLE}" >>"$LOG" || true',
                f'echo "CMD   : {cmd_str}" >>"$LOG" || true',
                'echo "" >>"$LOG" || true',
                'export ZNH_NON_INTERACTIVE=1',
                'write_status 0 0 running',
                'set +e',
                'if command -v timeout >/dev/null 2>&1; then',
                f'  ( timeout "${{TIMEOUT_S}}" {cmd_str} ) 2>&1 | tee -a "$LOG"',
                '  rc=${PIPESTATUS[0]}',
                'else',
                f'  ( {cmd_str} ) 2>&1 | tee -a "$LOG"',
                '  rc=${PIPESTATUS[0]}',
                'fi',
                'set -e',
                'echo "" >>"$LOG" || true',
                'echo "[webui] snapper rc=${rc}" >>"$LOG" || true',
                'if [ ${rc} -eq 124 ] 2>/dev/null; then',
                '  write_status 1 ${rc} timed-out',
                '  echo "[webui] ERROR: timed out" >>"$LOG" || true',
                '  rm -f "$0" >/dev/null 2>&1 || true',
                '  exit ${rc}',
                'fi',
                'if [ ${rc} -eq 0 ]; then',
                '  write_status 1 ${rc} done',
                'else',
                '  write_status 1 ${rc} failed',
                'fi',
                'rm -f "$0" >/dev/null 2>&1 || true',
                'exit ${rc}',
            ])

            try:
                os.makedirs(SNAPPER_STATUS_DIR, exist_ok=True)
                with open(script_file, "w", encoding="utf-8") as f:
                    f.write("#!/usr/bin/env bash\n")
                    f.write(script_text)
                    f.write("\n")
                os.chmod(script_file, 0o700)
            except Exception as e:
                return _json_response(self, 500, {"error": f"failed to write snapper unit script: {e}"}, origin)

            sys_cmd = [
                "systemd-run",
                "--quiet",
                "--collect",
                "--unit",
                unit,
                "--",
                "/usr/bin/bash",
                script_file,
            ]

            try:
                p = subprocess.run(
                    sys_cmd,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=15,
                )
                if p.returncode != 0:
                    out = (p.stdout or "").strip()
                    return _json_response(self, 500, {"error": f"systemd-run failed rc={p.returncode}", "output": out}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"systemd-run exception: {e}"}, origin)

            return _json_response(self, 200, {"job_id": job_id}, origin)

        if path == "/api/snapper/run":
            body = _read_json(self)
            action = str(body.get("action", "")).strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            # Determine if action requires confirmation.
            needs_confirm = action in ("create", "cleanup", "auto-enable", "auto-disable")
            if action in ("status", "list"):
                needs_confirm = False

            confirm_token = str(body.get("confirm_token", "")).strip()
            confirm_phrase = str(body.get("confirm_phrase", "")).strip()

            if needs_confirm:
                now_ts = time.time()
                _confirm_purge(now_ts)
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    meta = items.get(confirm_token)
                    if not meta:
                        return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                    if meta.get("action") != action:
                        return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)

                    required_phrase = {
                        "create": "SNAPSHOT",
                        "cleanup": "CLEANUP",
                        "auto-enable": "ENABLE",
                        "auto-disable": "DISABLE",
                    }.get(action, "")

                    if required_phrase and confirm_phrase.upper() != required_phrase:
                        return _json_response(self, 400, {"error": f"confirmation phrase mismatch (expected {required_phrase})"}, origin)

                    # One-time token.
                    try:
                        items.pop(confirm_token, None)
                    except Exception:
                        pass

            # Map actions to helper subcommands.
            cmd = None
            timeout_s = 60

            if action == "status":
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "status"]
                timeout_s = 30
            elif action == "list":
                n = str(params.get("n", "10"))
                if not re.fullmatch(r"[0-9]+", n):
                    n = "10"
                nn = 10
                try:
                    nn = int(n)
                except Exception:
                    nn = 10
                if nn < 1:
                    nn = 1
                if nn > 50:
                    nn = 50
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "list", str(nn)]
                timeout_s = 30
            elif action == "create":
                desc = str(params.get("desc", "")).strip()
                # Bound description size.
                if len(desc) > 200:
                    desc = desc[:200]
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "create", desc]
                timeout_s = 90
            elif action == "cleanup":
                mode = str(params.get("mode", "all")).strip()
                if mode not in ("all", "force-prune", "number", "timeline", "empty-pre-post"):
                    mode = "all"
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "cleanup", mode]
                timeout_s = 600
            elif action == "auto-enable":
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "auto"]
                timeout_s = 120
            elif action == "auto-disable":
                cmd = ["/usr/local/bin/zypper-auto-helper", "snapper", "auto-off"]
                timeout_s = 120
            else:
                return _json_response(self, 400, {"error": f"unsupported action: {action}"}, origin)

            # NOTE: Snapper concurrency/busy handling is enforced inside the helper itself
            # (including WebUI-friendly wait/retry). Do not hard-block here.

            extra_env = None
            if needs_confirm:
                # The WebUI already enforced a typed confirmation phrase.
                # Make the helper non-interactive so it won't block on read(1) prompts.
                extra_env = {"ZNH_NON_INTERACTIVE": "1"}

            rc, out = _run_cmd(cmd, timeout_s=timeout_s, log=getattr(self.server, "_znh_log", None), extra_env=extra_env)
            # Always return HTTP 200 so the WebUI can render output even on non-zero rc.
            return _json_response(self, 200, {"ok": (rc == 0), "rc": rc, "output": out, "action": action}, origin)

        # --- scrub-ghost (boot entry scrubber) ---
        def _scrub_pbool(p: dict, k: str, default=False) -> bool:
            try:
                v = p.get(k, default)
                if isinstance(v, bool):
                    return v
                s = str(v).strip().lower()
                if s in ("1", "true", "yes", "on", "y"):
                    return True
                if s in ("0", "false", "no", "off", "n"):
                    return False
                return bool(v)
            except Exception:
                return bool(default)

        def _scrub_pint(p: dict, k: str, default=0, minv=0, maxv=9999) -> int:
            try:
                v = p.get(k, default)
                n = int(str(v).strip())
                if n < minv:
                    n = minv
                if n > maxv:
                    n = maxv
                return n
            except Exception:
                return int(default)

        def _scrub_required_phrase(scrub_action: str, p: dict) -> tuple[str, str]:
            a = str(scrub_action or "").strip()
            p = p or {}

            if a in ("auto", "apply"):
                apply_mode = str(p.get("apply_mode", "backup") or "backup").strip().lower()
                prune_uninstalled = bool(p.get("prune_uninstalled", False))
                no_backup = bool(p.get("no_backup", False))

                if apply_mode == "delete":
                    return "DELETE", "Type DELETE to confirm PERMANENT deletion mode (danger: removes boot entries)."
                if prune_uninstalled:
                    return "KERNELS", "Type KERNELS to confirm pruning uninstalled-kernel boot entries (extra danger)."
                if no_backup:
                    return "NOBACKUP", "Type NOBACKUP to confirm applying scrub-ghost WITHOUT a filesystem backup copy (danger)."
                return "SCRUB", "Type SCRUB to confirm applying scrub-ghost (moves broken entries to backup)."

            if a.startswith("restore-"):
                clean_restore = bool(p.get("clean_restore", False))
                restore_anyway = bool(p.get("restore_anyway", False))

                if clean_restore:
                    return "CLEAN", "Type CLEAN to confirm --clean-restore (danger: deletes extra current entries)."
                if restore_anyway:
                    return "ANYWAY", "Type ANYWAY to confirm --restore-anyway (danger: overrides failed validation)."
                return "RESTORE", "Type RESTORE to confirm restoring scrub-ghost backups (danger)."

            return "", ""

        def _scrub_cmd(scrub_action: str, p: dict) -> tuple[list[str], int, str]:
            a = str(scrub_action or "").strip()
            p = p or {}

            # WebUI must never run interactive modes.
            if a in ("menu", "rescue"):
                raise ValueError("interactive action not supported in WebUI")

            cmd = [HELPER_BIN, "scrub-ghost", "--no-color", "--no-menu"]
            title = f"scrub-ghost {a}".strip()

            # Common optional flags
            if _scrub_pbool(p, "verbose", False):
                cmd.append("--verbose")
            if _scrub_pbool(p, "debug", False):
                cmd.append("--debug")

            # Common path overrides
            entries_dir = str(p.get("entries_dir", "") or "").strip()
            boot_dir = str(p.get("boot_dir", "") or "").strip()
            backup_root = str(p.get("backup_root", "") or "").strip()
            backup_dir = str(p.get("backup_dir", "") or "").strip()
            grub_cfg = str(p.get("grub_cfg", "") or "").strip()
            log_file = str(p.get("log_file", "") or "").strip()

            if entries_dir:
                cmd.extend(["--entries-dir", entries_dir])
            if boot_dir:
                cmd.extend(["--boot-dir", boot_dir])
            if backup_root:
                cmd.extend(["--backup-root", backup_root])
            if backup_dir:
                cmd.extend(["--backup-dir", backup_dir])
            if log_file:
                cmd.extend(["--log-file", log_file])

            # Advanced toggles
            if _scrub_pbool(p, "no_remount_rw", False):
                cmd.append("--no-remount-rw")

            # Prune toggles
            if _scrub_pbool(p, "prune_duplicates", False):
                cmd.append("--prune-duplicates")
            if _scrub_pbool(p, "prune_stale", False):
                cmd.append("--prune-stale-snapshots")
            if _scrub_pbool(p, "prune_uninstalled", False):
                cmd.append("--prune-uninstalled")
                # confirm flag is only *required* when applying changes, but allow
                # adding it during scan too.
                if _scrub_pbool(p, "confirm_uninstalled", False):
                    cmd.append("--confirm-uninstalled")
            if _scrub_pbool(p, "prune_zombies", False):
                cmd.append("--prune-zombies")

            timeout_s = 180

            if a == "scan":
                cmd.insert(2, "--dry-run")
                if _scrub_pbool(p, "json_output", False):
                    cmd.append("--json")
                timeout_s = 90

            elif a in ("auto", "apply"):
                apply_mode = str(p.get("apply_mode", "backup") or "backup").strip().lower()
                if apply_mode not in ("backup", "delete"):
                    apply_mode = "backup"

                if _scrub_pbool(p, "no_backup", False):
                    cmd.append("--no-backup")
                if _scrub_pbool(p, "no_snapper_backup", False):
                    cmd.append("--no-snapper-backup")

                if _scrub_pbool(p, "no_verify_snapshots", False):
                    cmd.append("--no-verify-snapshots")
                if _scrub_pbool(p, "no_verify_modules", False):
                    cmd.append("--no-verify-modules")

                if apply_mode == "delete":
                    cmd.append("--delete")
                else:
                    cmd.append("--force")

                if _scrub_pbool(p, "prune_uninstalled", False):
                    if not _scrub_pbool(p, "confirm_uninstalled", False):
                        raise ValueError("prune_uninstalled requires confirm_uninstalled")

                if _scrub_pbool(p, "update_sdboot", False):
                    cmd.append("--update-sdboot")

                if _scrub_pbool(p, "rebuild_grub", False):
                    if grub_cfg:
                        cmd.extend(["--grub-cfg", grub_cfg])
                    cmd.append("--rebuild-grub")

                keep_backups = _scrub_pint(p, "keep_backups", default=5, minv=0, maxv=50)
                cmd.extend(["--keep-backups", str(keep_backups)])

                timeout_s = 300

            elif a == "list-backups":
                cmd.append("--list-backups")
                timeout_s = 60

            elif a == "validate-latest":
                cmd.append("--validate-latest")
                timeout_s = 120

            elif a == "validate-pick":
                n = _scrub_pint(p, "validate_pick", default=0, minv=1, maxv=999)
                cmd.extend(["--validate-pick", str(n)])
                timeout_s = 120

            elif a == "validate-from":
                d = str(p.get("validate_from", "") or "").strip()
                if not d:
                    raise ValueError("validate_from is required")
                cmd.extend(["--validate-from", d])
                timeout_s = 120

            elif a == "restore-latest":
                cmd.append("--restore-latest")
                if _scrub_pbool(p, "clean_restore", False):
                    cmd.append("--clean-restore")
                if _scrub_pbool(p, "restore_anyway", False):
                    cmd.append("--restore-anyway")
                timeout_s = 600

            elif a == "restore-best":
                cmd.append("--restore-best")
                if _scrub_pbool(p, "clean_restore", False):
                    cmd.append("--clean-restore")
                if _scrub_pbool(p, "restore_anyway", False):
                    cmd.append("--restore-anyway")
                timeout_s = 600

            elif a == "restore-pick":
                n = _scrub_pint(p, "restore_pick", default=0, minv=1, maxv=999)
                cmd.extend(["--restore-pick", str(n)])
                if _scrub_pbool(p, "clean_restore", False):
                    cmd.append("--clean-restore")
                if _scrub_pbool(p, "restore_anyway", False):
                    cmd.append("--restore-anyway")
                timeout_s = 600

            elif a == "restore-from":
                d = str(p.get("restore_from", "") or "").strip()
                if not d:
                    raise ValueError("restore_from is required")
                cmd.extend(["--restore-from", d])
                if _scrub_pbool(p, "clean_restore", False):
                    cmd.append("--clean-restore")
                if _scrub_pbool(p, "restore_anyway", False):
                    cmd.append("--restore-anyway")
                timeout_s = 600

            elif a == "completion":
                shell = str(p.get("completion_shell", "zsh") or "zsh").strip().lower()
                if shell not in ("bash", "zsh"):
                    shell = "zsh"
                cmd.extend(["--completion", shell])
                timeout_s = 20
                title = "scrub-ghost completion"

            else:
                raise ValueError(f"unsupported scrub action: {a}")

            return cmd, int(timeout_s), title

        if path == "/api/scrub/confirm":
            body = _read_json(self)
            action = str(body.get("action", "")).strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            allowed = {
                "auto": "AUTO (recommended) scrub-ghost apply.",
                "apply": "Apply scrub-ghost with custom toggles.",
                "restore-latest": "Restore latest scrub-ghost backup (danger).",
                "restore-best": "Restore newest VALID scrub-ghost backup (danger).",
                "restore-pick": "Restore scrub-ghost backup number N (danger).",
                "restore-from": "Restore scrub-ghost backup from a specific directory (danger).",
            }
            if action not in allowed:
                return _json_response(self, 400, {"error": f"unsupported confirm action: {action}"}, origin)

            now_ts = time.time()
            _confirm_purge(now_ts)

            token = secrets.token_urlsafe(24)
            exp = now_ts + 120.0
            try:
                with tokens_lock:
                    if not hasattr(self.server, "confirm_tokens"):
                        self.server.confirm_tokens = {}
                    self.server.confirm_tokens[token] = {
                        "action": "scrub",
                        "scrub_action": action,
                        "params": params,
                        "exp": exp,
                    }
            except Exception:
                return _json_response(self, 500, {"error": "failed to store confirm token"}, origin)

            phrase, hint = _scrub_required_phrase(action, params)
            if not hint:
                hint = allowed[action]

            return _json_response(self, 200, {
                "confirm_token": token,
                "expires_in_seconds": 120,
                "phrase": phrase,
                "hint": hint,
            }, origin)

        if path == "/api/scrub/start":
            # Best-effort concurrency guard: avoid clobbering the single-task bubble UX.
            try:
                ri = _scrub_any_running()
                if ri.get("running"):
                    return _json_response(self, 409, {
                        "error": "a scrub-ghost job is already running",
                        "job_running": True,
                        "unit": ri.get("unit"),
                        "status_path": ri.get("status_path"),
                        "action": ri.get("action"),
                        "title": ri.get("title"),
                    }, origin)
            except Exception:
                pass

            body = _read_json(self)
            action = str(body.get("action", "") or "").strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            needs_confirm = action in ("auto", "apply") or action.startswith("restore-")

            confirm_token = str(body.get("confirm_token", "") or "").strip()
            confirm_phrase = str(body.get("confirm_phrase", "") or "").strip().upper()

            if needs_confirm:
                now_ts = time.time()
                _confirm_purge(now_ts)
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    meta = items.get(confirm_token)
                    if not meta:
                        return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                    if meta.get("action") != "scrub":
                        return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                    if meta.get("scrub_action") != action:
                        return _json_response(self, 400, {"error": "confirm token does not match scrub action"}, origin)

                    p0 = meta.get("params") or {}
                    required_phrase, _hint = _scrub_required_phrase(action, p0)
                    if required_phrase and confirm_phrase != str(required_phrase).strip().upper():
                        return _json_response(self, 400, {"error": f"confirmation phrase mismatch (expected {required_phrase})"}, origin)

                    # One-time token.
                    try:
                        items.pop(confirm_token, None)
                    except Exception:
                        pass

            # Build command
            try:
                cmd, timeout_s, title = _scrub_cmd(action, params)
            except ValueError as e:
                return _json_response(self, 400, {"error": str(e)}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"scrub command build failed: {e}"}, origin)

            # Run via systemd-run (persist across API/browser restarts)
            job_id = secrets.token_urlsafe(18)
            unit, log_path, status_path, script_file = _scrub_paths(job_id)

            # Precreate log + status so the first poll can't race before the unit writes anything.
            try:
                os.makedirs(SCRUB_LOG_DIR, exist_ok=True)
                os.makedirs(SCRUB_STATUS_DIR, exist_ok=True)
                with open(log_path, "a", encoding="utf-8"):
                    pass
                with open(status_path, "w", encoding="utf-8") as f:
                    f.write("done=0\n")
                    f.write("rc=0\n")
                    f.write("stage=starting\n")
                    f.write(f"action={action}\n")
                    f.write(f"title={title}\n")
            except Exception:
                pass

            cmd_str = " ".join(shlex.quote(str(x)) for x in cmd)

            script_text = "\n".join([
                'set -euo pipefail',
                f'LOG={shlex.quote(log_path)}',
                f'STATUS={shlex.quote(status_path)}',
                f'ACTION={shlex.quote(action)}',
                f'TITLE={shlex.quote(title)}',
                f'TIMEOUT_S={int(timeout_s)}',
                'mkdir -p /var/log/zypper-auto/service-logs || true',
                'mkdir -p /var/lib/zypper-auto || true',
                'STARTED_AT="$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                'write_status() {',
                '  local done="$1"; local rc="$2"; local stage="$3"',
                '  local tmp="${STATUS}.tmp.$$"',
                '  {',
                '    echo "done=${done}"',
                '    echo "rc=${rc}"',
                '    echo "stage=${stage}"',
                '    echo "action=${ACTION:-}"',
                '    echo "title=${TITLE:-}"',
                '    echo "started_at_utc=${STARTED_AT}"',
                '    echo "updated_at_utc=$(date -u "+%Y-%m-%dT%H:%M:%SZ" 2>/dev/null || true)"',
                '  } >"${tmp}" 2>/dev/null || true',
                '  mv -f "${tmp}" "${STATUS}" 2>/dev/null || true',
                '}',
                'write_status 0 0 starting',
                'echo "==========================================" >>"$LOG" || true',
                'echo " WebUI scrub-ghost job " >>"$LOG" || true',
                'echo "==========================================" >>"$LOG" || true',
                'date >>"$LOG" 2>/dev/null || true',
                'echo "" >>"$LOG" || true',
                'echo "ACTION: ${ACTION}" >>"$LOG" || true',
                'echo "TITLE : ${TITLE}" >>"$LOG" || true',
                f'echo "CMD   : {cmd_str}" >>"$LOG" || true',
                'echo "" >>"$LOG" || true',
                'export ZNH_NON_INTERACTIVE=1',
                'write_status 0 0 running',
                'set +e',
                f'( timeout "${{TIMEOUT_S}}" {cmd_str} ) 2>&1 | tee -a "$LOG"',
                'rc=${PIPESTATUS[0]}',
                'set -e',
                'echo "" >>"$LOG" || true',
                'echo "[webui] scrub-ghost rc=${rc}" >>"$LOG" || true',
                'if [ ${rc} -eq 124 ] 2>/dev/null; then',
                '  write_status 1 ${rc} timed-out',
                '  echo "[webui] ERROR: timed out" >>"$LOG" || true',
                '  rm -f "$0" >/dev/null 2>&1 || true',
                '  exit ${rc}',
                'fi',
                'if [ ${rc} -eq 0 ]; then',
                '  write_status 1 ${rc} done',
                'else',
                '  write_status 1 ${rc} failed',
                'fi',
                'rm -f "$0" >/dev/null 2>&1 || true',
                'exit ${rc}',
            ])

            try:
                os.makedirs(SCRUB_STATUS_DIR, exist_ok=True)
                with open(script_file, "w", encoding="utf-8") as f:
                    f.write("#!/usr/bin/env bash\n")
                    f.write(script_text)
                    f.write("\n")
                os.chmod(script_file, 0o700)
            except Exception as e:
                return _json_response(self, 500, {"error": f"failed to write scrub unit script: {e}"}, origin)

            sys_cmd = [
                "systemd-run",
                "--quiet",
                "--collect",
                "--unit",
                unit,
                "--",
                "/usr/bin/bash",
                script_file,
            ]

            try:
                p = subprocess.run(
                    sys_cmd,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=15,
                )
                if p.returncode != 0:
                    out = (p.stdout or "").strip()
                    return _json_response(self, 500, {"error": f"systemd-run failed rc={p.returncode}", "output": out}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"systemd-run exception: {e}"}, origin)

            return _json_response(self, 200, {"job_id": job_id}, origin)

        if path == "/api/scrub/run":
            body = _read_json(self)
            action = str(body.get("action", "")).strip()
            params = body.get("params", {})
            if not isinstance(params, dict):
                params = {}

            needs_confirm = action in ("auto", "apply") or action.startswith("restore-")

            confirm_token = str(body.get("confirm_token", "")).strip()
            confirm_phrase = str(body.get("confirm_phrase", "")).strip().upper()

            if needs_confirm:
                now_ts = time.time()
                _confirm_purge(now_ts)
                with tokens_lock:
                    items = getattr(self.server, "confirm_tokens", {})
                    meta = items.get(confirm_token)
                    if not meta:
                        return _json_response(self, 400, {"error": "missing/expired confirm token"}, origin)
                    if meta.get("action") != "scrub":
                        return _json_response(self, 400, {"error": "confirm token does not match action"}, origin)
                    if meta.get("scrub_action") != action:
                        return _json_response(self, 400, {"error": "confirm token does not match scrub action"}, origin)

                    p0 = meta.get("params") or {}
                    required_phrase, _hint = _scrub_required_phrase(action, p0)
                    if required_phrase and confirm_phrase != str(required_phrase).strip().upper():
                        return _json_response(self, 400, {"error": f"confirmation phrase mismatch (expected {required_phrase})"}, origin)

                    # One-time token.
                    try:
                        items.pop(confirm_token, None)
                    except Exception:
                        pass

            try:
                cmd, timeout_s, _title = _scrub_cmd(action, params)
            except ValueError as e:
                return _json_response(self, 400, {"error": str(e)}, origin)
            except Exception as e:
                return _json_response(self, 500, {"error": f"scrub command build failed: {e}"}, origin)

            extra_env = {"ZNH_NON_INTERACTIVE": "1"}
            rc, out = _run_cmd(cmd, timeout_s=int(timeout_s), log=getattr(self.server, "_znh_log", None), extra_env=extra_env)
            return _json_response(self, 200, {"ok": (rc == 0), "rc": rc, "output": out, "action": action}, origin)

        if path == "/api/client-log":
            body = _read_json(self)
            level = str(body.get("level", "info")).lower()
            msg = str(body.get("msg", ""))
            ctx = body.get("ctx", {})
            if level not in ("error","warn","info","debug"):
                level = "info"
            try:
                getattr(self.server, "_znh_log", lambda *_: None)(level, f"[UI] {msg} ctx={json.dumps(ctx, ensure_ascii=False)[:400]}")
            except Exception:
                pass
            return _json_response(self, 200, {"ok": True}, origin)

        if path == "/api/reset-config":
            # Non-interactive reset via helper so it stays consistent with installer template.
            cmd = ["/usr/local/bin/zypper-auto-helper", "--reset-config", "--yes"]

            rc = 0
            out = ""
            try:
                p = subprocess.run(
                    cmd,
                    check=False,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    encoding="utf-8",
                    errors="replace",
                    timeout=90,
                )
                rc = int(p.returncode)
                out = (p.stdout or "")
            except Exception as e:
                return _json_response(self, 500, {"error": f"reset-config exception: {e}"}, origin)

            if rc != 0:
                # Return some output for debugging; keep it bounded.
                tail = out[-4000:] if len(out) > 4000 else out
                return _json_response(self, 500, {"error": f"reset-config failed rc={rc}", "output": tail}, origin)

            eff, warnings, invalid = _read_conf(self.server.conf_path)
            # Ensure managed block matches the validated effective config.
            _write_managed_block(self.server.conf_path, eff)
            eff2, warnings2, invalid2 = _read_conf(self.server.conf_path)
            return _json_response(self, 200, {"config": eff2, "warnings": warnings2, "invalid_keys": invalid2}, origin)

        if path == "/api/config":
            body = _read_json(self)
            patch = body.get("patch", body)
            if not isinstance(patch, dict):
                patch = {}

            # Safety: prevent switching self-update channel while a self-update job is running.
            try:
                if "SELF_UPDATE_CHANNEL" in patch:
                    ri = _self_update_any_running()
                    if ri.get("running"):
                        return _json_response(self, 409, {
                            "error": "SELF_UPDATE_CHANNEL is locked while self-update is running",
                            "job_running": True,
                            "unit": ri.get("unit"),
                            "status_path": ri.get("status_path"),
                        }, origin)
            except Exception:
                pass

            eff, warnings, invalid = _read_conf(self.server.conf_path)

            # Apply patch to effective config (only known keys)
            applied = {}
            for k, v in patch.items():
                if k not in SCHEMA:
                    continue
                applied[k] = str(v)
                eff[k] = str(v)

            try:
                getattr(self.server, "_znh_log", lambda *_: None)("debug", f"Patch keys={list(applied.keys())} values={json.dumps(applied, ensure_ascii=False)[:400]}")
            except Exception:
                pass

            eff2, warnings2, invalid2 = _validate(eff)
            if invalid2:
                try:
                    getattr(self.server, "_znh_log", lambda *_: None)("warn", f"Invalid keys auto-healed: {invalid2}")
                except Exception:
                    pass

            # Write corrected values back so invalid inputs auto-heal to defaults.
            try:
                _write_managed_block(self.server.conf_path, eff2)
            except Exception as e:
                try:
                    getattr(self.server, "_znh_log", lambda *_: None)("error", f"Write failed for {self.server.conf_path}: {e}")
                except Exception:
                    pass
                return _json_response(self, 500, {"error": f"write failed: {e}"}, origin)

            eff3, warnings3, invalid3 = _read_conf(self.server.conf_path)
            return _json_response(self, 200, {"config": eff3, "warnings": warnings2 + warnings3, "invalid_keys": invalid2 + invalid3}, origin)

        return _json_response(self, 404, {"error": "not found"}, origin)


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--listen", default="127.0.0.1")
    ap.add_argument("--port", type=int, default=8766)
    ap.add_argument("--token-file", required=True)
    ap.add_argument("--config", default="/etc/zypper-auto.conf")
    ap.add_argument("--schema-file", default="/var/lib/zypper-auto/dashboard-schema.json")
    ap.add_argument("--log-file", default="/var/log/zypper-auto/service-logs/dashboard-api.log")
    ap.add_argument("--mirror-file", default="")
    ap.add_argument("--log-level", default="info", choices=["error","warn","info","debug"])
    args = ap.parse_args()

    global SCHEMA, DEFAULTS
    SCHEMA = _load_schema(args.schema_file)
    DEFAULTS = _build_defaults(SCHEMA)

    # Structured logging similar to the bash helper
    run_id = f"API-{os.getpid()}"

    def _ts():
        # millisecond timestamp
        import datetime
        return datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]

    def _write_line(path: str, line: str):
        if not path:
            return
        try:
            os.makedirs(os.path.dirname(path), exist_ok=True)
            with open(path, "a", encoding="utf-8") as f:
                f.write(line + "\n")
        except Exception:
            return

    LEVEL_ORDER = {"error": 0, "warn": 1, "info": 2, "debug": 3}
    LOG_LEVEL = args.log_level

    def log(level: str, msg: str):
        if LEVEL_ORDER.get(level, 2) > LEVEL_ORDER.get(LOG_LEVEL, 2):
            return
        line = f"[{level.upper()}] {_ts()} [RUN={run_id}] {msg}"
        _write_line(args.log_file, line)
        # Mirror into user dashboard dir so the HTML can display it.
        if args.mirror_file:
            _write_line(args.mirror_file, line)
            try:
                os.chmod(args.mirror_file, 0o644)
            except Exception:
                pass

    # Log startup
    log("info", f"Starting dashboard API on {args.listen}:{args.port} (config={args.config})")

    # API FIX: Use a multi-threaded HTTP server so slow requests (large logs,
    # snapper commands, etc.) don't freeze the entire dashboard.
    class ThreadingHTTPServer(socketserver.ThreadingMixIn, HTTPServer):
        daemon_threads = True
        allow_reuse_address = True

    token = _load_token(args.token_file)

    try:
        httpd = ThreadingHTTPServer((args.listen, args.port), Handler)
    except OSError as e:
        log("error", f"FATAL: Could not bind dashboard API to {args.listen}:{args.port}: {e}")
        raise SystemExit(1)

    httpd.token = token
    httpd.conf_path = args.config
    httpd._znh_log = log

    # Confirmation token cache must be thread-safe (ThreadingHTTPServer).
    httpd.confirm_tokens = {}
    httpd.tokens_lock = threading.Lock()

    try:
        httpd.serve_forever()
    except KeyboardInterrupt:
        log("info", "Stopping dashboard API (KeyboardInterrupt)")
    finally:
        try:
            httpd.server_close()
        except Exception:
            pass


if __name__ == "__main__":
    main()
PYEOF
then
    execute_guarded "Set API server permissions (755)" chmod 755 "${DASH_API_BIN}" || true
    log_success "Dashboard API server installed: ${DASH_API_BIN}"
else
    log_warn "Failed to install dashboard API server (non-fatal)"
fi

# Install systemd unit
if write_atomic "${DASH_API_UNIT}" <<EOF
[Unit]
Description=Zypper Auto Dashboard Settings API (localhost)
After=network.target

[Service]
Type=simple
EnvironmentFile=-/var/lib/zypper-auto/dashboard-api.env
ExecStart=${DASH_API_BIN} --listen 127.0.0.1 --port 8766 --token-file ${DASH_API_TOKEN_FILE} --config ${CONFIG_FILE} --schema-file /var/lib/zypper-auto/dashboard-schema.json --log-file /var/log/zypper-auto/service-logs/dashboard-api.log --mirror-file=${DASH_API_MIRROR_FILE:-} --log-level ${DASH_API_LOG_LEVEL:-info}
Restart=on-failure
RestartSec=2

# Background priority + caps (best-effort; ignored on older systemd / cgroup setups)
Nice=10
IOSchedulingClass=best-effort
IOSchedulingPriority=7
CPUWeight=20
IOWeight=20
MemoryHigh=250M
MemoryMax=400M

# Basic hardening
NoNewPrivileges=true
PrivateTmp=true
ProtectSystem=strict
ProtectHome=read-only
ReadWritePaths=${CONFIG_FILE} ${DASH_API_TOKEN_DIR} /var/log/zypper-auto /var/log/zypper-auto/service-logs /run /var/run

[Install]
WantedBy=multi-user.target
EOF
then
    chmod 644 "${DASH_API_UNIT}" 2>/dev/null || true
    execute_guarded "systemd daemon-reload (dashboard api unit)" systemctl daemon-reload || true
    log_success "Dashboard API systemd unit installed: ${DASH_API_UNIT}"
else
    log_warn "Failed to write dashboard API unit file (non-fatal): ${DASH_API_UNIT}"
fi

# Ensure token directory exists with strict perms
mkdir -p "${DASH_API_TOKEN_DIR}" 2>/dev/null || true
chown root:root "${DASH_API_TOKEN_DIR}" 2>/dev/null || true
chmod 700 "${DASH_API_TOKEN_DIR}" 2>/dev/null || true

# Write dashboard schema used by the Settings API/UI
__znh_write_dashboard_schema_json "${DASH_API_TOKEN_DIR}/dashboard-schema.json" || true

# Install scrub-ghost (boot entry scrubber) from the embedded source.
log_info ">>> Installing scrub-ghost tool (/usr/local/bin/scrub-ghost)..."
update_status "Installing scrub-ghost tool..."
__znh_write_scrub_ghost_script || true

# Create an initial token if missing (will be replaced by --dash-open as needed)
if [ ! -f "${DASH_API_TOKEN_FILE}" ]; then
    if command -v python3 >/dev/null 2>&1; then
        python3 - <<'PY'
import secrets
print(secrets.token_urlsafe(24))
PY
    else
        date +%s%N
    fi | tr -d '\n' >"${DASH_API_TOKEN_FILE}" 2>/dev/null || true
    chmod 600 "${DASH_API_TOKEN_FILE}" 2>/dev/null || true
fi

# --- 11f. Install dashboard performance worker (user-space) ---
# This worker writes perf-data.json into the user's dashboard directory so
# status.html can show realtime service CPU/memory/IO charts when opened via
# --dash-open.
DASH_PERF_BIN="/usr/local/bin/zypper-auto-dashboard-perf-worker"

log_info ">>> Installing dashboard performance worker (service perf charts)..."
update_status "Installing dashboard performance worker..."

if write_atomic "${DASH_PERF_BIN}" <<'PYEOF'
#!/usr/bin/env python3
import argparse
import json
import os
import subprocess
import sys
import time
from collections import deque
from datetime import datetime, timezone

def _iso_now() -> str:
    return datetime.now(timezone.utc).astimezone().isoformat(timespec="seconds")

def _to_int(v, default=0):
    try:
        if v is None:
            return default
        s = str(v).strip()
        if s == "":
            return default
        return int(s)
    except Exception:
        return default

def _systemctl_show(unit: str) -> dict:
    # Keep the set small + stable; only what we need for charts.
    props = [
        "CPUUsageNSec",
        "MemoryCurrent",
        "IOReadBytes",
        "IOWriteBytes",
        "ActiveState",
        "SubState",
        "ExecMainPID",
        "ExecMainStatus",
    ]
    cmd = ["systemctl", "show", unit]
    for p in props:
        cmd.extend(["-p", p])

    try:
        p = subprocess.run(
            cmd,
            check=False,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=2,
        )
    except Exception as e:
        return {"error": f"exec failed: {e}"}

    if p.returncode != 0:
        err = (p.stderr or "").strip()
        out = (p.stdout or "").strip()
        msg = err or out or f"systemctl show failed rc={p.returncode}"
        return {"error": msg}

    out = {}
    for line in (p.stdout or "").splitlines():
        if "=" not in line:
            continue
        k, v = line.split("=", 1)
        out[k.strip()] = v.strip()
    return out

def _atomic_write(path: str, data: dict):
    tmp = f"{path}.tmp.{os.getpid()}"
    s = json.dumps(data, separators=(",", ":"), ensure_ascii=False)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(s)
        f.write("\n")
    os.replace(tmp, path)
    try:
        os.chmod(path, 0o644)
    except Exception:
        pass

def main() -> int:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out-dir", required=True)
    ap.add_argument("--interval", type=float, default=2.0)
    ap.add_argument("--max-samples", type=int, default=180)
    ap.add_argument(
        "--units",
        default="zypper-autodownload.service,zypper-auto-verify.service,zypper-auto-dashboard-api.service",
    )
    args = ap.parse_args()

    out_dir = os.path.abspath(os.path.expanduser(args.out_dir))
    out_file = os.path.join(out_dir, "perf-data.json")

    units = [u.strip() for u in str(args.units).split(",") if u.strip()]
    if not units:
        return 0

    max_samples = max(10, int(args.max_samples))
    interval = float(args.interval)
    if interval < 0.5:
        interval = 0.5

    hist = {u: deque(maxlen=max_samples) for u in units}
    prev_cpu = {u: None for u in units}
    prev_t = {u: None for u in units}

    while True:
        now = time.time()
        now_ms = int(now * 1000)

        payload_units = {}
        for u in units:
            show = _systemctl_show(u)
            if "error" in show:
                # Still emit a point so the UI can show that collection failed.
                hist[u].append({"t": now_ms, "cpu": 0.0, "mem": 0, "r": 0, "w": 0, "err": show.get("error")})
                payload_units[u] = {"samples": list(hist[u])}
                continue

            cpu_ns = _to_int(show.get("CPUUsageNSec"), 0)
            mem_b = _to_int(show.get("MemoryCurrent"), 0)
            r_b = _to_int(show.get("IOReadBytes"), 0)
            w_b = _to_int(show.get("IOWriteBytes"), 0)

            cpu_pct = 0.0
            if prev_cpu[u] is not None and prev_t[u] is not None:
                dcpu = cpu_ns - int(prev_cpu[u])
                dt = now - float(prev_t[u])
                if dcpu < 0:
                    dcpu = 0
                if dt > 0:
                    cpu_pct = (dcpu / (dt * 1e9)) * 100.0
            prev_cpu[u] = cpu_ns
            prev_t[u] = now

            # Bound extreme spikes (multi-core can exceed 100; keep it sane for charts).
            if cpu_pct < 0:
                cpu_pct = 0.0
            if cpu_pct > 4000:
                cpu_pct = 4000.0

            hist[u].append({
                "t": now_ms,
                "cpu": round(cpu_pct, 2),
                "mem": mem_b,
                "r": r_b,
                "w": w_b,
                "active": show.get("ActiveState", ""),
                "sub": show.get("SubState", ""),
                "pid": _to_int(show.get("ExecMainPID"), 0),
                "status": _to_int(show.get("ExecMainStatus"), 0),
            })
            payload_units[u] = {"samples": list(hist[u])}

        payload = {
            "generated_iso": _iso_now(),
            "interval_sec": interval,
            "units": payload_units,
        }

        try:
            _atomic_write(out_file, payload)
        except Exception:
            # Don't die just because the filesystem had a transient error.
            pass

        time.sleep(interval)


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except KeyboardInterrupt:
        raise SystemExit(0)
PYEOF
then
    execute_guarded "Set perf worker permissions (755)" chmod 755 "${DASH_PERF_BIN}" || true
    log_success "Dashboard perf worker installed: ${DASH_PERF_BIN}"
else
    log_warn "Failed to install dashboard perf worker (non-fatal)"
fi

# --- 12. Final self-check ---
log_info ">>> Final syntax self-check..."
update_status "Running final syntax checks..."
run_self_check

# --- 13. Reload user systemd daemon and ensure notifier timer is active ---
USER_BUS_PATH="unix:path=/run/user/$(id -u "$SUDO_USER")/bus"

log_info ">>> Reloading user systemd daemon and (re)starting ${NT_SERVICE_NAME}.timer..."
update_status "Enabling user services..."
log_debug "User bus path: $USER_BUS_PATH"

if execute_guarded "systemctl --user daemon-reload" \
    sudo -u "$SUDO_USER" DBUS_SESSION_BUS_ADDRESS="$USER_BUS_PATH" systemctl --user daemon-reload; then
    log_success "User systemd daemon reloaded"
    
    log_debug "Enabling user timer: ${NT_SERVICE_NAME}.timer"
    if execute_guarded "Enable + start user timer ${NT_SERVICE_NAME}.timer" \
        sudo -u "$SUDO_USER" DBUS_SESSION_BUS_ADDRESS="$USER_BUS_PATH" systemctl --user enable --now "${NT_SERVICE_NAME}.timer"; then
        log_success "User notifier timer enabled and started"
        # Some systemd versions can leave the timer in an 'elapsed' state
        # with no NEXT trigger after unit changes. Force a restart so it
        # gets a fresh schedule and actually fires again for this user.
        log_debug "Restarting user timer to ensure it is scheduled"
        execute_guarded "Restart user timer ${NT_SERVICE_NAME}.timer" \
            sudo -u "$SUDO_USER" DBUS_SESSION_BUS_ADDRESS="$USER_BUS_PATH" systemctl --user restart "${NT_SERVICE_NAME}.timer" || true
    else
        log_error "Failed to enable user timer (non-fatal)"
        log_info "You may need to run manually as the target user:"
        log_info "  systemctl --user enable --now ${NT_SERVICE_NAME}.timer"
    fi
else
    log_error "Warning: Could not talk to user systemd (no session bus?)"
    log_info "You may need to run manually as the target user:"
    log_info "  systemctl --user daemon-reload"
    log_info "  systemctl --user enable --now ${NT_SERVICE_NAME}.timer"
fi


# --- 14. Installation Verification (called during install) ---
if [ "${VERIFICATION_ONLY_MODE:-0}" -ne 1 ]; then
    # Only run verification during installation, not in verify-only mode
    # (verify-only mode calls the function directly and exits)
    run_smart_verification_with_safety_net 1
fi

# --- 14b. Check for Optional Packages ---
log_info ">>> Checking for optional package managers..."
MISSING_PACKAGES=()

if ! command -v flatpak >/dev/null 2>&1; then
    log_info "Flatpak is not installed (optional)"
    MISSING_PACKAGES+=("flatpak")
fi

if ! command -v snap >/dev/null 2>&1; then
    log_info "Snapd is not installed (optional)"
    MISSING_PACKAGES+=("snapd")
fi

# Optional: Soar CLI helper (used to sync metadata after updates)
# Soar is typically installed per-user (for example under ~/.local/bin or
# ~/pkgforge). Detect it using the user's PATH and common install dirs so
# we don't warn when it is already present.
SOAR_PRESENT=0

# Optional: pipx helper (for Python CLI tools). Only warn when
# ENABLE_PIPX_UPDATES=true and pipx is missing for the target user.
PIPX_MISSING_FOR_UPDATES=0
if [[ "${ENABLE_PIPX_UPDATES,,}" == "true" ]]; then
    if ! sudo -u "$SUDO_USER" command -v pipx >/dev/null 2>&1; then
        PIPX_MISSING_FOR_UPDATES=1
        log_info "pipx is not installed for user $SUDO_USER but ENABLE_PIPX_UPDATES=true (optional)"
    fi
fi

# 1) Check via the user's PATH
if sudo -u "$SUDO_USER" command -v soar >/dev/null 2>&1; then
    SOAR_PRESENT=1
# 2) Check common per-user install locations
elif [ -x "$SUDO_USER_HOME/.local/bin/soar" ]; then
    SOAR_PRESENT=1
elif [ -d "$SUDO_USER_HOME/pkgforge" ] && \
     find "$SUDO_USER_HOME/pkgforge" -maxdepth 1 -type f -name 'soar*' -perm -u+x 2>/dev/null | grep -q .; then
    SOAR_PRESENT=1
fi

if [ "$SOAR_PRESENT" -eq 0 ]; then
    log_info "Soar CLI is not installed for user $SUDO_USER (optional)"
    MISSING_PACKAGES+=("soar")
fi

if [ "$PIPX_MISSING_FOR_UPDATES" -eq 1 ]; then
    MISSING_PACKAGES+=("pipx")
fi

# Notify user about missing packages if any
if [ "${#MISSING_PACKAGES[@]}" -gt 0 ]; then
    log_info "Optional package managers missing: ${MISSING_PACKAGES[*]}"
    
    # Create notification for user
    MISSING_MSG="The following optional package managers are not installed:\n\n"
    for pkg in "${MISSING_PACKAGES[@]}"; do
        if [ "$pkg" = "flatpak" ]; then
            MISSING_MSG+="• Flatpak - for Flatpak app updates\n  Install: sudo zypper install flatpak\n\n"
        elif [ "$pkg" = "snapd" ]; then
            MISSING_MSG+="• Snapd - for Snap package updates\n  Install: sudo zypper install snapd\n  Enable: sudo systemctl enable --now snapd\n\n"
        fi
    done
    MISSING_MSG+="These are optional. System updates will work without them."
    
    # Send desktop notification to user
    if command -v notify-send >/dev/null 2>&1; then
        sudo -u "$SUDO_USER" DBUS_SESSION_BUS_ADDRESS="$USER_BUS_PATH" notify-send \
            -u normal \
            -t 15000 \
            -i "dialog-information" \
            "Zypper Auto-Helper: Optional Packages" \
            "${MISSING_MSG}" 2>/dev/null || true
    fi

    # If Soar is missing and the helper exists, also show a richer
    # notification with an "Install Soar" button that opens a terminal
    # running the official install script.
    if printf '%s
' "${MISSING_PACKAGES[@]}" | grep -qx 'soar'; then
        # Propagate DISPLAY from the current environment so the helper
        # can open a terminal on the correct graphical session. Without
        # this, the helper fell back to DISPLAY=:0 which may not match
        # the user's real display.
        if sudo -u "$SUDO_USER" DISPLAY="$DISPLAY" DBUS_SESSION_BUS_ADDRESS="$USER_BUS_PATH" \
            "$USER_BIN_DIR/zypper-soar-install-helper" >/dev/null 2>&1 & then
            log_debug "Launched Soar install helper notification for user $SUDO_USER"
        fi
    fi
    
    echo "" | tee -a "${LOG_FILE}"
    echo "============================" | tee -a "${LOG_FILE}"
    echo "⚠️  Optional Packages Missing" | tee -a "${LOG_FILE}"
    echo "============================" | tee -a "${LOG_FILE}"
    echo "" | tee -a "${LOG_FILE}"
    for pkg in "${MISSING_PACKAGES[@]}"; do
        if [ "$pkg" = "flatpak" ]; then
            echo "Flatpak:" | tee -a "${LOG_FILE}"
            echo "  Purpose: Update Flatpak applications" | tee -a "${LOG_FILE}"
            echo "  Install: sudo zypper install flatpak" | tee -a "${LOG_FILE}"
            echo "" | tee -a "${LOG_FILE}"
        elif [ "$pkg" = "snapd" ]; then
            echo "Snapd:" | tee -a "${LOG_FILE}"
            echo "  Purpose: Update Snap packages" | tee -a "${LOG_FILE}"
            echo "  Install (zypper): sudo zypper install snapd" | tee -a "${LOG_FILE}"
            echo "  Install (opi)   : sudo opi snapd" | tee -a "${LOG_FILE}"
            echo "  Enable services : sudo systemctl enable --now snapd.apparmor.service snapd.seeded.service snapd.service snapd.socket" | tee -a "${LOG_FILE}"
            echo "" | tee -a "${LOG_FILE}"
        elif [ "$pkg" = "soar" ]; then
            echo "Soar:" | tee -a "${LOG_FILE}"
            echo "  Purpose: Optional CLI helper for keeping metadata in sync after updates" | tee -a "${LOG_FILE}"
            echo "  Install: curl -fsSL \"https://raw.githubusercontent.com/pkgforge/soar/main/install.sh\" | sh" | tee -a "${LOG_FILE}"
            echo "  Usage after install: soar sync" | tee -a "${LOG_FILE}"
            echo "" | tee -a "${LOG_FILE}"
        elif [ "$pkg" = "pipx" ]; then
            echo "pipx:" | tee -a "${LOG_FILE}"
            echo "  Purpose: Manage standalone Python CLI tools (yt-dlp, black, ansible, httpie, etc.)" | tee -a "${LOG_FILE}"
            echo "  Install: sudo zypper install python3-pipx" | tee -a "${LOG_FILE}"
            echo "  Helper:  zypper-auto-helper --pip-package  (run without sudo)" | tee -a "${LOG_FILE}"
            echo "" | tee -a "${LOG_FILE}"
        fi
    done
    echo "Note: These are optional. System updates will work without them." | tee -a "${LOG_FILE}"
    echo "============================" | tee -a "${LOG_FILE}"
    echo "" | tee -a "${LOG_FILE}"
fi

# --- 15. Final Summary ---
log_success ">>> Installation completed successfully!"
update_status "SUCCESS: Installation completed"

# Update the static HTML dashboard (best-effort)
generate_dashboard || true

# Ensure dashboard desktop shortcut exists for the primary user (best-effort)
if [ -n "${SUDO_USER:-}" ] && [ -n "${SUDO_USER_HOME:-}" ]; then
    __znh_ensure_dash_desktop_shortcut "${SUDO_USER}" "${SUDO_USER_HOME}" || true
fi

# Remote monitoring: notify success (best-effort)
send_webhook "zypper-auto-helper: Installation successful" \
    "Installation completed successfully.\nInstall log: ${LOG_FILE}" \
    "65280" || true

echo "" | tee -a "${LOG_FILE}"
echo "==============================================" | tee -a "${LOG_FILE}"
echo "Installation Summary:" | tee -a "${LOG_FILE}"
echo "  - Command: zypper-auto-helper (installed to /usr/local/bin)" | tee -a "${LOG_FILE}"
echo "  - System service: ${DL_SERVICE_NAME}.timer (enabled)" | tee -a "${LOG_FILE}"
echo "  - User service: ${NT_SERVICE_NAME}.timer (enabled)" | tee -a "${LOG_FILE}"
echo "  - Install logs: ${LOG_DIR}/install-*.log" | tee -a "${LOG_FILE}"
echo "  - Service logs: ${LOG_DIR}/service-logs/" | tee -a "${LOG_FILE}"
echo "  - User logs: ${USER_LOG_DIR}/" | tee -a "${LOG_FILE}"
echo "  - Status file: ${STATUS_FILE}" | tee -a "${LOG_FILE}"
echo "  - Dashboard note: if the dashboard is already open in your browser, reload the tab to load new UI features." | tee -a "${LOG_FILE}"
echo "" | tee -a "${LOG_FILE}"
echo "Quick Commands:" | tee -a "${LOG_FILE}"
echo "  sudo zypper-auto-helper --verify        # Check system health" | tee -a "${LOG_FILE}"
echo "  sudo zypper-auto-helper --help          # Show help" | tee -a "${LOG_FILE}"
echo "  cat ${STATUS_FILE}                      # View current status" | tee -a "${LOG_FILE}"
echo "" | tee -a "${LOG_FILE}"

echo "Enterprise Quickstart (optional):" | tee -a "${LOG_FILE}"
echo "  Fastest: sudo zypper-auto-helper --dash-install" | tee -a "${LOG_FILE}"
echo "  (enables example hooks + generates/opens dashboard)" | tee -a "${LOG_FILE}"
echo "" | tee -a "${LOG_FILE}"
echo "  Manual steps:" | tee -a "${LOG_FILE}"
echo "  1) Edit ${CONFIG_FILE} and set WEBHOOK_URL=\"...\" (leave empty to disable webhooks)" | tee -a "${LOG_FILE}"
echo "  2) Enable hooks by copying templates and making them executable:" | tee -a "${LOG_FILE}"
echo "     - ${HOOKS_BASE_DIR:-/etc/zypper-auto/hooks}/pre.d/00-example-pre.sh.example" | tee -a "${LOG_FILE}"
echo "     - ${HOOKS_BASE_DIR:-/etc/zypper-auto/hooks}/post.d/00-example-post.sh.example" | tee -a "${LOG_FILE}"
echo "  3) Open the dashboard: ${SUDO_USER_HOME}/.local/share/zypper-notify/status.html" | tee -a "${LOG_FILE}"
echo "" | tee -a "${LOG_FILE}"
echo "Service Status:" | tee -a "${LOG_FILE}"
echo "  systemctl status ${DL_SERVICE_NAME}.timer" | tee -a "${LOG_FILE}"
echo "  systemctl --user status ${NT_SERVICE_NAME}.timer" | tee -a "${LOG_FILE}"
echo "" | tee -a "${LOG_FILE}"
echo "View Logs:" | tee -a "${LOG_FILE}"
echo "  journalctl -u ${DL_SERVICE_NAME}.service" | tee -a "${LOG_FILE}"
echo "  journalctl --user -u ${NT_SERVICE_NAME}.service" | tee -a "${LOG_FILE}"
echo "  cat ${LOG_FILE}" | tee -a "${LOG_FILE}"
echo "==============================================" | tee -a "${LOG_FILE}"
echo "Completed: $(date)" | tee -a "${LOG_FILE}"
